-- Poems batch 96
INSERT OR IGNORE INTO poems (id,title,author,dynasty,collection,collection_id,rhythmic,tags,excerpt,length,source_path,paragraphs) VALUES
('fafd7417-6456-44a9-bc86-8dd694b9fc32','和采石詩韵寄韓無咎','吳芾','宋','宋诗','song-poetry','','[]','野性從來愛水雲，合耕巖下釣溪濱。',64,'全唐诗/poet.song.114000.json','["野性從來愛水雲，合耕巖下釣溪濱。", "宦游愧負平生志，臨按欣逢我輩人。", "奎閣雄文光照日，錦囊佳句艷爭春。", "外臺况上三年計，一節行看詔墨新。"]'),
('71ed1003-b32b-4bb6-90e4-6b16412ae1f9','寄劉汝一陳天予','吳芾','宋','宋诗','song-poetry','','[]','昔年言路記同遊，回首那知歲月流。',64,'全唐诗/poet.song.114000.json','["昔年言路記同遊，回首那知歲月流。", "已歎數公隨物化，却欣二老與余留。", "去天不謂踰三歲，補外那知尚一州。", "想得賜環俱在即，不應似我老林丘。"]'),
('d622c8e5-91ff-4b66-b72a-305a8070b766','二公見和又成一首寄之','吳芾','宋','宋诗','song-poetry','','[]','憶昔同臺接勝遊，相期端不愧清流。',64,'全唐诗/poet.song.114000.json','["憶昔同臺接勝遊，相期端不愧清流。", "一時人物存無幾，百歲光陰挽不留。", "老去只思陶靖節，向來尤歎薛居州。", "亦聞聚首時傾倒，應笑衰翁守故丘。"]'),
('1fabeaa6-65e6-4a2c-93b3-4571f7fa4d97','和陳澤民即事二首  其一','吳芾','宋','宋诗','song-poetry','','[]','鷄聲催曉夢驚殘，喜得歸來卧碧巒。',64,'全唐诗/poet.song.114000.json','["鷄聲催曉夢驚殘，喜得歸來卧碧巒。", "已是人間三月暮，尚餘枕上五更寒。", "心安靖退雖無事，身覺衰頹亦鮮歡。", "頼有故人時會面，開顔一笑酒杯乾。"]'),
('8c7b7d52-69d0-42d0-9e53-bba45537a1fe','和陳澤民即事二首  其二','吳芾','宋','宋诗','song-poetry','','[]','蕭條古寺野僧殘，聊與僧俱住翠巒。',64,'全唐诗/poet.song.114000.json','["蕭條古寺野僧殘，聊與僧俱住翠巒。", "樹影繞簾春晝靜，水晶摇屋暮天寒。", "固知書劍不嫌冷，却恨杯盤未盡歡。", "當念老人衰已久，外雖强健實中乾。"]'),
('7c6b597a-fc59-46de-91d5-cc2e4e8a37f4','和遠老韵','吳芾','宋','宋诗','song-poetry','','[]','野性平時酷愛山，年來何幸得休官。',64,'全唐诗/poet.song.114000.json','["野性平時酷愛山，年來何幸得休官。", "情知軒冕生無益，身在林泉死亦安。", "已免出門頻應接，尚貪散策縱遊觀。", "得師妙語相開發，始覺浮華不足看。"]'),
('021d681e-402c-4401-b2d9-7e8744b8c5cb','和遠老見懷','吳芾','宋','宋诗','song-poetry','','[]','老去光陰能幾何，祇求適意不求多。',64,'全唐诗/poet.song.114000.json','["老去光陰能幾何，祇求適意不求多。", "消除舊恨憑三盞，斷送餘生付一蓑。", "風月情懷雖已滅，漁樵伴侶尚相過。", "師來好趁荷花盛，我欲同遊擊棹歌。"]'),
('7208884a-18de-4b2c-b0bc-2f3aa5478a45','和朱守有待亭','吳芾','宋','宋诗','song-poetry','','[]','使君斂惠撫吾鄉，物阜年豐特異常。',64,'全唐诗/poet.song.114000.json','["使君斂惠撫吾鄉，物阜年豐特異常。", "已向湖中同衆樂，更來山上發天藏。", "登臨緬想高懷適，賦詠懸知雅興長。", "獨恨杜門方屏縮，莫窺佳致望餘光。"]'),
('a48b5aa8-b550-4afb-ab4a-2e5d76cb8d6c','和魯季欽別後寄','吳芾','宋','宋诗','song-poetry','','[]','盍簪經歲遽分襟，夜夜相思夢裏尋。',64,'全唐诗/poet.song.114000.json','["盍簪經歲遽分襟，夜夜相思夢裏尋。", "寄遠正慚無好語，開緘忽喜得高吟。", "感君不替綢繆意，使我還銷鄙吝心。", "他日相逢重把酒，莫辭蘸甲十分深。"]'),
('a0cf52dd-32a2-4a26-bcd4-29cfa32f3802','病起泛舟呈諸親友','吳芾','宋','宋诗','song-poetry','','[]','屏跡山間歲月深，四圍綠樹總成陰。',64,'全唐诗/poet.song.114000.json','["屏跡山間歲月深，四圍綠樹總成陰。", "已欣叢竹生湖岸，更愛雙蓮出水心。", "倚杖頓驚明老眼，艤舟還喜豁煩襟。", "病餘雖是無佳思，乘興何妨試一吟。"]'),
('df5a05fd-313d-48ae-bdc8-21e91b76bf81','山居歸來恰一年有感','吳芾','宋','宋诗','song-poetry','','[]','去歲茲辰始息肩，俄然日月已周天。',64,'全唐诗/poet.song.114000.json','["去歲茲辰始息肩，俄然日月已周天。", "經營小隠雖云畢，栽種清陰苦未圓。", "湖畔百年多古木，山前一望足平川。", "從嗟白髮催吾老，能享林泉得幾年。"]'),
('cc86cfad-7075-4690-a826-a738bf03b4ff','再和四首  其一','吳芾','宋','宋诗','song-poetry','','[]','花枝拂眼柳垂肩，幸得身閒且樂天。',64,'全唐诗/poet.song.114000.json','["花枝拂眼柳垂肩，幸得身閒且樂天。", "木杪夕陽當反照，草頭朝露豈長圓。", "興來策杖雲迷徑，睡起憑欄月滿川。", "老矣不堪供世用，只將蕭散度殘年。"]'),
('ea61ee5b-71da-4e76-87ad-5e45636c0ab5','再和四首  其二','吳芾','宋','宋诗','song-poetry','','[]','歸來深欲斷塵緣，常拜青詞密籲天。',64,'全唐诗/poet.song.114000.json','["歸來深欲斷塵緣，常拜青詞密籲天。", "既幸此身無玷辱，更欣盡室得團圓。", "捫心只合安三徑，度力那能障百川。", "若也天公終見念，從今便是再生年。"]'),
('1e9cd941-8b31-4340-9fd5-44cebf550f11','再和四首  其三','吳芾','宋','宋诗','song-poetry','','[]','卜得幽居野性便，山中風月水中天。',64,'全唐诗/poet.song.114000.json','["卜得幽居野性便，山中風月水中天。", "新栽翠竹陰雖薄，舊植青松蓋已圓。", "高致固難追綠野，勝遊那復繼斜川。", "我今已得安心法，早掛衣冠不待年。"]'),
('cd92ce21-b43f-4af7-a137-0ebbe57fe9ed','再和四首  其四','吳芾','宋','宋诗','song-poetry','','[]','新買湖頭十畝園，綠陰罅裏見青天。',64,'全唐诗/poet.song.114000.json','["新買湖頭十畝園，綠陰罅裏見青天。", "金櫻相亞枝枝裊，銀杏低垂顆顆圓。", "仰看烏鳶翔古木，俯窺鷗鷺戲晴川。", "便須臨水營臺榭，要與漁樵樂暮年。"]'),
('cceda480-0308-4702-a855-2cca277a431d','澤民見示遊洞宮護聖二詩次來韵  其一','吳芾','宋','宋诗','song-poetry','','[]','洞府藏真鎖碧巒，我來頓覺百憂寬。',64,'全唐诗/poet.song.114000.json','["洞府藏真鎖碧巒，我來頓覺百憂寬。", "真人已去留遺像，古木猶存翳舊壇。", "清入杖藜襟抱豁，冷侵衣袂骨毛寒。", "何妨便作誅茅計，幸我年來已掛冠。"]'),
('9773751a-fe1e-4e4e-b804-ba931b5d1b48','澤民見示遊洞宮護聖二詩次來韵  其二','吳芾','宋','宋诗','song-poetry','','[]','山間安有此池塘，疑是天分一派江。',64,'全唐诗/poet.song.114000.json','["山間安有此池塘，疑是天分一派江。", "萬仞方如青玉案，千章森似碧油幢。", "簷前山色日侵座，屋角松聲夜撼窗。", "遊罷擁衾渾不寐，心清都把睡魔降。"]'),
('959a9357-4dfc-40b2-bee9-0fd2945134a2','和薛丞','吳芾','宋','宋诗','song-poetry','','[]','歸來林下恰年餘，喜對青山更面湖。',64,'全唐诗/poet.song.114000.json','["歸來林下恰年餘，喜對青山更面湖。", "野興自來知不淺，宦情今日覺全無。", "任從俗目嗤吾老，未許山靈誚客逋。", "多謝新詩相慰藉，頭風一讀頓然蘇。"]'),
('d384021a-93b0-441d-91ce-da03083d06a8','再和','吳芾','宋','宋诗','song-poetry','','[]','少年勤苦惜三餘，老去惟思泛五湖。',64,'全唐诗/poet.song.114000.json','["少年勤苦惜三餘，老去惟思泛五湖。", "已向林間甘淡泊，更從塵外學虛無。", "酒徒漸覺隨年減，詩債還應隔歲逋。", "强欲冥搜賡絕唱，苦無筆力似三蘇。"]'),
('dc2d35f0-3327-4cf1-ac5f-3dc4c666ed7f','送朝京赴福清宰','吳芾','宋','宋诗','song-poetry','','[]','來往看看二十春，開懷情話日相親。',64,'全唐诗/poet.song.114000.json','["來往看看二十春，開懷情話日相親。", "懸車我已安三徑，捧檄君俄向七閩。", "肯爲浮名隨薄俗，但施善政撫疲民。", "他時奏最歸來處，好訪湖山莫厭頻。"]'),
('ea3894d1-cc0a-4d09-ad87-905046199685','生朝有感','吳芾','宋','宋诗','song-poetry','','[]','每恨生朝天一涯，今年却喜得還家。',64,'全唐诗/poet.song.114000.json','["每恨生朝天一涯，今年却喜得還家。", "漸看寒谷回春律，愈使衰翁感歲華。", "客至寧辭傾竹葉，老來能醉幾梅花。", "餘生祇願長如此，浮利浮名未足誇。"]'),
('847bd4ca-3031-4ddd-a64b-3aaf43c1f3de','遣興','吳芾','宋','宋诗','song-poetry','','[]','天憐衰病放還鄉，猶恐多情易感傷。',64,'全唐诗/poet.song.114000.json','["天憐衰病放還鄉，猶恐多情易感傷。", "已遣蛙聲喧鼓吹，更令燕語奏絲簧。", "固知老去心情減，頗愛閒中氣味長。", "終日杜門無一事，不妨隠几凈焚香。"]'),
('4d5dc9ac-d552-435d-ae3b-01eb8fd63e95','余以庚寅十月十日抵敝廬今恰三年感而有作偶成三律  其一','吳芾','宋','宋诗','song-poetry','','[]','遡自洪都返故園，今朝倒指恰三年。',64,'全唐诗/poet.song.114000.json','["遡自洪都返故園，今朝倒指恰三年。", "舉頭但見松筠長，轉盼那知歲月遷。", "幸有青山長在眼，休嗟白髮已垂顛。", "此身儻未歸黄壤，花下猶堪醉聖賢。"]'),
('7097c0cf-6881-4d5a-b426-46297d4f3484','余以庚寅十月十日抵敝廬今恰三年感而有作偶成三律  其二','吳芾','宋','宋诗','song-poetry','','[]','何處風烟似我園，且將蕭散樂餘年。',64,'全唐诗/poet.song.114000.json','["何處風烟似我園，且將蕭散樂餘年。", "向來已不憂三黜，老去誰能羨九遷。", "門外往還惟白足，里中遊舊盡華顛。", "竹林已是幽棲地，只恐風流愧七賢。"]'),
('0773907e-af28-4e70-a980-35b184dfe6f0','余以庚寅十月十日抵敝廬今恰三年感而有作偶成三律  其三','吳芾','宋','宋诗','song-poetry','','[]','幸有湖邊數畝園，尚堪行樂度殘年。',64,'全唐诗/poet.song.114000.json','["幸有湖邊數畝園，尚堪行樂度殘年。", "驚魚自合潛淵去，倦翼寧思出谷遷。", "既乏仙方能却老，又無奇策可扶顛。", "但知藏拙安吾分，一任人稱賢不賢。"]'),
('c8c6b92b-69dc-4c21-832e-1cb3706e0655','送沈子壽','吳芾','宋','宋诗','song-poetry','','[]','孤城度日宛如年，頼有吾人慰眼前。',64,'全唐诗/poet.song.114000.json','["孤城度日宛如年，頼有吾人慰眼前。", "把酒論文方累月，揚鞭別我遽朝天。", "長才合赴風雲會，新渥行沾雨露邊。", "帝里故人如見問，爲言衰悴愈皤然。"]'),
('8a56d21a-57bc-43ba-82f8-408af4fae308','挽袁正言','吳芾','宋','宋诗','song-poetry','','[]','言路同遊記昔年，英風凜凜共推賢。',64,'全唐诗/poet.song.114000.json','["言路同遊記昔年，英風凜凜共推賢。", "從容峩豸霜臺上，感慨嬰鱗黼扆前。", "持橐自應登禁闥，乘軺聊復向江壖。", "一朝豈料成千古，空有清規後代傳。"]'),
('8c0b9561-a1eb-41e9-9d0d-0665819ba81c','挽鄭武子','吳芾','宋','宋诗','song-poetry','','[]','中原耆舊久彫零，頼有夫君尚典刑。',64,'全唐诗/poet.song.114000.json','["中原耆舊久彫零，頼有夫君尚典刑。", "持節有心吞朔騎，請纓無路報朝廷。", "壯圖落落嗟難合，末俗紛紛笑獨醒。", "坐蛻已超塵世去，空餘遺像在丹青。"]'),
('f0de74fc-56fd-4a81-ad67-d47220da8ada','挽李季文二首  其一','吳芾','宋','宋诗','song-poetry','','[]','世趨捷徑蹈危機，公獨安恬度歲時。',64,'全唐诗/poet.song.114000.json','["世趨捷徑蹈危機，公獨安恬度歲時。", "但見謙謙卑自牧，不爲赫赫急人知。", "政成名已聞丹扆，官滿身將上赤墀。", "豈料一朝成奄忽，空傳南國去思碑。"]'),
('72c856e4-eb67-48de-952a-c2a43c41ce7b','挽李季文二首  其二','吳芾','宋','宋诗','song-poetry','','[]','吳郡爲僚記少時，別來光景迅如飛。',64,'全唐诗/poet.song.114000.json','["吳郡爲僚記少時，別來光景迅如飛。", "江頭我始懷章去，嶺外君纔解組歸。", "正望故人時見過，迴思往事遽成非。", "死生契濶無窮恨，極目高原淚滿衣。"]'),
('d1161d96-c6ee-4502-af68-d0e7bfa16ab7','挽翟伯壽二首  其一','吳芾','宋','宋诗','song-poetry','','[]','高情爽氣薄雲天，灑落真如晉七賢。',64,'全唐诗/poet.song.114000.json','["高情爽氣薄雲天，灑落真如晉七賢。", "筆下蟲魚元自得，胸中丘壑更依然。", "風流已足追千載，壽考胡爲不百年。", "人物此時誰得似，祇應餘慶尚流傳。"]'),
('38ebb4c1-443d-4e39-9461-c553efd9578f','挽翟伯壽二首  其二','吳芾','宋','宋诗','song-poetry','','[]','少日爲僚古樂成，一時共喜得豪英。',64,'全唐诗/poet.song.114000.json','["少日爲僚古樂成，一時共喜得豪英。", "盍簪便有功名志，傾蓋曾無世俗情。", "回想舊遊如昨夢，頓成塵跡負平生。", "故人倒指彫零盡，矯首佳城淚欲傾。"]'),
('4140fbbb-0b25-4209-b7f4-46a70b27a1b3','挽徐子固','吳芾','宋','宋诗','song-poetry','','[]','相逢一笑記臨安，倒指今逾二十年。',64,'全唐诗/poet.song.114000.json','["相逢一笑記臨安，倒指今逾二十年。", "別後每思論舊事，朝來忽報啟新阡。", "蒞官凜凜風猶在，居里恂恂譽更傳。", "遥想武陵溪上路，送車千兩一潸然。"]'),
('34964b04-aaec-4744-b8c4-dcfd72fae01b','挽季行可','吳芾','宋','宋诗','song-poetry','','[]','當年闕下久棲遲，故里歸來萬事非。',64,'全唐诗/poet.song.114000.json','["當年闕下久棲遲，故里歸來萬事非。", "訪舊幾人成鬼錄，傷君未老棄親闈。", "開樽尚想延賓醉，發廩猶思賑歲饑。", "積慶流芳知未艾，會看門戶日光輝。"]'),
('5526e71e-b1ab-4193-9eb4-3a2707c53e04','挽五兄知府二首  其一','吳芾','宋','宋诗','song-poetry','','[]','平生臭味最相投，方喜同時得退休。',64,'全唐诗/poet.song.114000.json','["平生臭味最相投，方喜同時得退休。", "正欲從容陪杖屨，從茲蕭散老林丘。", "高標豈料成千古，遺愛空嗟滿一州。", "兄弟凋零復無繼，故山誰與我同遊。"]'),
('ef7ee99a-da62-42ba-8ec7-f2de352880da','挽五兄知府二首  其二','吳芾','宋','宋诗','song-poetry','','[]','三吳意氣各翩翩，尚憶俱遊太學年。',64,'全唐诗/poet.song.114000.json','["三吳意氣各翩翩，尚憶俱遊太學年。", "伯氏久驚歸厚夜，吾兄遠復掩新阡。", "自憐門戶今衰矣，回想音容祇泫然。", "猶幸諸兒渾競爽，他時當不負家傳。"]'),
('020b44e5-1b55-4737-a1b9-8048bfd04bdc','挽何內翰二首  其一','吳芾','宋','宋诗','song-poetry','','[]','場屋聲名四海知，十年平步上丹墀。',64,'全唐诗/poet.song.114000.json','["場屋聲名四海知，十年平步上丹墀。", "伏蒲議論高千古，視草文章妙一時。", "雅望自應登輔弼，壯圖仍欲濟艱危。", "誰知竟負經綸志，空使人懷殄瘁悲。"]'),
('fc5884ee-2392-486e-b987-85b48222c0a0','挽何內翰二首  其二','吳芾','宋','宋诗','song-poetry','','[]','老去交遊半淺深，高山流水獨知音。',64,'全唐诗/poet.song.114000.json','["老去交遊半淺深，高山流水獨知音。", "分携苦未經寒暑，轉盼那知隔古今。", "聯事尚懷時把酒，同朝猶記共論心。", "無因執紼西山路，空對東風淚滿襟。"]'),
('e91a9f8d-1118-4ce4-87f9-ab10e19f1425','挽錢省幹','吳芾','宋','宋诗','song-poetry','','[]','高義由來擅月評，壯年銳志立功名。',64,'全唐诗/poet.song.114000.json','["高義由來擅月評，壯年銳志立功名。", "助平逆黨謀先定，謾駡兇酋色不驚。", "赤幘蹉跎憐晚景，青雲騰蹋負平生。", "祇應餘慶鍾蘭玉，桂籍傳芳奕世榮。"]'),
('68eeca37-72d5-4a6c-91b3-510599ac8269','挽陳巡檢','吳芾','宋','宋诗','song-poetry','','[]','夫君端是一時豪，排難捐軀不憚勞。',64,'全唐诗/poet.song.114000.json','["夫君端是一時豪，排難捐軀不憚勞。", "忠義自能全里社，姓名那肯辱銓曹。", "一生倜儻心常逸，五世團欒壽更高。", "瞑目定知無可憾，九原風樹漫悲號。"]'),
('8aebbb76-f233-4b5e-b964-142d5aab4738','挽王之先','吳芾','宋','宋诗','song-poetry','','[]','壯志凌雲氣吐虹，才華高出輩流中。',64,'全唐诗/poet.song.114000.json','["壯志凌雲氣吐虹，才華高出輩流中。", "讀書不負建樓意，好客尚賒投轄風。", "鶚薦共期登虎榜，鷁飛無復到蟾宮。", "春來池館渾如舊，夢覺黄粱事已空。"]'),
('500253dd-2544-4355-9d40-27befda1795d','挽應偉節尊人','吳芾','宋','宋诗','song-poetry','','[]','歸來閭里問高年，此日惟公五福全。',64,'全唐诗/poet.song.114000.json','["歸來閭里問高年，此日惟公五福全。", "三世儒科身及見，四經鄉飲衆推先。", "安時不恨青衫晚，適意還欣綵服鮮。", "終始哀榮無可憾，想應含笑入黄泉。"]'),
('e3c490e7-143d-4cfa-978a-293493cc72e8','挽孟仲安二首  其一','吳芾','宋','宋诗','song-poetry','','[]','琴劔縱橫迹已陳，凜然英氣尚如存。',64,'全唐诗/poet.song.114000.json','["琴劔縱橫迹已陳，凜然英氣尚如存。", "向來忠義全鄉社，老去詩書付子孫。", "正好林泉窮勝事，那知風月負清樽。", "他年陰德留餘慶，會見簪紳萃一門。"]'),
('f0e2bcb3-d10c-4ebb-8fb0-6dd38a8f2ed4','挽孟仲安二首  其二','吳芾','宋','宋诗','song-poetry','','[]','義薄雲天氣吐虹，平生心事許誰同。',64,'全唐诗/poet.song.114000.json','["義薄雲天氣吐虹，平生心事許誰同。", "從容破賊無遺策，清白傳家有祖風。", "共意騫騰千里外，誰知蕭瑟九原中。", "百年已矣餘芳在，庭下行看發桂叢。"]'),
('8998d4d2-a769-4402-8c63-20f11bfd7bc6','挽程朝議二首  其一','吳芾','宋','宋诗','song-poetry','','[]','兵革連年苦亂離，江東耆舊日衰微。',64,'全唐诗/poet.song.114000.json','["兵革連年苦亂離，江東耆舊日衰微。", "身兼五福如公少，眼見重孫自古稀。", "未厭案頭翻貝葉，方榮堂上戲斑衣。", "東風忽破南柯夢，回首音容涕淚揮。"]'),
('4008e62c-c651-4b6f-b65a-449d45c705eb','挽程朝議二首  其二','吳芾','宋','宋诗','song-poetry','','[]','憶昔安輿到郡時，使君歡迓鎮江湄。',64,'全唐诗/poet.song.114000.json','["憶昔安輿到郡時，使君歡迓鎮江湄。", "萬人踴躍瞻耆艾，千里歌謠美孝慈。", "盛德所鍾門閥在，平生無愧鬼神知。", "佳城一閉成千古，徒有陰風拂繐幃。"]'),
('11f29377-b25b-4f00-bc68-cc7663561415','挽席夫人二首  其一','吳芾','宋','宋诗','song-poetry','','[]','持身禮法動無違，四德如君古亦稀。',64,'全唐诗/poet.song.114000.json','["持身禮法動無違，四德如君古亦稀。", "大國增封光典冊，長年獻壽擁庭闈。", "俄驚蒿里飛丹旐，尚想萱堂玩綵衣。", "竊意生前猶有恨，沙堤不及見公歸。"]'),
('c1db0c09-b853-4fd0-ae12-703452074d34','挽席夫人二首  其二','吳芾','宋','宋诗','song-poetry','','[]','猗歟陶母世稱賢，生子還持輔佐權。',64,'全唐诗/poet.song.114000.json','["猗歟陶母世稱賢，生子還持輔佐權。", "政府舊曾迎象服，成都重見擁戎旃。", "佳城閉處千車集，華屋生來五福全。", "終始衰榮今已矣，空餘陳迹載青編。"]'),
('c5bab65a-a93e-4e90-a755-834253432a45','題商樂庵','吳芾','宋','宋诗','song-poetry','','[]','遊戲一橘中，自謂有足樂。',24,'全唐诗/poet.song.114000.json','["遊戲一橘中，自謂有足樂。", "何如在商山，笑傲視寥廓。"]'),
('7f94cb8a-c6a2-47b2-a5c8-b4ef13fd4294','芳洲','吳芾','宋','宋诗','song-poetry','','[]','秋風彫蘭芷，芳洲久寂寞。',24,'全唐诗/poet.song.114000.json','["秋風彫蘭芷，芳洲久寂寞。", "痛飲讀離騷，此興亦不惡。"]'),
('3dc1c6f5-a948-4020-a163-5e5857d83290','詠松','吳芾','宋','宋诗','song-poetry','','[]','幸不生澗底，傑出蒼蒼崖。',24,'全唐诗/poet.song.114000.json','["幸不生澗底，傑出蒼蒼崖。", "歲寒只孤秀，萬木非吾儕。"]'),
('4db5667b-687b-4b72-a689-184daaa5a6e7','送白酒白蓮與鍾統制錢廣文因成二絕  其一','吳芾','宋','宋诗','song-poetry','','[]','甕頭白酒熟，池上白蓮開。',24,'全唐诗/poet.song.114000.json','["甕頭白酒熟，池上白蓮開。", "我愛君純白，聊持薦一杯。"]'),
('5b548986-437e-49fe-8e56-d8157eeefb59','送白酒白蓮與鍾統制錢廣文因成二絕  其二','吳芾','宋','宋诗','song-poetry','','[]','白酒方浮玉，白蓮仍可人。',24,'全唐诗/poet.song.114000.json','["白酒方浮玉，白蓮仍可人。", "贈君飛大白，聊作冷官春。"]'),
('311921a1-b1f8-419b-b4aa-18dcf280ad90','六月末間拒霜已開','吳芾','宋','宋诗','song-poetry','','[]','暑氣猶未退，寒花早已開。',24,'全唐诗/poet.song.114000.json','["暑氣猶未退，寒花早已開。", "衰年寧有幾，寒暑若相催。"]'),
('c0f76c65-40a0-424c-a96e-9dcddd300a79','香叢','吳芾','宋','宋诗','song-poetry','','[]','緩步繞芳叢，時時鼻觀通。',24,'全唐诗/poet.song.114000.json','["緩步繞芳叢，時時鼻觀通。", "不須薰百和，滿院是香風。"]'),
('2d19bb8d-04ab-4f25-8771-9a0c8c4fec5e','生朝有感','吳芾','宋','宋诗','song-poetry','','[]','每歲逢生日，予心喜復悲。',24,'全唐诗/poet.song.114000.json','["每歲逢生日，予心喜復悲。", "新年六十六，能得幾多時。"]'),
('d32eaebe-3490-4bd1-9837-c671bb779ee6','小有洞','吳芾','宋','宋诗','song-poetry','','[]','世人競蝸角，終日汩塵緣。',24,'全唐诗/poet.song.114000.json','["世人競蝸角，終日汩塵緣。", "誰謂名園內，深藏小洞天。"]'),
('59ca63ba-d030-49fb-9062-330f382f356c','虞兵張宥康永年未六十一日相繼力求歸農余因嘉其志作小絕以紀之','吳芾','宋','宋诗','song-poetry','','[]','仕宦老不休，虞兵乃知止。',24,'全唐诗/poet.song.114000.json','["仕宦老不休，虞兵乃知止。", "低頭愧斯人，三歎不能已。"]'),
('ea47bf40-1d92-4272-8a28-c2fbd23283c5','芙蓉','吳芾','宋','宋诗','song-poetry','','["\u897f\u6e56"]','誰向澄波上，盡將雲錦鋪。',24,'全唐诗/poet.song.114000.json','["誰向澄波上，盡將雲錦鋪。", "無因一寓目，却憶小西湖。"]'),
('5699da11-5bf7-4ba2-ae6d-a085d97a6548','前太守仲求石問留題因和三首  其一','吳芾','宋','宋诗','song-poetry','','[]','不解追時好，尤非治郡才。',24,'全唐诗/poet.song.114000.json','["不解追時好，尤非治郡才。", "故山猿鶴怨，應怪未歸來。"]'),
('069475a4-ef53-46f5-84db-f73fdd74426c','前太守仲求石問留題因和三首  其二','吳芾','宋','宋诗','song-poetry','','[]','度力難堪事，甘心作棄才。',24,'全唐诗/poet.song.114000.json','["度力難堪事，甘心作棄才。", "欲歸歸未得，却悔出山來。"]'),
('a331d3fa-1ae1-48b1-afad-c9e0c8168cbc','前太守仲求石問留題因和三首  其三','吳芾','宋','宋诗','song-poetry','','[]','此日老法從，當年窮秀才。',24,'全唐诗/poet.song.114000.json','["此日老法從，當年窮秀才。", "從今歸去好，非不遇時來。"]'),
('a024ec9c-3861-4141-8060-8975f4b0470f','題日涉園','吳芾','宋','宋诗','song-poetry','','[]','幽園足佳趣，散策日經行。',24,'全唐诗/poet.song.114000.json','["幽園足佳趣，散策日經行。", "歲久禽魚熟，人來自不驚。"]'),
('56e6b235-9920-4e6b-90fe-0cf6d43c2281','題閲歲亭','吳芾','宋','宋诗','song-poetry','','[]','歲月催人老，少年安在哉。',24,'全唐诗/poet.song.114000.json','["歲月催人老，少年安在哉。", "羨君杯酒裏，日日見花開。"]'),
('f7e9b79d-c0f4-427f-9532-227afcecbadb','題望雲亭','吳芾','宋','宋诗','song-poetry','','[]','白雲來何時，英英冠山椒。',24,'全唐诗/poet.song.114000.json','["白雲來何時，英英冠山椒。", "西風莫吹去，使我心摇摇。"]'),
('3c9d0fb4-9e8a-41c9-8a02-16d85bb8de73','蒙恩易鎮豫章丐假還鄉途中偶成十七首  其一','吳芾','宋','宋诗','song-poetry','','["\u897f\u6e56"]','處處是紅蕖，分明似畫圖。',24,'全唐诗/poet.song.114000.json','["處處是紅蕖，分明似畫圖。", "匆匆看不盡，歸對小西湖。"]'),
('dc06c716-44f8-46d2-8f72-dcb7051bfab2','蒙恩易鎮豫章丐假還鄉途中偶成十七首  其二','吳芾','宋','宋诗','song-poetry','','[]','官舍似郵傳，宦游如路岐。',24,'全唐诗/poet.song.114000.json','["官舍似郵傳，宦游如路岐。", "吾年行七十，安用苦奔馳。"]'),
('007f853e-b8db-4cba-b45b-92a28e082cca','蒙恩易鎮豫章丐假還鄉途中偶成十七首  其三','吳芾','宋','宋诗','song-poetry','','[]','觸目盡陂塘，山光接水光。',24,'全唐诗/poet.song.114000.json','["觸目盡陂塘，山光接水光。", "近來仍雨足，莫道是山鄉。"]'),
('4a277e77-8714-4bf9-a211-91c033c96b84','蒙恩易鎮豫章丐假還鄉途中偶成十七首  其四','吳芾','宋','宋诗','song-poetry','','[]','方困長塗滑，俄逢赫日明。',24,'全唐诗/poet.song.114000.json','["方困長塗滑，俄逢赫日明。", "只憂開太早，却恐雨還生。"]'),
('4b80ca19-0677-4b5c-8c47-357d4bc04c21','蒙恩易鎮豫章丐假還鄉途中偶成十七首  其五','吳芾','宋','宋诗','song-poetry','','[]','沙虛防敗岸，舟小怯驚湍。',24,'全唐诗/poet.song.114000.json','["沙虛防敗岸，舟小怯驚湍。", "行路難如此，爭如野處安。"]'),
('75aa4d70-46d4-493c-ad56-257a06bc6b8a','蒙恩易鎮豫章丐假還鄉途中偶成十七首  其六','吳芾','宋','宋诗','song-poetry','','[]','劇暑當三伏，新凉似九秋。',24,'全唐诗/poet.song.114000.json','["劇暑當三伏，新凉似九秋。", "日光還欲吐，雲影未全收。"]'),
('f7484bb9-cb9f-45b3-87b7-7b9694a7fe2a','蒙恩易鎮豫章丐假還鄉途中偶成十七首  其七','吳芾','宋','宋诗','song-poetry','','[]','中夜不能眠，頗疑天有雨。',24,'全唐诗/poet.song.114000.json','["中夜不能眠，頗疑天有雨。", "寒燠自古然，不應冷如許。"]'),
('88367266-d329-4005-808b-ffea028252d0','蒙恩易鎮豫章丐假還鄉途中偶成十七首  其八','吳芾','宋','宋诗','song-poetry','','[]','自江至吾廬，七日喜及半。',24,'全唐诗/poet.song.114000.json','["自江至吾廬，七日喜及半。", "却恐席未溫，又過江南岸。"]'),
('d0dce3d0-969c-46e7-a84e-0a528e6fbcff','蒙恩易鎮豫章丐假還鄉途中偶成十七首  其九','吳芾','宋','宋诗','song-poetry','','[]','村徑迷南北，晨興乃錯行。',24,'全唐诗/poet.song.114000.json','["村徑迷南北，晨興乃錯行。", "悟來還已遠，却悔早貪程。"]'),
('53a8aca4-0894-48fa-a98f-fd3bf01cf007','蒙恩易鎮豫章丐假還鄉途中偶成十七首  其一○','吳芾','宋','宋诗','song-poetry','','[]','崇閣瞰方池，池邊綠樹圍。',24,'全唐诗/poet.song.114000.json','["崇閣瞰方池，池邊綠樹圍。", "披襟臨水坐，寧復畏炎威。"]'),
('a91ffe3b-61e5-4e66-9e66-5545d3102c1c','蒙恩易鎮豫章丐假還鄉途中偶成十七首  其一一','吳芾','宋','宋诗','song-poetry','','[]','雨餘江色浄，風過稻花香。',24,'全唐诗/poet.song.114000.json','["雨餘江色浄，風過稻花香。", "客裏逢清曠，何妨且納凉。"]'),
('9555b145-56e5-442a-bc38-6c32b1317435','蒙恩易鎮豫章丐假還鄉途中偶成十七首  其一二','吳芾','宋','宋诗','song-poetry','','[]','游魚跳水面，幽鳥囀山腰。',24,'全唐诗/poet.song.114000.json','["游魚跳水面，幽鳥囀山腰。", "各隨飛潛性，人猶戀市朝。"]'),
('373fd2ca-f76d-455a-b559-1b3a4a72eb9f','蒙恩易鎮豫章丐假還鄉途中偶成十七首  其一三','吳芾','宋','宋诗','song-poetry','','[]','睡裏聞風雨，吾行擬暫停。',24,'全唐诗/poet.song.114000.json','["睡裏聞風雨，吾行擬暫停。", "起來搔首坐，喜見一天星。"]'),
