('4db025b9-c998-44c6-a9fc-3104e08cbde3','雪後觀梅  其一','吳芾','宋','宋诗','song-poetry','','[]','雨聲纔歇雪漫漫，深恐梅花不耐寒。',32,'全唐诗/poet.song.114000.json','["雨聲纔歇雪漫漫，深恐梅花不耐寒。", "破曉踏泥來問訊，細看枝上喜平安。"]'),
('b0f4cf52-a8af-468a-8095-742bfd39bb6b','雪後觀梅  其二','吳芾','宋','宋诗','song-poetry','','[]','春色三分已一分，江梅猶自占青春。',32,'全唐诗/poet.song.114000.json','["春色三分已一分，江梅猶自占青春。", "有花堪折須拚醉，莫待東風吹作塵。"]'),
('dd7a0709-be1e-4972-91cd-beb2c0778590','折梅','吳芾','宋','宋诗','song-poetry','','[]','不傍茅簷便竹籬，初開猶未許人知。',32,'全唐诗/poet.song.114000.json','["不傍茅簷便竹籬，初開猶未許人知。", "一枝到手春雖淺，肯負花前金屈巵。"]'),
('0110b662-e983-4e13-a82a-7b7d6792c12a','寒梅','吳芾','宋','宋诗','song-poetry','','[]','冰玉精神絕點埃，人間無物似寒梅。',32,'全唐诗/poet.song.114000.json','["冰玉精神絕點埃，人間無物似寒梅。", "凌霜傲雪渾閒事，最是欺春不逐來。"]'),
('68c1f31f-e21e-4e4a-89e5-7999d15d8430','蠟梅二首  其一','吳芾','宋','宋诗','song-poetry','','[]','誰將栗玉刻蜂房，巧向梢頭取次妝。',32,'全唐诗/poet.song.114000.json','["誰將栗玉刻蜂房，巧向梢頭取次妝。", "羞得江梅都避舍，滿園不見一枝芳。"]'),
('4e4d3f9a-afdc-499c-9696-9df50c92f368','蠟梅二首  其二','吳芾','宋','宋诗','song-poetry','','[]','園林摇落獨芬芳，未讓江梅雪裏香。',32,'全唐诗/poet.song.114000.json','["園林摇落獨芬芳，未讓江梅雪裏香。", "還恐人嫌梅太白，故來枝上盡塗黄。"]'),
('340803ae-9ba8-4bed-91ab-44ef299eb227','謝陳詹山惠蠟梅','吳芾','宋','宋诗','song-poetry','','[]','歲晚相逢眼已明，一枝還復見高情。',32,'全唐诗/poet.song.114000.json','["歲晚相逢眼已明，一枝還復見高情。", "幽香不與江梅共，要與夫君鬭獨清。"]'),
('49ff061b-6fe5-4936-9dcc-b2942be2ad35','藏雲寺有海棠一樹在僧舍後竹籬荆棘之間余因勸耕偶見之遣兵移植於堂下仍賦一絕以紀之','吳芾','宋','宋诗','song-poetry','','[]','海棠一樹竹籬根，密掩深藏若避人。',32,'全唐诗/poet.song.114000.json','["海棠一樹竹籬根，密掩深藏若避人。", "移向亭前端有意，要令山下盡知春。"]'),
('dd911716-b4f3-479a-85e3-5555985fe0e7','詠海棠呈子肅','吳芾','宋','宋诗','song-poetry','','[]','海棠元自有天香，底事時人故謗傷。',32,'全唐诗/poet.song.114000.json','["海棠元自有天香，底事時人故謗傷。", "不信請來花下坐，惱人鼻觀不尋常。"]'),
('bd1708ea-107d-4077-8235-91981c37dde8','子肅見示和篇復次韵','吳芾','宋','宋诗','song-poetry','','[]','花到濃時自有香，未逢真賞亦堪傷。',32,'全唐诗/poet.song.114000.json','["花到濃時自有香，未逢真賞亦堪傷。", "今朝滲鼻渾如許，豈是茲花返故常。"]'),
('4b6491d7-9962-4764-b751-2f121fe85070','和陳子良海棠四首  其一','吳芾','宋','宋诗','song-poetry','','[]','春來人物盡熙熙，紅紫無情亦滿枝。',32,'全唐诗/poet.song.114000.json','["春來人物盡熙熙，紅紫無情亦滿枝。", "正引衰翁詩思動，舉頭那更得君詩。"]'),
('320762dc-1c27-4122-8e70-f82592009f82','和陳子良海棠四首  其二','吳芾','宋','宋诗','song-poetry','','[]','花間春色麗晴空，惱我狂來只繞叢。',32,'全唐诗/poet.song.114000.json','["花間春色麗晴空，惱我狂來只繞叢。", "試問妖嬈誰與比，一株勝却萬株紅。"]'),
('a74c18cc-9458-4fd2-86c6-e0704a081074','和陳子良海棠四首  其三','吳芾','宋','宋诗','song-poetry','','[]','雨後花頭頓覺肥，細看還是舊風姿。',32,'全唐诗/poet.song.114000.json','["雨後花頭頓覺肥，細看還是舊風姿。", "坐餘自有香芬馥，不許凡人取次知。"]'),
('45b5d1f7-15f8-4ec6-b7e4-af98cfed20d4','和陳子良海棠四首  其四','吳芾','宋','宋诗','song-poetry','','[]','十年栽種滿園花，無似茲花艷麗多。',32,'全唐诗/poet.song.114000.json','["十年栽種滿園花，無似茲花艷麗多。", "已是譜中推第一，不須還更問如何。"]'),
('6a7e3c15-28fc-4176-81e7-192967f52779','領客賞海棠雪作  其一','吳芾','宋','宋诗','song-poetry','','[]','絕艷妖嬈壓衆芳，况來燭下逞新妝。',32,'全唐诗/poet.song.114000.json','["絕艷妖嬈壓衆芳，况來燭下逞新妝。", "引將姑射神人到，亦逐春風上下狂。"]'),
('d403ef90-b65e-4a93-892a-aaae6c8c5946','領客賞海棠雪作  其二','吳芾','宋','宋诗','song-poetry','','[]','撩撥遊人思不禁，也緣尤物蕩人心。',32,'全唐诗/poet.song.114000.json','["撩撥遊人思不禁，也緣尤物蕩人心。", "今宵雪向花間作，應妬此花紅太深。"]'),
('b7c53844-757c-43b0-8c5e-01b3600cfa66','去春勸耕雲際移植海棠曾留小詩今歲困於多事欲往不果悵然有懷復和前韵以示主僧','吳芾','宋','宋诗','song-poetry','','[]','去年勸相到雲根，滿樹花光欲照人。',32,'全唐诗/poet.song.114000.json','["去年勸相到雲根，滿樹花光欲照人。", "料得今年花更好，無端風雨阻行春。"]'),
('18457caa-49f5-47d9-bf14-f1def7e9a05f','寄朝宗海棠','吳芾','宋','宋诗','song-poetry','','[]','海棠已賦十分妝，細看妖嬈更異常。',32,'全唐诗/poet.song.114000.json','["海棠已賦十分妝，細看妖嬈更異常。", "不得與君同勝賞，空燒銀燭照花光。"]'),
('8d514415-cfc6-4cf5-9a36-120662803203','和潘大卿芍藥二首  其一','吳芾','宋','宋诗','song-poetry','','[]','落盡羣花春已殘，忽驚庭下錦新翻。',32,'全唐诗/poet.song.114000.json','["落盡羣花春已殘，忽驚庭下錦新翻。", "夜深領客窮清賞，一笑開懷倒數尊。"]'),
