('689e08a0-c88f-4ded-b65e-67308430482a','和遠老四首  其三','吳芾','宋','宋诗','song-poetry','','[]','世人老去不知休，祇羨三公與五侯。',32,'全唐诗/poet.song.114000.json','["世人老去不知休，祇羨三公與五侯。", "爭似山僧都不會，困來衲被便蒙頭。"]'),
('fe30f827-fa68-4b70-a05e-2d0a7847248f','和遠老四首  其四','吳芾','宋','宋诗','song-poetry','','[]','相逢正好共看山，底事匆匆便欲還。',32,'全唐诗/poet.song.114000.json','["相逢正好共看山，底事匆匆便欲還。", "今日乍晴山更好，可能伴我片時閒。"]'),
('ed9d01c8-8ad1-4f15-b026-e2fa51617504','上七齋素不飲','吳芾','宋','宋诗','song-poetry','','[]','人日晴天萬里開，自應一笑上春臺。',32,'全唐诗/poet.song.114000.json','["人日晴天萬里開，自應一笑上春臺。", "清齋偶阻花前醉，且把茶甌當酒杯。"]'),
('3e6b2980-2027-4a91-b949-35d6d108e84d','送津赴紹興倅八首  其一','吳芾','宋','宋诗','song-poetry','','[]','讀書已負少年時，老大空疏愧我知。',32,'全唐诗/poet.song.114000.json','["讀書已負少年時，老大空疏愧我知。", "汝肯爲余償此志，雖窮亦是起家兒。"]'),
('263bb6dd-c45c-412c-ac23-72bde4232053','送津赴紹興倅八首  其二','吳芾','宋','宋诗','song-poetry','','[]','山色湖光足自怡，幽棲無一不相宜。',32,'全唐诗/poet.song.114000.json','["山色湖光足自怡，幽棲無一不相宜。", "只嫌野外遊從少，汝早歸來共樂之。"]'),
('1320e49d-b8c2-4ad1-a9bb-8e3099d2dd54','送津赴紹興倅八首  其三','吳芾','宋','宋诗','song-poetry','','[]','汝辭秦邸佐名藩，端爲親庭數舍間。',32,'全唐诗/poet.song.114000.json','["汝辭秦邸佐名藩，端爲親庭數舍間。", "數舍相望雖不遠，爭如在側日承顔。"]'),
('2bdee49e-f6cd-45a4-a5e7-51b719a7a106','送津赴紹興倅八首  其四','吳芾','宋','宋诗','song-poetry','','[]','當年我鎮卧龍山，曾種千花與萬竿。',32,'全唐诗/poet.song.114000.json','["當年我鎮卧龍山，曾種千花與萬竿。", "歲久不知無恙否，因來且爲報平安。"]'),
('58ece31d-117a-461b-9741-90be6871b42b','送津赴紹興倅八首  其五','吳芾','宋','宋诗','song-poetry','','[]','我曾開鑿鑑湖田，功竟難成愧昔賢。',32,'全唐诗/poet.song.114000.json','["我曾開鑿鑑湖田，功竟難成愧昔賢。", "汝謁馬祠須問訊，此湖興復是何年。"]'),
('322bfbc6-0368-458a-ba45-abd726d01cec','送津赴紹興倅八首  其六','吳芾','宋','宋诗','song-poetry','','[]','出仕曾塵侍從班，退休還得老湖山。',32,'全唐诗/poet.song.114000.json','["出仕曾塵侍從班，退休還得老湖山。", "已慚過分無他望，只願吾兒相對閒。"]'),
('86dc6965-872b-4fdd-b025-6a22548e8cc1','送津赴紹興倅八首  其七','吳芾','宋','宋诗','song-poetry','','[]','我辭官路已多時，魂夢今猶畏險巇。',32,'全唐诗/poet.song.114000.json','["我辭官路已多時，魂夢今猶畏險巇。", "汝既飽諳游宦味，會須早作箇歸期。"]'),
('78ae415d-3d02-4601-8d6e-c79fa6db3649','送津赴紹興倅八首  其八','吳芾','宋','宋诗','song-poetry','','[]','人生萬事不如歸，只恐歸來不及時。',32,'全唐诗/poet.song.114000.json','["人生萬事不如歸，只恐歸來不及時。", "汝若能爲陶靖節，我身勝到鳳凰池。"]'),
('14032335-bdef-4ecd-ad25-dd2fa4ca0427','山居上元','吳芾','宋','宋诗','song-poetry','','[]','未能免俗强隨緣，聊掛燈毬記上元。',32,'全唐诗/poet.song.114000.json','["未能免俗强隨緣，聊掛燈毬記上元。", "席上雖無羅綺繞，遊人來往亦喧喧。"]'),
('28b5f787-745b-4b26-a988-05e9755e2812','十六夜見月','吳芾','宋','宋诗','song-poetry','','[]','連宵待月屢登城，特地遮藏不肯明。',32,'全唐诗/poet.song.114000.json','["連宵待月屢登城，特地遮藏不肯明。", "過了佳辰方皎潔，嫦娥何事太無情。"]'),
('35814b3f-443c-407b-9213-e17f011db4bf','代答','吳芾','宋','宋诗','song-poetry','','[]','人生何用苦多憂，無日無時可宴遊。',32,'全唐诗/poet.song.114000.json','["人生何用苦多憂，無日無時可宴遊。", "但使此心忘係累，凉天佳月即中秋。"]'),
('06987e97-355d-4122-8180-3e70cf6708cc','甲子日無雨偶成','吳芾','宋','宋诗','song-poetry','','[]','連歲人懷水潦憂，年登猶歎不全收。',32,'全唐诗/poet.song.114000.json','["連歲人懷水潦憂，年登猶歎不全收。", "夏逢甲子天無雨，預喜今年又有秋。"]'),
('b697d398-4c37-4a44-84a5-b5b0ca403922','和許守松陰','吳芾','宋','宋诗','song-poetry','','[]','喬松轉日影斜斜，穿入疏櫺細作花。',32,'全唐诗/poet.song.114000.json','["喬松轉日影斜斜，穿入疏櫺細作花。", "怪得清陰長不改，原來松下蟄龜蛇。"]'),
('df03d6df-1ddb-4876-885a-8817741bd0a9','題心遠軒二首  其一','吳芾','宋','宋诗','song-poetry','','[]','山居我欲避囂塵，尚覺門庭俗客頻。',32,'全唐诗/poet.song.114000.json','["山居我欲避囂塵，尚覺門庭俗客頻。", "羨爾結茅當道左，一軒風月作閒人。"]'),
('0f734072-07f2-4269-a010-fd27a7f406a3','題心遠軒二首  其二','吳芾','宋','宋诗','song-poetry','','[]','扁榜當年我命名，喜君心與迹雙清。',32,'全唐诗/poet.song.114000.json','["扁榜當年我命名，喜君心與迹雙清。", "眼前風物渾如舊，但覺庭前春草生。"]'),
('6fa8e1c7-6ed7-4aea-9e47-6137ce37e4fc','和劉與權韵三首  其一','吳芾','宋','宋诗','song-poetry','','[]','平生嗜好唯愛山，前身疑是山中相。',32,'全唐诗/poet.song.114000.json','["平生嗜好唯愛山，前身疑是山中相。", "歸來深處得幽棲，柴門正與山相向。"]'),
('39746f0d-805d-47ce-a4da-ef46a6d8d957','和劉與權韵三首  其二','吳芾','宋','宋诗','song-poetry','','[]','去年君過我山中，尊酒相歡十日同。',32,'全唐诗/poet.song.114000.json','["去年君過我山中，尊酒相歡十日同。", "別後相思腸欲斷，暮雲空復指江東。"]'),
('4b814605-2868-4e72-80c5-c0b35525b2f9','和劉與權韵三首  其三','吳芾','宋','宋诗','song-poetry','','[]','異縣相望兩驛間，何時復此共看山。',32,'全唐诗/poet.song.114000.json','["異縣相望兩驛間，何時復此共看山。", "向來同社今無幾，莫惜籃輿數往還。"]'),
('180c36f2-005f-48ec-804b-a5d2bfe81bb1','陳子厚送韶鴨將以七絕因次其韵  其一','吳芾','宋','宋诗','song-poetry','','[]','久聞韶鴨有靈蹤，首尾俱輕快御風。',32,'全唐诗/poet.song.114000.json','["久聞韶鴨有靈蹤，首尾俱輕快御風。", "公獨惠然持見贈，應知野性與余同。"]'),
('ecfda48b-91bc-4120-a3ee-ab7934f2ca39','陳子厚送韶鴨將以七絕因次其韵  其二','吳芾','宋','宋诗','song-poetry','','["\u897f\u6e56"]','興在江湖萬里間，洿池一曲豈能安。',32,'全唐诗/poet.song.114000.json','["興在江湖萬里間，洿池一曲豈能安。", "今朝來我西湖上，眼底陡驚天地寬。"]'),
('3b81c3dd-40e7-4829-a08c-5c4cf30254ad','陳子厚送韶鴨將以七絕因次其韵  其三','吳芾','宋','宋诗','song-poetry','','[]','湖光深處恣沉浮，未讓波間鷺與鷗。',32,'全唐诗/poet.song.114000.json','["湖光深處恣沉浮，未讓波間鷺與鷗。", "舊侶此時應羨汝，欲來相就苦無由。"]'),
('284eb4c3-93d1-4e9f-a74f-95a4477c9f7e','陳子厚送韶鴨將以七絕因次其韵  其四','吳芾','宋','宋诗','song-poetry','','[]','朝朝兩兩下平沙，添得湖中景趣嘉。',32,'全唐诗/poet.song.114000.json','["朝朝兩兩下平沙，添得湖中景趣嘉。", "碧卵從今生育去，便堪裝點作漁家。"]'),
('58f982ae-ff1a-4f90-9a80-8833e0486525','陳子厚送韶鴨將以七絕因次其韵  其五','吳芾','宋','宋诗','song-poetry','','[]','投迹山林不厭深，老來寧復計升沉。',32,'全唐诗/poet.song.114000.json','["投迹山林不厭深，老來寧復計升沉。", "水禽得得來相伴，應識幽人一片心。"]'),
('1170418a-6968-4e89-9920-3845919eb052','陳子厚送韶鴨將以七絕因次其韵  其六','吳芾','宋','宋诗','song-poetry','','[]','初來便自與人宜，相近相親自在飛。',32,'全唐诗/poet.song.114000.json','["初來便自與人宜，相近相親自在飛。", "底事悠然無畏忌，也知老子久忘機。"]'),
('f4393988-436e-4b42-9da3-e02db586bc30','陳子厚送韶鴨將以七絕因次其韵  其七','吳芾','宋','宋诗','song-poetry','','[]','雖是微禽亦美觀，豈無繒弋欲相干。',32,'全唐诗/poet.song.114000.json','["雖是微禽亦美觀，豈無繒弋欲相干。", "不須更起高飛念，且向湖中戢羽翰。"]'),
('47b572cd-c911-4334-a2b3-357ce34c4cf2','題珪師松雲菴','吳芾','宋','宋诗','song-poetry','','[]','一瓶一鉢一枝筇，皓首歸來萬事慵。',32,'全唐诗/poet.song.114000.json','["一瓶一鉢一枝筇，皓首歸來萬事慵。", "應笑白雲猶世態，却來庵外媚孤松。"]'),
('0dee1b8d-4467-4d3b-9bcb-516755be387c','錢廣文采芹亭','吳芾','宋','宋诗','song-poetry','','[]','開明後學日升車，千里文風一旦雄。',32,'全唐诗/poet.song.114000.json','["開明後學日升車，千里文風一旦雄。", "池上采芹摇水碧，帳中摛藻映紗紅。"]'),
('80a29156-9b79-49f6-adc3-ee31f8da078d','聞伯可郎中銳然有冥鴻之舉小詩奉慶','吳芾','宋','宋诗','song-poetry','','[]','郎省聲猷藹搢紳，看看步武到通津。',64,'全唐诗/poet.song.114000.json','["郎省聲猷藹搢紳，看看步武到通津。", "合留北闕扶宸極，却向西溪整釣綸。", "愧我暮年方謝事，羨君壯歲便抽身。", "時賢莫把衰翁比，林下如君只一人。"]'),
('4bd857a7-7c76-4f01-affb-789e6cef9e93','海棠','吳芾','宋','宋诗','song-poetry','','[]','靚妝濃艷雨濛茸，高下池臺細細風。',64,'全唐诗/poet.song.114000.json','["靚妝濃艷雨濛茸，高下池臺細細風。", "却恨韶華偏蜀土，更無顔色似川紅。", "尋芳只恐三春暮，把酒欣逢一笑同。", "子美詩才猶閣筆，至今寂寞錦城中。"]'),
('786ecc16-a606-4293-b6be-2590aef684d8','和澤民求海棠','吳芾','宋','宋诗','song-poetry','','[]','君是詩中老作家，笑將麗句換名花。',64,'全唐诗/poet.song.114000.json','["君是詩中老作家，笑將麗句換名花。", "花因詩去情非淺，詩爲花來語更嘉。", "須好栽培承雨露，莫令憔悴困塵沙。", "他年爛漫如西蜀，我欲從君看綺霞。"]'),
('d6197e37-2bf7-4056-8091-5674b87ed2a8','登景星巖','吳芾','宋','宋诗','song-poetry','','[]','道滿三千界，潮音未許緘。',48,'全唐诗/poet.song.114000.json','["道滿三千界，潮音未許緘。", "何爲獅子座，却上景星巖。", "天近雲隨步，林深翠滴衫。", "我來寧憚遠，端欲洗塵凡。"]'),
('bca93755-7360-48bf-8169-99a284a5e3ea','和陶影答形','吳芾','宋','宋诗','song-poetry','','[]','行止每依人，人皆笑我拙。',96,'全唐诗/poet.song.114000.json','["行止每依人，人皆笑我拙。", "獨以相從久，未能便棄絕。", "縱君得顯榮，亦耻事諛悅。", "人情苦好乖，會少常多別。", "而我獨與君，初不易生滅。", "相親如一體，亦不畏寒熱。", "但我常自暇，而君力常竭。", "若以此比方，孰優還若劣。"]'),
('969daf81-f80c-44b9-8f3e-9a0cd2f8a127','酬楊直閣知府','吳芾','宋','宋诗','song-poetry','','[]','識破人間僞與真，自憐擾擾百年身。',64,'全唐诗/poet.song.114000.json','["識破人間僞與真，自憐擾擾百年身。", "誰教來作剖符客，仍更去爲分閫人。", "故里溪山空入夢，舊家亭館想生塵。", "願言天意終從欲，歸去林間度幾春。"]'),
('edbd64ec-45e4-4ccd-b2c2-f0d48bf7e212','登卧龍山','吳芾','宋','宋诗','song-poetry','','[]','巋然千古卧龍山，節物年來□舊觀。',64,'全唐诗/poet.song.114000.json','["巋然千古卧龍山，節物年來□舊觀。", "猶有樓臺出天半，正令星斗逼人寒。", "春風偶種花千樹，夏日仍栽竹萬竿。", "自愧牧民無實□，漫留佳致後來看。"]'),
('8a177d27-64b2-4411-9161-1df6816eb888','句','吳芾','宋','宋诗','song-poetry','','[]','半刺豈能淹驥足，一封行見下龍墀。',16,'全唐诗/poet.song.114000.json','["半刺豈能淹驥足，一封行見下龍墀。"]'),
('78cd24f0-384f-4ab3-848c-0f71b50d3a73','句','余某','宋','宋诗','song-poetry','','[]','此生待足何時足，未老得閑方是閑。',16,'全唐诗/poet.song.114000.json','["此生待足何時足，未老得閑方是閑。"]'),
('51bf1040-b936-4326-8372-a04ef2c305e8','柘川漁火','蔣晉','宋','宋诗','song-poetry','','[]','玉川一带光涵秋，漁艇縱橫網罟稠。',64,'全唐诗/poet.song.114000.json','["玉川一带光涵秋，漁艇縱橫網罟稠。", "西風日落寒烟暝，煌煌燈火明中流。", "數點如螢走絡繹，影趁流波瀉金液。", "一聲欵乃明滅間，鄰雞又報東方白。"]'),
('31a831cc-7345-4026-a1b8-e8f5790f6f70','西巖勝水','蔣晉','宋','宋诗','song-poetry','','[]','柘川之西有削石，屹立巍巍峻如壁。',64,'全唐诗/poet.song.114000.json','["柘川之西有削石，屹立巍巍峻如壁。", "下有滄浪百尺深，澄清恰似秋天碧。", "逝者如斯竟不停，孺子長歌堪濯纓。", "故知源頭有活水，支流分派迢迢清。"]'),
('82369f65-1a46-4aeb-8b2c-4ede3efdba8e','鯉嶼浮嵐','蔣晉','宋','宋诗','song-poetry','','[]','天地造化真何如，幻就青嵐如鯉魚。',64,'全唐诗/poet.song.114000.json','["天地造化真何如，幻就青嵐如鯉魚。", "初疑孝子感天意，復恐古人傳素書。", "嵐氣時浮北烟瘴，縹緲奔騰似吹浪。", "遠跳深驚欲化龍，故有飄飄五雲障。"]'),
('56b7fc9a-295b-403f-b19f-91d9c4c0e6a2','翠屏列畫','蔣晉','宋','宋诗','song-poetry','','[]','青峯如屏高插天，懸崖積翠生雲烟。',64,'全唐诗/poet.song.114000.json','["青峯如屏高插天，懸崖積翠生雲烟。", "誰把王維舊墨蹟，巍巍高挂安居前。", "勝景應知世稀有，妙學丹青乃縮手。", "嗟哉畫有蠹損時，斯圖壽比南山久。"]'),
('e9cfbee6-e30f-4327-9c2b-cc8eba7d5476','葛井仙蹤','蔣晉','宋','宋诗','song-poetry','','[]','誰鑿雲根清氣洩，混混源泉流不竭。',64,'全唐诗/poet.song.114000.json','["誰鑿雲根清氣洩，混混源泉流不竭。", "味極太古比龍涎，飲之令人骨清徹。", "父老爲云有葛仙，丹成此地經多年。", "寂寞煙霞洞雲靜，惟留斯跡令人傳。"]'),
('bbad4825-1c1f-4edb-922f-b14577f20c33','題范烏程松桂亭','陳棣','宋','宋诗','song-poetry','','[]','誰云宰邑難，宰邑有真樂。',204,'全唐诗/poet.song.114000.json','["誰云宰邑難，宰邑有真樂。", "但知絃歌趣，永謝塵勞縛。", "琴堂吏驚散，晝日垂朱箔。", "燒香對棐几，文史資優學。", "一洗朱墨昏，至味非糟粕。", "范公今循良，一同聊笑謔。", "回視卓魯輩，政可束高閣。", "苕溪古侯邦，繁庶類京洛。", "壯哉萬戶邑，何異逢盤錯。", "公來省其俗，治劇操至約。", "政成日有餘，空庭可羅雀。", "西園久棄置，疏町走芒屩。", "經營四顧間，得地平如削。", "築堂號松桂，軒檻敞寥廓。", "雖無松桂陰，胸中自丘壑。", "况逢賢使君，成有新詩落。", "異時採歌謠，持用獻木鐸。"]'),
('a8057c13-fbdd-4da6-a12e-5a6bd65b3024','題竹友軒','陳棣','宋','宋诗','song-poetry','','[]','長夏苦炎熱，開軒除鬰蒸。',168,'全唐诗/poet.song.114000.json','["長夏苦炎熱，開軒除鬰蒸。", "簷前鳥雀喧，朝旭上朱甍。", "席間裁函丈，詩書浩縱橫。", "盤礴環堵間，幽獨懷友生。", "古人在黄卷，千載使我傾。", "出門窺物變，草木各鮮榮。", "青青牆東竹，見汝忽眼明。", "愛玩不能忘，移根傍軒楹。", "俯仰與竹俱，定交見深情。", "不是無朋友，此君氷玉清。", "風吹萬籟響，寒梢韻竽笙。", "我獨哦其間，詩作秋蟲鳴。", "琅玕亦有實，期汝向秋成。", "鳳凰何時來，翽翽翔我庭。"]'),
('680c49d2-ec55-467e-84a0-52051fe832b1','棲軒偶成呈同僚','陳棣','宋','宋诗','song-poetry','','[]','我本山中人，勉强束冠带。',216,'全唐诗/poet.song.114000.json','["我本山中人，勉强束冠带。", "欠伸輒有拘，似被天工械。", "誰令作此來，政爲窮所賣。", "規彼五斗粟，折腰何足怪。", "敢希拄頰傲，寧免望塵拜。", "平生浩然氣，摧落甘伍噲。", "茲軒粗可人，虛名供眼界。", "得從黄嬭遊，佳處時一解。", "多生作蠹魚，復此償書債。", "雖抗塵土容，耿耿氷壺在。", "同僚多俊遊，臺閣鵷鴻輩。", "胸中有雲夢，畧不見芥蔕。", "吏師有龔黄，民賊絕蜂蠆。", "而我躡後塵，嘉穀雜稊稗。", "詩壇欲尋盟，恐墮拋磚戒。", "翻思石鼎句，自取侯郎敗。", "終期探理窟，一洗荆榛隘。", "得肉姑置之，大嚼聊發快。"]'),
('bf5c337f-91c3-4dc2-b108-75459cc50494','次韻葛教授新闢柏桐軒','陳棣','宋','宋诗','song-poetry','','[]','柏桐有正性，梁琴豈其天。',168,'全唐诗/poet.song.114000.json','["柏桐有正性，梁琴豈其天。", "丹雘自煇燿，絃徽漫鏘然。", "深慙社旁櫟，政爾終天年。", "復愧南城槁，猶知過飛仙。", "廟前今安在，爨下亦浪傳。", "何當生學宮，廣文遺新篇。", "色映醉吟杜，陰休眠晝邊。", "端如兩高弟，儼立聽誦絃。", "又如雙青衣，對舞風露前。", "方依植壇杏，不羨干雲楩。", "日哦二木間，妙意遺言詮。", "霜枝半摧剝，月影相回旋。", "後雕歲寒見，始華春意全。", "比德君無愧，五柳徒自賢。"]'),
('3643d6b3-2e17-4d08-badc-865341bd4627','再次韻柏桐軒','陳棣','宋','宋诗','song-poetry','','[]','修垣蔽軒楹，如觀坐井天。',168,'全唐诗/poet.song.114000.json','["修垣蔽軒楹，如觀坐井天。", "高人爲披豁，物趣俱森然。", "柏桐伍蒿萊，混迹幾歲年。", "俄驚俯丹楹，况得依臞仙。", "佳名一品題，好語萬口傳。", "高參溜雨句，美並朝陽篇。", "掄才稽往牒，橫陳榱棟邊。", "論功及乃祖，屢薦薰風絃。", "謙居髯松下，優在良梓前。", "荆徐入貢時，曾不數樟楩。", "固殊上林木，虞衡日量詮。", "且異溫室樹，衣冠時遶旋。", "此方安靜僻，所欲唯生全。", "植物貴遂性，憑君較愚賢。"]'),
('3ae44c67-5099-44ab-9703-ef10f73ccb7a','次韻蘇伯言題所居鑑止軒','陳棣','宋','宋诗','song-poetry','','[]','小軒劣容膝，詎敢邀君詩。',96,'全唐诗/poet.song.114000.json','["小軒劣容膝，詎敢邀君詩。", "君詩亟借重，物趣俱新奇。", "簷前列蒼翠，檻外潴漣漪。", "憑欄作癡兀，欲靜忘五綦。", "湛然俯明鏡，水定心不馳。", "微風忽披拂，巾袂俄變移。", "緬思東坡公，昔與潁水嬉。", "此樂五十年，人間真未知。"]'),
('ed28c370-b721-4f54-8598-92008a66ed83','次韻鄭舜舉題簿廳交翠軒','陳棣','宋','宋诗','song-poetry','','[]','人生一漚浮，何適非暫寄。',168,'全唐诗/poet.song.114000.json','["人生一漚浮，何適非暫寄。", "會須脫塵勞，談文不談利。", "開軒得此君，意愜投宿嗜。", "未堪食鳳凰，已足巢翡翠。", "惜哉小窗櫳，此地久何閟。", "想當未闢初，寧免簿書累。", "高人一披拂，便有無窮意。", "紛紛市廛子，冠蓋亂如沸。", "倘令見清標，魄褫復喪氣。", "客如王子猷，不速端可致。", "嗟予飽憂患，久矣無佳思。", "舊學已榛蕪，聞一豈知二。", "市肆羅無目，聊爲將軍地。", "斗酒詩百篇，是乃公能事。"]'),
('4ca36c3b-2ca8-4bda-b399-1dd857e58689','次韻陳季陵記夢','陳棣','宋','宋诗','song-poetry','','[]','夜閒得安寢，方期萬事休。',156,'全唐诗/poet.song.114000.json','["夜閒得安寢，方期萬事休。", "那知清夢中，螘穴有勝遊。", "朝把南柯麾，暮獵龜山頭。", "停杯猶未舉，俯仰二十秋。", "等爲幻緣縛，名實或相浮。", "邯鄲囊中枕，徑渡竹葉舟。", "俄頃失所歷，變滅隨東流。", "遊仙豈神交，因想理或不。", "至人本無夢，偶夢非謬悠。", "乃知一念熟，寤寐欻何求。", "子建賦感甄，空貽方策羞。", "何當破諸妄，自足銷沉憂。", "政使對癡人，言之亦寡尤。"]'),
('52b60e22-372e-4ded-abca-460c5641379d','先春賦梅一首','陳棣','宋','宋诗','song-poetry','','[]','與客到先春，衰思覺飛越。',168,'全唐诗/poet.song.114000.json','["與客到先春，衰思覺飛越。", "時當萬卉凋，似補羣花闕。", "始信元化功，生意何曾輟。", "却疑鈞天宴，羣仙委珮玦。", "不數藐姑仙，神膚瑩氷雪。", "癯然抱清幽，卓爾負奇絕。", "生香巧藏密，靜艷羞容悅。", "陽萌知獨復，歲寒見孤潔。", "我來觴其下，坐對垂垂發。", "頭白不待摧，顔赬爲爾設。", "因思年少時，高枝手攀折。", "林逋與何遜，妙語誰優劣。", "老矣吟事慳，人笑心如鐵。", "何當夜深來，更看梢頭月。"]'),
('09884d0f-047f-457b-a68b-938ddfdbc8c1','惜梅','陳棣','宋','宋诗','song-poetry','','[]','朔雪沒寒蕪，嚴威等羣木。',144,'全唐诗/poet.song.114000.json','["朔雪沒寒蕪，嚴威等羣木。", "東君惜江梅，先與借微燠。", "造物逞新奇，亭亭付幽獨。", "天然氷雪姿，不許鉛華凟。", "疎影浸澄波，斜枝度修竹。", "奇標含春容，清致漫山腹。", "夜月耿扶踈，寒風來馥鬰。", "素艷等瓊瑶，真香笑蘭菊。", "昨宵風雨顛，遺英滿平陸。", "憑誰望蒼天，榮枯何太速。", "凌晨眠霜林，餘芳猶五六。", "不厭終日看，尚可供詩目。"]'),
('3f3a5f39-7bb9-4bb6-859d-a84845af8d86','次韻葉夢符端午','陳棣','宋','宋诗','song-poetry','','[]','吾邦重午節，興目皆可寓。',216,'全唐诗/poet.song.114000.json','["吾邦重午節，興目皆可寓。", "遊人肆喧闐，畫舫紛排布。", "遡風伐鼉鼓，擊楫觀競渡。", "驕豪務相誇，水陸爭治具。", "醉憂瓶之罄，懽迫日云暮。", "朋從喜盍簪，謔浪時一遇。", "朅來廷尉府，官冷知誰顧。", "吻燥無復濡，腹枵何時飫。", "堂堂匡鼎來，解后肯同趣。", "携家忽過我，市飲容旋酤。", "遥知分已投，更喜首暫聚。", "慙非浴沂人，鄙志蒙推與。", "憐我孤危資，極力爲調護。", "高談驚四筵，坐使兒女怖。", "便當追彥國，未肯多文度。", "長篇粲珠玉，綺語斥霞鶩。", "人生類飄蓬，會合寧有數。", "交情看白頭，何必論新故。"]'),
('fefb6214-0c4e-4e18-a90d-190d0a1e90cc','沈德和使君生辰四首  其一','陳棣','宋','宋诗','song-poetry','','[]','星斗煥靈輝，川嶽儲英氣。',120,'全唐诗/poet.song.114000.json','["星斗煥靈輝，川嶽儲英氣。", "散爲天地祥，鍾作人間瑞。", "正應五百年，乃克見名世。", "長庚夢太白，斯文得鼓吹。", "崧高生甫申，中興資屏衛。", "若人不時出，或出豈無謂。", "岩廊頼嘉謨，民物蒙美利。", "權輿生吾道，羽翼副六藝。", "我公豈其倫，稟賦已殊異。", "由來活國手，固自有次第。"]'),
('ba5a7e2f-4a50-47fc-97ec-fec2fa99d1b2','沈德和使君生辰四首  其二','陳棣','宋','宋诗','song-poetry','','[]','麟閣仙蓬萊，蘭省星躔次。',120,'全唐诗/poet.song.114000.json','["麟閣仙蓬萊，蘭省星躔次。", "瞻之已足榮，到者亦未易。", "惟公名德尊，飛聲從早歲。", "青錢中妙選，豈止一科第。", "果聞超卓姿，遍歷清華地。", "青藜照讐書，赤管供奏議。", "視典昔常遊，觀耕嘗入侍。", "熙朝百度新，一麾煩卧治。", "欲知天眷隆，御屏題姓氏。", "公豈久外人，趣裝宜早計。"]'),
('7e5a3684-4d6a-48fd-b905-baf397743325','沈德和使君生辰四首  其三','陳棣','宋','宋诗','song-poetry','','[]','桐川古桃州，地僻官事少。',120,'全唐诗/poet.song.114000.json','["桐川古桃州，地僻官事少。", "簡靜宜有餘，苛刻則煩擾。", "公來省其俗，好尚已默了。", "碧凝燕寢香，青鞠圜扉草。", "麥壠雨初勻，棠陰風自掃。", "回觀漢循良，未足語治道。", "豈惟術數多，更覺規模小。", "公將宰天下，一郡乃戲嬲。", "便當作吏師，詎止爲民表。", "邦人何所祈，區區頌難老。"]'),
('f4ce3f9a-0d99-496d-b0b5-3a0b9e50fad8','沈德和使君生辰四首  其四','陳棣','宋','宋诗','song-poetry','','[]','化工有至仁，噓爲三月春。',120,'全唐诗/poet.song.114000.json','["化工有至仁，噓爲三月春。", "寧知清淑氣，回薄在茲辰。", "茲辰亦何有，璇霄見老人。", "黄堂沸笙簫，宴席方橫陳。", "寶觴酌流霞，艷歌飛梁塵。", "未嘗王母桃，敢薦蒙莊椿。", "賤子今何幸，明時識鳳麟。", "馬曹寧寄傲，鼠技屢迷津。", "尚容東郭吹，敢效西子顰。", "誓將頑鈍質，埏埴煩陶鈞。"]'),
('dc1bda94-4d1f-445f-a6e2-77de1f85658b','釣瀨漁樵行送嚴守蘇伯業赴闕','陳棣','宋','宋诗','song-poetry','','[]','漁樵生長子陵州，偶爲城市逍遥遊。',320,'全唐诗/poet.song.114000.json','["漁樵生長子陵州，偶爲城市逍遥遊。", "相逢欲話平生事，以手加額頻點頭。", "自言家世居村落，頗厭吾邦風土惡。", "大饑小歉偶一遭，棄擲鋤耰弄刀槊。", "二十年前事可驚，錦襦繡帽爭乘城。", "太平日久人忘戰，衣冠荆棘戈鋋腥。", "去年米貴無餘粟，往往驚顧如麋鹿。", "大開陳廩貸兼并，却笑隣邦才食粥。", "只今豐盈天報施，餘糧棲畝麥兩岐。", "牛羊日落草萊處，場圃秋深䆉稏時。", "父老歌謠童稚笑，歡聲萬口如同調。", "向來遊手今良農，今日膏腴昔荒嶠。", "漁樵無事官無逋，民不識吏亡追呼。", "田間第見隨軒鹿，道上兼無攫肉烏。", "問云何術能臻此，盡道我公才德美。", "文采風流求古人，循良事業空前史。", "公今去我歸朝天，攀轅截鐙何當前。", "願公早佩紫荷橐，顧我擬續甘棠篇。", "欲碑遺愛傳千古，政聲未暇從頭數。", "大書特書不一書，請載漁樵當日語。"]'),
('e790355b-d42d-470f-9fe8-c793ba07fa14','次韻陶幾道觀洪積仁詩編','陳棣','宋','宋诗','song-poetry','','[]','令尹韜潛藏六龜，逸韻長憂兒輩知。',160,'全唐诗/poet.song.114000.json','["令尹韜潛藏六龜，逸韻長憂兒輩知。", "剡藤敲氷琢玉板，月兔脫穎供毛錐。", "冥搜豈但夢春草，招隠昔嘗吟桂枝。", "江山駿奔來筆下，疑有神助非人爲。", "公餘退客醉經史，底用紅裙捧玉巵。", "凌雲未讀相如賦，解頤共聽匡衡詩。", "詎容陶令賦歸去，且效謫仙歌別離。", "手題六紙勿輕示，把玩自足娛安期。", "千篇政恐雷電取，數仞不許門人闚。", "何當築壇拜詩將，一看橫槊英雄姿。"]'),
('42636ba5-be7a-45e9-8a4b-00e9cf7738a8','題李杜畫像','陳棣','宋','宋诗','song-poetry','','[]','吟詩莫學李太白，千首萬言皆酒色。',128,'全唐诗/poet.song.114000.json','["吟詩莫學李太白，千首萬言皆酒色。", "吟詩莫學杜拾遺，一生抱恨長嗟咨。", "二豪胸中有佳趣，詩酒聊以發其悟。", "世人有眼誰識真，第見詩篇不見人。", "借令置之廟堂上，事業肯道風騷將。", "睥睨連帥奴將軍，英風義氣高薄雲。", "我今再拜觀遺像，猶疑飯顆相逢樣。", "詩題繪事在人間，光焰何翅長萬丈。"]'),
('fc57eab9-cafd-4d7e-9e46-6537faefe418','鄭倅生辰','陳棣','宋','宋诗','song-poetry','','[]','柯山插空天爲隣，飛仙窟宅無纖塵。',256,'全唐诗/poet.song.114000.json','["柯山插空天爲隣，飛仙窟宅無纖塵。", "降靈孕秀神所相，豈但崧高生甫申。", "笑別方壺離紫府，道骨清標映華組。", "二十八宿羅心胸，霽月光風映眉宇。", "書带家聲舊著聞，相國邸第南北分。", "人間未省見三絕，天上曾觀瑞五雲。", "箋詩傳禮窮家學，豈止談經能折角。", "鼓篋來爲碧水遊，賢關英俊推先覺。", "雄文大手古無倫，安知韓柳非前身。", "方期江夏無雙譽，只許樊川第五人。", "厭直承明祈外補，暫擁屏星左銅虎。", "萬口爭歌王海沂，懸榻已題陳仲舉。", "籍甚聲聞咫尺顔，竚聽鋒車趣賜環。", "歸持清禁紫荷橐，却踏彤墀玉笋班。", "我今幸遇懸弧旦，敢採民謠書弱翰。", "一言何以祝我公，願輔昇平到不窮。"]'),
('086a8d11-f57e-494d-b04f-fc0666a415d1','古遊俠行','陳棣','宋','宋诗','song-poetry','','[]','君不見長安俠少兒，臂鷹走狗爭輕肥。',181,'全唐诗/poet.song.114000.json','["君不見長安俠少兒，臂鷹走狗爭輕肥。", "一朝遭渠國士知，笑視鼎鑊如氷澌。", "翹關負重俱細事，拔山扛鼎焉能爲。", "橫行匈奴十萬騎，肯以祕計干閼氏。", "朝竊晉鄙符，暮解邯鄲圍。", "軍中不聞天子詔，向來灞上皆兒嬉。", "我有黄石書，孺子漫多奇。", "我有歐冶劍，荆卿何足揮。", "運籌折衝衽席上，料敵决勝如蓍龜。", "世遭右文歎數奇，縱有勇畧將安施。", "漢皇方受宣室釐，干戈不用包虎皮。", "使我不得封萬戶，恨不生當高祖時。"]'),
('d94bf974-5628-4e9d-b074-9b136f4470f8','傷春詞','陳棣','宋','宋诗','song-poetry','','[]','春風兮颸颸，春日兮遲遲。',175,'全唐诗/poet.song.114000.json','["春風兮颸颸，春日兮遲遲。", "草木秀兮原野，蘭茝芳兮水湄。", "美人去兮何所，白雲深兮莫窺。", "望極浦兮掩淚，倚危檻兮懷思。", "囁嚅兮鳦語，連娟兮蝶飛。", "感微物兮靈偶，私自憐兮芳時。", "玲瓏兮瓊珮，沉寂兮蕙幃。", "對芳時兮太息，豈獨凜秋兮足悲。", "香消悴兮□鸞鏡，愁委積兮堆蛾眉。", "登山臨水兮有蘭夢，斷雁沉魚兮無錦詩。", "鶗鴂鳴兮衆芳衰，春冉冉兮不可羈。", "人生行樂兮將何之，王孫王孫兮胡不歸。"]'),
('9937484b-9575-49f1-a873-d4cf9a216167','食枸杞菊','陳棣','宋','宋诗','song-poetry','','[]','君不見天隨有宅松江曲，屋隙牆陰多杞菊。',198,'全唐诗/poet.song.114000.json','["君不見天隨有宅松江曲，屋隙牆陰多杞菊。", "課兒採掇入杯盤，匕箸芳香勝粱肉。", "又不見坡公昔佩刺史符，賓客少至無與娛。", "偶餐杞菊作後賦，捫腹噎嘔猶軒渠。", "散人枯腸真食杞，居士戲筆聊爾耳。", "膠西自古號侯邦，齋厨縱乏寧需此。", "我今作掾長苦饑，一區不異耕田時。", "太倉紅腐才五斗，舉家食粥寧忍炊。", "頹城草木迷荒榭，綠穎芳苕羅舍下。", "官閒擷取芼春羹，未棘未莎皆不赦。", "三年享此似無饜，二者誰云不可兼。", "行趣歸裝耕谷口，此物猶堪饁南畝。"]'),
('9edfcbb5-7b80-40c3-85a7-83f5774761a4','次韻章堯文梅花','陳棣','宋','宋诗','song-poetry','','[]','先生讀書常閉戶，卒歲優游娛藝圃。',192,'全唐诗/poet.song.114000.json','["先生讀書常閉戶，卒歲優游娛藝圃。", "風雷筆舌待時攄，錦繡肝腸終日吐。", "鳴騶未驗北山文，絳帳且爲東道主。", "忽作尋梅得得來，南枝未落北枝開。", "攀條弄英不能去，只愁白日空西頹。", "臨池照影都無伴，偶挂幽昏不用媒。", "主人生來幾傳癖，道耕德獵無遺力。", "形模奇古每起予，議論縱橫時奪席。", "但喜書橫孔聖編，那知梅怨桓伊笛。", "正值清霜爛漫晴，賓從滿目皆豪英。", "未開東閣緣何事，要見詩鳴訴不平。", "明日定拚花下醉，想公不負白鷗盟。"]'),
('9a1df0f1-bda2-47cd-8fc6-7ab4b7c5a498','驟雨呈質夫兄','陳棣','宋','宋诗','song-poetry','','[]','屏翳驅馳雲陣疾，西山猶銜半輪日。',192,'全唐诗/poet.song.114000.json','["屏翳驅馳雲陣疾，西山猶銜半輪日。", "迅雷震地窗戶摇，急雨翻盆溝澮溢。", "紫電燒空天爲低，黑風逆浪海欲立。", "縱多虐魃未爲殃，直使長鯨那暇吸。", "草木號呼山鬼驚，珠璣亂迸鮫人泣。", "曲畦走水白紛紛，稚穗抽芒青戢戢。", "童稚休傳蜥蜴歌，倉箱行貯生民粒。", "枝端發翠喜濯枝，池面凝漚占戴笠。", "猛省呼晴鳩婦鳴，旋看突漲魚兒出。", "窗扉共賞一襟凉，屋漏俄驚半床濕。", "鷗鷺盟邊引望遥，芭蕉聲裏催詩急。", "請君速著瑞雨頌，要上新編華萼集。"]'),
('a7fa8996-ac46-4db6-b951-8d09b7acdf12','送李明甫召除奉常簿','陳棣','宋','宋诗','song-poetry','','[]','睿主臨軒達四聰，皎如麗日明高穹。',224,'全唐诗/poet.song.114000.json','["睿主臨軒達四聰，皎如麗日明高穹。", "傾葵發蔀燭幽隠，熙然萬物還春風。", "鼎新百度躋時雍，西垣東省羅鵷鴻。", "鋒車趣召無虛日，高陽才子咸登庸。", "古桃小壘江之東，邇來慶事何其豐。", "使君已秉螭坳筆，尺一于今召我公。", "我公智畧真夔龍，劍佩合侍明光宮。", "昇平雅樂欲大備，暫借筆管調笙鐘。", "奉常地峻位望隆，不與列棘監寺同。", "文傳章句羣經外，器識錞于衆樂中。", "不願封侯食萬鍾，不羨乘雲遊樊桐。", "羨公此行登仙去，蜚聲直上徹九重。", "上方更化歸醇醲，論思獻納宜舂容。", "凝旒若訪草茅士，餘論無忘采菲葑。"]'),
('5aeb9b7e-971a-4e4f-befa-ecc22f87caad','鬻婦歎','陳棣','宋','宋诗','song-poetry','','[]','凶年老弱難相保，歸與婦謀謀不早。',128,'全唐诗/poet.song.114000.json','["凶年老弱難相保，歸與婦謀謀不早。", "啼饑滿耳不忍聞，待得麥秋人已槁。", "有辭欲說重酸辛，欲說未說眉再顰。", "就令相視饑餓死，何當持汝歸富人。", "朝歸富人夕得粟，數口尚堪同食粥。", "愁容斂袂哽不言，稚子牽衣驚且哭。", "答云至此奈若何，離別孰與性命多。", "他年豐稔五穀熟，勿吝百金來相贖。"]'),
('612cc51e-5b6f-45f0-95b4-f07964c0746d','題鑑止軒','陳棣','宋','宋诗','song-poetry','','[]','安身南北皆吾里，勿較使行兼尼止。',64,'全唐诗/poet.song.114000.json','["安身南北皆吾里，勿較使行兼尼止。", "心猶泥絮吹不起，豈有顔甲生微泚。", "方塘凈綠含真理，與我娛嬉聊爾爾。", "佳處難言還隠几，冷煖自知如飲水。"]'),
('57657258-d03c-4d63-a557-3935f085dc00','端午洪積仁召客口占戲柬薛仲藏','陳棣','宋','宋诗','song-poetry','','[]','佳節撩人愁欲卧，衝門都騎傳呼過。',64,'全唐诗/poet.song.114000.json','["佳節撩人愁欲卧，衝門都騎傳呼過。", "想簪榴艾泛菖蒲，應召鄒枚雜郊賀。", "歌聲端不羨紅兒，酒力真堪欺白墮。", "自愧雖非趙倚樓，何當一效陳驚座。"]'),
('ff9b6ba8-26bb-4789-a13f-08a772acf12c','春日雜興五首  其一','陳棣','宋','宋诗','song-poetry','','[]','春色遽如許，春愁一望賒。',48,'全唐诗/poet.song.114000.json','["春色遽如許，春愁一望賒。", "簾低宜著燕，柳暗欲藏鴉。", "鳩婦催踈雨，蜂臣趁落花。", "只愁清景促，無計駐曦車。"]'),
('29410ac1-b200-4507-a0b4-b8e71d834674','春日雜興五首  其二','陳棣','宋','宋诗','song-poetry','','[]','地僻近煙蘿，門無車馬過。',48,'全唐诗/poet.song.114000.json','["地僻近煙蘿，門無車馬過。", "林深宜雨急，野曠覺春多。", "草軟遊人醉，鶑嬌姹女歌。", "顛狂江上興，可奈少陵何。"]'),
('06b36075-7101-4f08-97b6-99d702f4f514','春日雜興五首  其三','陳棣','宋','宋诗','song-poetry','','[]','桃李漫芬芳，終然委路旁。',48,'全唐诗/poet.song.114000.json','["桃李漫芬芳，終然委路旁。", "踏青心欲醉，舉白興何長。", "夢覺池塘綠，詩成草木香。", "懶追時俗好，獨立倚蒼茫。"]'),
('2f81e0e2-eaca-4503-8a7a-e76f345eb176','春日雜興五首  其四','陳棣','宋','宋诗','song-poetry','','[]','鴨綠前溪漲，鵝黄遠柳垂。',48,'全唐诗/poet.song.114000.json','["鴨綠前溪漲，鵝黄遠柳垂。", "微波卷羅带，細葉展顰眉。", "愛酒常歌頌，傷春更賦詩。", "東君無限思，全在野桃枝。"]'),
('4114fb0a-0409-4c53-b22c-a8bdf7252afe','春日雜興五首  其五','陳棣','宋','宋诗','song-poetry','','[]','料峭寒猶薄，陰雲带晚烟。',48,'全唐诗/poet.song.114000.json','["料峭寒猶薄，陰雲带晚烟。", "雨催驚蟄候，風作勒花天。", "日永消香篆，愁濃逼酒船。", "爲君借餘景，收拾賦新篇。"]'),
('63fc52f8-7acf-4398-a16a-d2157b3849d5','春日偶成三首  其一','陳棣','宋','宋诗','song-poetry','','[]','東君馳驛騎，萬里一宵通。',48,'全唐诗/poet.song.114000.json','["東君馳驛騎，萬里一宵通。", "柳眼凝晴碧，桃腮泣露紅。", "丙鱗安淺瀨，乙羽怯柔風。", "莫向高城望，愁生阿堵中。"]'),
('aa4f813e-65dd-49e7-9b67-c05e3da8cfbe','春日偶成三首  其二','陳棣','宋','宋诗','song-poetry','','[]','雨後春逾麗，平堤漲綠波。',48,'全唐诗/poet.song.114000.json','["雨後春逾麗，平堤漲綠波。", "侵人花氣釀，刺眼麥芒多。", "舴艋閒蓑笠，鞦韆醉綺羅。", "光陰難把翫，秀句與消磨。"]'),
('ddbbeb6b-3ff9-4e3c-ab61-bb20382348dd','春日偶成三首  其三','陳棣','宋','宋诗','song-poetry','','[]','陋巷逢春日，生涯亦足誇。',48,'全唐诗/poet.song.114000.json','["陋巷逢春日，生涯亦足誇。", "堆錢聚榆莢，積絮撲楊花。", "旌旆千行竹，笙歌兩部蛙。", "憑誰爲商榷，何似五侯家。"]'),
('be4978d4-fae9-4cd7-b854-2c0de2268f79','再次韻  其一','陳棣','宋','宋诗','song-poetry','','[]','小圃香初足，枯池水乍通。',48,'全唐诗/poet.song.114000.json','["小圃香初足，枯池水乍通。", "捲簾延舊燕，掃徑襯飛紅。", "寂寂梨花雨，斜斜柳带風。", "東君有餘思，別在一壺中。"]'),
('5a2d7f59-eff1-4096-91ba-f772e8b6ffdf','再次韻  其二','陳棣','宋','宋诗','song-poetry','','[]','雨過灘聲急，無風亦自波。',48,'全唐诗/poet.song.114000.json','["雨過灘聲急，無風亦自波。", "花稠春意閙，山遠月明多。", "地僻無來轍，門閒欲設羅。", "胸中元礧磈，詩酒漫揩磨。"]'),
('95aaa4bf-2e7d-4ef7-8c76-6c2178d963b9','再次韻  其三','陳棣','宋','宋诗','song-poetry','','[]','老去懽情少，逢人强自誇。',48,'全唐诗/poet.song.114000.json','["老去懽情少，逢人强自誇。", "閒愁付蕉葉，衰鬢耻菱花。", "倚杖閒捫虱，臨池戲詠蛙。", "深慙詩律細，何以世吾家。"]'),
('c3ea65c1-c323-4529-8650-f5201501b35d','疊韻春日雜興五首  其一','陳棣','宋','宋诗','song-poetry','','[]','南陌遊人少，東城去路賒。',48,'全唐诗/poet.song.114000.json','["南陌遊人少，東城去路賒。", "尋芳閒趁蝶，失喜漫占鴉。", "着物春猶淺，薰人氣自華。", "夜來風雨急，驚動阿香車。"]'),
('b5fb635a-de51-459b-a109-de1d096becbd','疊韻春日雜興五首  其二','陳棣','宋','宋诗','song-poetry','','[]','幽懷聊自適，踈性懶相過。',48,'全唐诗/poet.song.114000.json','["幽懷聊自適，踈性懶相過。", "塵事偏宜少，詩篇不厭多。", "三人花下酒，一曲醉時歌。", "此外非吾事，陶陶奈樂何。"]'),
('916e5e75-6e02-4546-9594-80bbc24b1e7d','疊韻春日雜興五首  其三','陳棣','宋','宋诗','song-poetry','','[]','遣興文楸內，微吟錦瑟旁。',48,'全唐诗/poet.song.114000.json','["遣興文楸內，微吟錦瑟旁。", "泉聲谷口靜，月色竹陰長。", "酒入肌膚暈，茶餘齒頰香。", "望窮却回首，此意造微茫。"]'),
('338bd5e3-6014-44d9-89d2-769b2af8662b','疊韻春日雜興五首  其四','陳棣','宋','宋诗','song-poetry','','[]','經春衣带賸，過午食簞垂。',48,'全唐诗/poet.song.114000.json','["經春衣带賸，過午食簞垂。", "嫩綠方迷眼，輕黄未上眉。", "世情無足語，節物總堪詩。", "未展摶風翼，鷦鷯且一枝。"]'),
('cf167199-13db-491c-90cf-1ef3aa7abcda','疊韻春日雜興五首  其五','陳棣','宋','宋诗','song-poetry','','[]','踈鐘餘逸響，野燒矗孤煙。',48,'全唐诗/poet.song.114000.json','["踈鐘餘逸響，野燒矗孤煙。", "輕暖花邊日，微寒雨後天。", "才能拆襪線，詩思上灘船。", "却憶峨嵋老，杯停已百篇。"]'),
('15ac41cc-e338-4397-abed-1256fcbc26b7','春雨','陳棣','宋','宋诗','song-poetry','','[]','春雨止復作，無聊終日閒。',48,'全唐诗/poet.song.114000.json','["春雨止復作，無聊終日閒。", "殷紅悲着地，淺綠暗歸山。", "雲幕久蒙潤，風扉每日關。", "愁端與詩思，容易減朱顔。"]'),
('9691c74c-07d9-4181-ac3f-11a2fe7d2de8','寒食懷公藻幾道','陳棣','宋','宋诗','song-poetry','','[]','灑落陶彭澤，風流陳太丘。',48,'全唐诗/poet.song.114000.json','["灑落陶彭澤，風流陳太丘。", "別來添夕夢，歸日負春遊。", "已改枯榆火，寧汙寒具油。", "不知行樂地，能話野人不。"]'),
('da9ef785-a1df-4f3b-b626-3ca1713eb024','倦暑','陳棣','宋','宋诗','song-poetry','','[]','試作西風想，煩襟鬰嫩凉。',48,'全唐诗/poet.song.114000.json','["試作西風想，煩襟鬰嫩凉。", "李沉寒玉碧，瓜泛淺金黄。", "羽扇徒揮雪，紗厨不貯香。", "白醪雖可漉，染指敢先嘗。"]'),
('09a19244-69ad-4813-ae8d-b7d296d25667','感懷二首  其一','陳棣','宋','宋诗','song-poetry','','[]','道義年來勝，幽居興倍長。',48,'全唐诗/poet.song.114000.json','["道義年來勝，幽居興倍長。", "望隨愁共遠，懶與事相妨。", "斜月光生座，脩梧影轉廊。", "是心無起滅，世態自炎凉。"]'),
('aa3e7911-4bb1-4a0c-96dc-cc8d782035a5','感懷二首  其二','陳棣','宋','宋诗','song-poetry','','[]','已嘆東隅失，桑榆浩莫收。',48,'全唐诗/poet.song.114000.json','["已嘆東隅失，桑榆浩莫收。", "只知心緒懶，那覺鬢毛秋。", "有酒堪藏拙，無門可避愁。", "吾今知此意，萬事付悠悠。"]'),
('d501f814-5000-4ecf-9ab0-09876d66ff4a','遣興','陳棣','宋','宋诗','song-poetry','','[]','早願風雲會，那知歲月侵。',48,'全唐诗/poet.song.114000.json','["早願風雲會，那知歲月侵。", "未應忘故步，已覺負初心。", "蕙帳聊跧伏，天閽隔遽深。", "且憑詩遣興，往事任瓶沉。"]'),
('2bebc79e-c7c5-4056-b9f0-c7dbcc15a294','靜夜','陳棣','宋','宋诗','song-poetry','','[]','靜夜披黄卷，青藜照五行。',48,'全唐诗/poet.song.114000.json','["靜夜披黄卷，青藜照五行。", "恨無知我鮑，空羨起予商。", "學業心將棘，功名鬢欲霜。", "此生應自斷，無復問穹蒼。"]'),
('26511877-01b5-43e5-859c-a0430e9a73cf','晨起趨府','陳棣','宋','宋诗','song-poetry','','[]','五鼓未停撾，喧呼趨早衙。',48,'全唐诗/poet.song.114000.json','["五鼓未停撾，喧呼趨早衙。", "霜風晨正急，望月曉初斜。", "輿竹依青蓋，燈籠閃絳紗。", "三年蝴蝶夢，笑殺野人家。"]'),
('5b2c01ef-94d8-4349-be59-aef8a26c8905','清晝','陳棣','宋','宋诗','song-poetry','','[]','庭院閒清晝，踈槐轉午陰。',48,'全唐诗/poet.song.114000.json','["庭院閒清晝，踈槐轉午陰。", "悄無人過眼，却有事經心。", "續夢聊欹枕，牽愁擬破琴。", "可憐精衛志，欲障海波深。"]'),
('d49be533-55d9-434d-a705-b24e1307f870','獨覺','陳棣','宋','宋诗','song-poetry','','[]','簷滴蕭蕭靜，微凉午睡宜。',48,'全唐诗/poet.song.114000.json','["簷滴蕭蕭靜，微凉午睡宜。", "鶑簧有餘韻，螘穴不多時。", "篆燼回風滅，花陰晚日移。", "覺來無一事，追夢續新詩。"]'),
('a4318a53-ccca-4488-bdfc-94a0cd677a7f','踈梅','陳棣','宋','宋诗','song-poetry','','[]','發興江頭路，相將月下臺。',48,'全唐诗/poet.song.114000.json','["發興江頭路，相將月下臺。", "衝行逢縞袂，迫視得踈梅。", "木偶當三嗅，石腸應九迴。", "鍾情唯我輩，欲去更徘徊。"]'),
('bf778fae-154e-4629-8309-549be7ac77ec','古剎','陳棣','宋','宋诗','song-poetry','','[]','古剎囂塵外，浮圖屋角西。',48,'全唐诗/poet.song.114000.json','["古剎囂塵外，浮圖屋角西。", "殘緇猶贊仰，孳羽共依棲。", "清影蕪城遠，孤棱落照低。", "丹梯儻容躡，極目飽雙溪。"]'),
('06b8bf94-835f-469f-af8f-cad8c8edc26d','芳園','陳棣','宋','宋诗','song-poetry','','[]','勳業尊朝著，園池近日光。',48,'全唐诗/poet.song.114000.json','["勳業尊朝著，園池近日光。", "雕欄紅玉列，羽蓋碧荷張。", "草薙難滋蔓，花開寧久長。", "當年金谷地，榛棘斷人腸。"]'),
('de3afe90-4f9e-455a-8945-8b93b87e76c6','挽丞相祁國公三首  其一','陳棣','宋','宋诗','song-poetry','','[]','斧扆求良弼，鈞衡得偉人。',48,'全唐诗/poet.song.114000.json','["斧扆求良弼，鈞衡得偉人。", "文章照黼黻，勳業見經綸。", "化洽編氓阜，時調寶歷新。", "方祈永霖雨，俄復跨箕辰。"]'),
('54ef4b71-0634-4da4-a3d8-adaf5b2fd637','挽丞相祁國公三首  其二','陳棣','宋','宋诗','song-poetry','','[]','寵極心彌小，名尊貌愈恭。',48,'全唐诗/poet.song.114000.json','["寵極心彌小，名尊貌愈恭。", "勛華雙輔翼，槐鼎四登庸。", "海宇熙春物，邊陲罷夕烽。", "了無能致績，頌筆漫形容。"]'),
('6c2a3d71-bccd-4c08-b6c8-8031dac334e1','挽丞相祁國公三首  其三','陳棣','宋','宋诗','song-poetry','','[]','强壯登黄閣，斑衣衮繡成。',48,'全唐诗/poet.song.114000.json','["强壯登黄閣，斑衣衮繡成。", "飛聲追丙魏，有子繼韋平。", "舟楫川方濟，龍蛇夢倏驚。", "天胡嗇遐壽，舉世但哀榮。"]'),
('1856df91-ceb0-430c-885f-1a4edd233edf','挽知軍劉公三首  其一','陳棣','宋','宋诗','song-poetry','','[]','種學三冬富，禔身百行兼。',48,'全唐诗/poet.song.114000.json','["種學三冬富，禔身百行兼。", "文章崑玉瑩，政事莫邪銛。", "才贍榮登早，心休進取廉。", "典刑今已矣，遐想淚空霑。"]'),
('a1e7fce9-3ea5-453e-b598-1f96cff5bbf6','挽知軍劉公三首  其二','陳棣','宋','宋诗','song-poetry','','[]','屢贊紅蓮幙，初分翠竹符。',48,'全唐诗/poet.song.114000.json','["屢贊紅蓮幙，初分翠竹符。", "五遷恩始浹，三已慍曾無。", "冠劍空幽壤，儀容儼畫圖。", "傳家有餘慶，接武看諸孤。"]'),
('21337fc5-d8d4-4288-9c9d-067424cee9fd','挽知軍劉公三首  其三','陳棣','宋','宋诗','song-poetry','','[]','昔我先君子，期公泰茹連。',48,'全唐诗/poet.song.114000.json','["昔我先君子，期公泰茹連。", "索文姑作贄，拂袖遽言旋。", "偉節人難學，高風史逸傳。", "邕碑誰秉筆，願採入新篇。"]'),
('c25e77a5-1dd9-44c0-9ccf-2b2ba98001bc','挽潘右司二首  其一','陳棣','宋','宋诗','song-poetry','','[]','南州推望士，北闕仰良臣。',48,'全唐诗/poet.song.114000.json','["南州推望士，北闕仰良臣。", "風誼高閭里，聲名藹搢紳。", "課兒千卷古，與友一堂新。", "石折符幽讖，山頹喪哲人。"]'),
('c80917a8-21dc-4652-a00b-0cf5eb4c4817','挽潘右司二首  其二','陳棣','宋','宋诗','song-poetry','','[]','再奉祠宮逸，三遷省闥榮。',48,'全唐诗/poet.song.114000.json','["再奉祠宮逸，三遷省闥榮。", "摳衣遲從橐，回首遇佳城。", "鵰鶚摶方急，龍蛇夢忽驚。", "但餘豐碣在，凜凜氣猶生。"]'),
('086b2f65-d4fb-4336-bb5f-6a2b4a8faa2b','挽中書舍人葉公三首  其一','陳棣','宋','宋诗','song-poetry','','[]','博學該羣籍，飛聲藹上庠。',48,'全唐诗/poet.song.114000.json','["博學該羣籍，飛聲藹上庠。", "巍科曾疊貫，要路遂橫翔。", "策府登清選，銓曹得望郎。", "九重方簡在，一鑑遽云亡。"]'),
('6a5d46ba-f59a-4915-907f-2d8573626c45','挽中書舍人葉公三首  其二','陳棣','宋','宋诗','song-poetry','','[]','遍歷清華地，星辰紀未周。',48,'全唐诗/poet.song.114000.json','["遍歷清華地，星辰紀未周。", "雄文藏鳳閣，直筆著螭頭。", "聞望高簪紱，論思動冕旒。", "從班無跬步，底事却回輈。"]'),
('1d16623a-558a-43ec-901f-b40445fc6431','挽中書舍人葉公三首  其三','陳棣','宋','宋诗','song-poetry','','[]','久厭承明直，遐宣使驛風。',48,'全唐诗/poet.song.114000.json','["久厭承明直，遐宣使驛風。", "乘軺循浙右，持斧肅江東。", "共徯鋒車召，俄驚夜壑空。", "傳家宜令子，濟物有陰功。"]'),
('cd04ce11-4201-4f3e-a576-66ab1007d7a4','挽知錄李元老二首  其一','陳棣','宋','宋诗','song-poetry','','[]','德齒追前輩，聲華擅雋遊。',48,'全唐诗/poet.song.114000.json','["德齒追前輩，聲華擅雋遊。", "心期師孔孟，文欲比曹劉。", "丹桂枝高折，青雲路未周。", "日駒偷過隙，夜壑漫藏舟。"]'),
('de85d5ce-ac6d-41b1-9c9c-a45b38c82f53','挽知錄李元老二首  其二','陳棣','宋','宋诗','song-poetry','','[]','枳棘棲雲翼，芙蓉泛綠波。',48,'全唐诗/poet.song.114000.json','["枳棘棲雲翼，芙蓉泛綠波。", "談玄三語足，折獄片言多。", "未熟黄粱夢，俄悲薤露歌。", "陰功付諸子，異日踵巍科。"]'),
('38233431-047f-4f2c-a623-1570cdc9b0cf','挽主簿吳寧侯三首  其一','陳棣','宋','宋诗','song-poetry','','[]','德行追前輩，聲華擅一鄉。',48,'全唐诗/poet.song.114000.json','["德行追前輩，聲華擅一鄉。", "遊心終藝圃，得雋屢文場。", "小試棲鸞政，連飛薦鶚章。", "傷嗟臺閣地，不許暫翺翔。"]'),
('82fa236c-e9f1-426f-8fd2-1649ad99cf72','挽主簿吳寧侯三首  其二','陳棣','宋','宋诗','song-poetry','','[]','昔我先君子，時稱鑒裁公。',48,'全唐诗/poet.song.114000.json','["昔我先君子，時稱鑒裁公。", "知君非介紹，虛館授兒童。", "倒屣迎王粲，登門得孔融。", "他年記先友，孰不仰清風。"]'),
('bbb7af02-8d16-431c-905c-54c9db902d14','挽主簿吳寧侯三首  其三','陳棣','宋','宋诗','song-poetry','','[]','憶昔荆湖日，童心懵未開。',48,'全唐诗/poet.song.114000.json','["憶昔荆湖日，童心懵未開。", "七年勤仰止，一字有從來。", "模範瞻如在，音儀挽不回。", "依歸今已矣，些語寫餘哀。"]'),
('483a2aba-aa5e-4667-8496-6221cbcbb7cc','挽內兄余聘可三首  其一','陳棣','宋','宋诗','song-poetry','','[]','中外六兄弟，相逢丱角中。',48,'全唐诗/poet.song.114000.json','["中外六兄弟，相逢丱角中。", "追隨萬里遠，憂樂半生同。", "勝韻談飛屑，高懷氣吐虹。", "紛紛身外事，回首萬緣空。"]'),
('54ec48e3-9628-49ab-a0da-9ea6af2ea31b','挽內兄余聘可三首  其二','陳棣','宋','宋诗','song-poetry','','[]','結髮事鉛槧，終身尺寸功。',48,'全唐诗/poet.song.114000.json','["結髮事鉛槧，終身尺寸功。", "矯情多病後，飲恨不言中。", "戶有三珠秀，家愁五盜窮。", "空山埋玉樹，腸斷白楊風。"]'),
('231dc405-4d70-4429-9060-5a21937a7da2','挽內兄余聘可三首  其三','陳棣','宋','宋诗','song-poetry','','[]','去去松塋路，愁聞薤露詩。',48,'全唐诗/poet.song.114000.json','["去去松塋路，愁聞薤露詩。", "齊眉乖婦約，華髮重親悲。", "被酒清狂後，論文慷慨時。", "傷心棲止地，無復見形儀。"]'),
('36e4a573-3959-4941-80aa-98c82b0864df','挽江公三首  其一','陳棣','宋','宋诗','song-poetry','','[]','彩筆傳家學，春華飾妙詞。',48,'全唐诗/poet.song.114000.json','["彩筆傳家學，春華飾妙詞。", "品題風鑑遠，論議月評推。", "柳岸陰將合，濠亭迹半隳。", "治家有遺訓，留付寧馨兒。"]'),
('c4e6bda5-27df-4f56-8641-b3892cdb5266','挽江公三首  其二','陳棣','宋','宋诗','song-poetry','','[]','世路方巇險，高情與衆殊。',48,'全唐诗/poet.song.114000.json','["世路方巇險，高情與衆殊。", "一官聊戲劇，三徑肯荒蕪。", "富樂身蒹有，功名累獨無。", "豐碑誰秉筆，持此較賢愚。"]'),
('fe071740-8f40-49dc-9542-ec87397642e1','挽江公三首  其三','陳棣','宋','宋诗','song-poetry','','[]','憶昔羈棲日，唯公迹分親。',48,'全唐诗/poet.song.114000.json','["憶昔羈棲日，唯公迹分親。", "呼盧銀燭夜，琢句錦囊春。", "碁敵爭先勁，弓號命中頻。", "向來行樂地，無復見斯人。"]'),
('7aa903ed-0d84-46a5-b162-086539492987','挽處士富公二首  其一','陳棣','宋','宋诗','song-poetry','','[]','慶曆元臣後，勳名泰華高。',48,'全唐诗/poet.song.114000.json','["慶曆元臣後，勳名泰華高。", "當年遺德澤，流裔盡英豪。", "繼世誇榮耀，唯公隠寂寥。", "潛輝傳野史，猶足見清標。"]'),
('906aa038-833e-44f0-b580-0f7dae17f673','挽處士富公二首  其二','陳棣','宋','宋诗','song-poetry','','[]','家富倉箱積，陶朱伯仲間。',48,'全唐诗/poet.song.114000.json','["家富倉箱積，陶朱伯仲間。", "禔身郭有道，教子竇燕山。", "錢鏄周貧匱，刀圭起病孱。", "懸知公不死，學道透玄關。"]'),
('12c4bbc9-4733-4c0b-905d-e89329295c33','挽處士吳德載二首  其一','陳棣','宋','宋诗','song-poetry','','[]','憶昔知公日，東嘉逆旅中。',48,'全唐诗/poet.song.114000.json','["憶昔知公日，東嘉逆旅中。", "遊從三月久，談笑一樽同。", "却暑瓜盤綠，烹鮮鱠筯紅。", "傷心棲止地，萬事轉頭空。"]'),
('28b1c225-e46a-4116-92cb-70dd2e49e842','挽處士吳德載二首  其二','陳棣','宋','宋诗','song-poetry','','[]','范蠡操贏日，相如病渴時。',48,'全唐诗/poet.song.114000.json','["范蠡操贏日，相如病渴時。", "瓶罌雖屢罄，砭劑已難施。", "薤露鴒原慘，松塋鴈序悲。", "更嗟垂白叟，泣送寧馨兒。"]'),
('83a3e1f8-5e6f-417b-921f-5ebbc83abfec','挽潘夫人','陳棣','宋','宋诗','song-poetry','','[]','閬苑花歸後，香殘舊綺羅。',48,'全唐诗/poet.song.114000.json','["閬苑花歸後，香殘舊綺羅。", "已應隨逝水，無復步凌波。", "遺訓芬蘭佩，慈容想月娥。", "空山埋玉處，忍效鼓盆歌。"]'),
('d6028488-d2d5-4bcb-81f8-1d609f26f1a4','送鄭舜舉赴闕  其一','陳棣','宋','宋诗','song-poetry','','[]','書带傳家飽六經，飄飄詞氣海東青。',64,'全唐诗/poet.song.114000.json','["書带傳家飽六經，飄飄詞氣海東青。", "英名久合班朝列，麗藻行觀掞帝庭。", "修翮摶風上閶闔，巨鱗縱壑擊滄溟。", "投機亨會寧容髮，願報除書慰側聆。"]'),
('49b56ea3-aaf7-4305-8b45-8b9c134f6291','送鄭舜舉赴闕  其二','陳棣','宋','宋诗','song-poetry','','[]','束裝西嘯指長安，正是新春快活天。',64,'全唐诗/poet.song.114000.json','["束裝西嘯指長安，正是新春快活天。", "酒病詩愁應有夢，鳥啼花發正爭妍。", "君空冀北今行矣，我滯周南豈偶然。", "東閤他時訪遺逸，爲言憔悴鶴谿邊。"]'),
('2bebabd0-0a02-448a-a261-cbde122c2704','送鄭舜舉赴闕  其三','陳棣','宋','宋诗','song-poetry','','[]','籍甚聲名著日邊，英辭健筆許誰先。',64,'全唐诗/poet.song.114000.json','["籍甚聲名著日邊，英辭健筆許誰先。", "置之華省星曹上，付以赤墀香案前。", "好向從班光玉筍，竚膺蜜炬照金蓮。", "此行何啻登仙去，願拜車塵爲執鞭。"]'),
('c8660723-093b-4efc-afe2-562b7b68a64b','送鄭舜舉赴闕  其四','陳棣','宋','宋诗','song-poetry','','[]','暫綰桐川刺史章，優優布政漢循良。',64,'全唐诗/poet.song.114000.json','["暫綰桐川刺史章，優優布政漢循良。", "鳳銜初下新頒詔，鷄舌曾聞舊賜香。", "前席久虛思見賈，璽書增寵果徵黄。", "從今定展調元手，小試專城見雨暘。"]'),
('e849a08b-37f9-4dd7-bfd2-eb620d986520','送鄭舜舉赴闕  其五','陳棣','宋','宋诗','song-poetry','','[]','備員無補見絲毫，幸喜爲官似馬曹。',64,'全唐诗/poet.song.114000.json','["備員無補見絲毫，幸喜爲官似馬曹。", "每許蕪音持布鼓，更容劣技試鉛刀。", "兼收屢賜百金諾，借重終期一字褒。", "廊廟他時應有待，誓將么麽寄鈞陶。"]'),
('b666be5a-bead-4e1a-99d9-92f4641daa27','春來','陳棣','宋','宋诗','song-poetry','','[]','春來底物最先知，凍蝶癡蜂便欲飛。',64,'全唐诗/poet.song.114000.json','["春來底物最先知，凍蝶癡蜂便欲飛。", "好雨應時生地脈，迅雷剖蟄震天威。", "光風艷艷翔空闊，和氣駸駸發細微。", "解道蒼苔紅藥句，令人却憶謝玄暉。"]'),
('6ea1a2a1-f414-4d1d-88bb-cb8f50168c61','次韻王有之主簿  其一','陳棣','宋','宋诗','song-poetry','','[]','春歸滿目盡桑麻，岸柳敷陰荻有芽。',64,'全唐诗/poet.song.114000.json','["春歸滿目盡桑麻，岸柳敷陰荻有芽。", "急景豈容留石火，餘香何處認空花。", "曲眉持酒真成夢，纖手分茶亦浪誇。", "欲醉流霞烹瑞雪，直須同謁五侯家。"]'),
('f9b30564-6124-47a7-b78a-1911a4985ed6','次韻王有之主簿  其二','陳棣','宋','宋诗','song-poetry','','[]','蓬生敢望直如麻，才思真同焦穀芽。',64,'全唐诗/poet.song.114000.json','["蓬生敢望直如麻，才思真同焦穀芽。", "擁被苦吟聲躑躅，盈編細札眼空花。", "羨君得意方豪縱，顧我無知絕誕誇。", "輸與能詩王主簿，驚人句法自名家。"]'),
('dbf4f36d-34e1-44da-a725-adcd3c790a52','次韻葉秀實縣治環翠亭  其一','陳棣','宋','宋诗','song-poetry','','[]','亭高望遠破天慳，萬疊晴嵐俯仰間。',64,'全唐诗/poet.song.114000.json','["亭高望遠破天慳，萬疊晴嵐俯仰間。", "着屐好追靈運逸，垂簾尤愛愷之閒。", "詩豪會見揮銀筆，酒聖端能倒玉山。", "杖履欲歸聊徙倚，棲鴉寒带暝烟還。"]'),
('f0eeaa7f-1453-469e-b53c-324730f1f421','次韻葉秀實縣治環翠亭  其二','陳棣','宋','宋诗','song-poetry','','[]','合綴嚴宸玉筍班，尚勞小試簿書間。',64,'全唐诗/poet.song.114000.json','["合綴嚴宸玉筍班，尚勞小試簿書間。", "溟鯤未擊三千里，天驥終歸十二閑。", "望氣行看求利劍，知音當已識高山。", "逼人富貴君寧免，未許山陰興盡還。"]'),
('f757d556-4396-4740-a3f2-74fab7e21874','次韻葉秀實縣治環翠亭  其三','陳棣','宋','宋诗','song-poetry','','[]','畏途蹤跡幾間關，浩氣空存天地間。',64,'全唐诗/poet.song.114000.json','["畏途蹤跡幾間關，浩氣空存天地間。", "沈湎恨無千日醉，浪遊贏得半生閒。", "觀書尚喜眼如月，搜句誰憐肩聳山。", "三徑曉來添逸興，柳梢桃色報春還。"]'),
('1feecae6-2530-4a42-8bd5-3cf36a1deaac','陪五馬勸農巗山晚會桃花塢','陳棣','宋','宋诗','song-poetry','','[]','晚參旌騎勸農回，賞遍郊原錦繡堆。',64,'全唐诗/poet.song.114000.json','["晚參旌騎勸農回，賞遍郊原錦繡堆。", "掠面快風吹酒去，逼人踈雨送詩來。", "鳴鳩乳燕數聲好，艷粉夭桃一笑開。", "欲遣巴詞侑盃酌，千鍾萬斝未容陪。"]'),
('b9e9f1c7-c72b-4590-950b-d427047e74c4','題溫守梁尚書新創富覽亭','陳棣','宋','宋诗','song-poetry','','[]','傑檻雄簷倚碧空，玲瓏窗戶濕青紅。',64,'全唐诗/poet.song.114000.json','["傑檻雄簷倚碧空，玲瓏窗戶濕青紅。", "因山卜地心機巧，望水如天眼力窮。", "千里勝形吟筆內，萬家和氣飲杯中。", "吏民共指雙旌語，今日梁公昔謝公。"]'),
('f5c9f29c-ae36-47fa-8a10-c4c8773e2ead','次韻陳公藻局中即事時推排物力不得往來','陳棣','宋','宋诗','song-poetry','','[]','料峭輕寒春寂寥，雨餘庭竹靜蕭蕭。',64,'全唐诗/poet.song.115000.json','["料峭輕寒春寂寥，雨餘庭竹靜蕭蕭。", "一池芳草翠欲合，數點殘梅雪未消。", "寸步思君成瘦悴，片文怡我足歡謠。", "相過政恐還驚座，惡客從來不待招。"]'),
('17e73be9-7c48-40f3-805d-84f1baa04456','次韻幾道玉泉小集時公藻以病僕以沿檄不與','陳棣','宋','宋诗','song-poetry','','[]','激水聊充一笑嬉，扁舟西子想當時。',64,'全唐诗/poet.song.115000.json','["激水聊充一笑嬉，扁舟西子想當時。", "應憐波底無雙鯉，直恐樽前有鸒斯。", "笑我獨將愁醖釀，聞君長苦酒禁持。", "山中異日尋遺事，徒見吾家伯仲詩。"]'),
('e7fd7a84-82f6-4899-a284-9767ad828a0f','諸公見和次韻呈鄭舜舉國錄瑞伯仙尉  其一','陳棣','宋','宋诗','song-poetry','','[]','冠佩追隨倏半生，每憐蕭艾倚蘭英。',64,'全唐诗/poet.song.115000.json','["冠佩追隨倏半生，每憐蕭艾倚蘭英。", "開懷共醉酒賢聖，得句寧論詩父兄。", "天賦君才行有用，人言我拙坐無成。", "登壇已拜風騷將，誰敢區區踵孟明。"]'),
('51d4fe8d-5ef7-4459-b99a-81dc914ba112','諸公見和次韻呈鄭舜舉國錄瑞伯仙尉  其二','陳棣','宋','宋诗','song-poetry','','[]','家聲赫奕繼更生，草聖縱橫亂伯英。',64,'全唐诗/poet.song.115000.json','["家聲赫奕繼更生，草聖縱橫亂伯英。", "鄴下文章惟七子，潁川人士有諸兄。", "新詩寫物無餘態，硬語盤空若混成。", "吏隠一官聊戲劇，他時勳業看承明。"]'),
('a86b9432-d844-49b6-a2aa-d05f240f2c24','用韻戲趙貫道買妾并呈鄭舜舉王有之二丈','陳棣','宋','宋诗','song-poetry','','[]','碧玉雙簪兩髻丫，滿懷春恨正萌芽。',64,'全唐诗/poet.song.115000.json','["碧玉雙簪兩髻丫，滿懷春恨正萌芽。", "停橈空對無情水，倚檻誰鄰解語花。", "蚤與幽閨深領畧，毋令狂客浪矜誇。", "須知三昧非凡手，北苑知名第一家。"]'),
('ec0b6958-c632-457b-b0ef-88280117eed3','次韻魯堯卿病起  其一','陳棣','宋','宋诗','song-poetry','','[]','河陽桃李未成陰，已覺栽培用意深。',64,'全唐诗/poet.song.115000.json','["河陽桃李未成陰，已覺栽培用意深。", "病起暫同中酒味，詩來還有惜花心。", "養全浩氣虹千丈，瘦減清標玉一尋。", "春待吾儕共行樂，莫言無暇倦登臨。"]'),
('1d40a8f7-261c-4667-9c47-caf9d95f264e','次韻魯堯卿病起  其二','陳棣','宋','宋诗','song-poetry','','[]','一區聊寄古牆陰，燈火蕭條語夜深。',64,'全唐诗/poet.song.115000.json','["一區聊寄古牆陰，燈火蕭條語夜深。", "强對簡編聊適意，欲參佛祖問安心。", "青衫有約還輕別，白髮無期苦見尋。", "咫尺佳時修禊事，蘭亭老筆爲君臨。"]'),
('60fbcf4a-60c0-4f40-8893-97f341755307','代上時相生辰  其一','陳棣','宋','宋诗','song-poetry','','[]','國論盈庭正尚同，唯公英畧與天通。',64,'全唐诗/poet.song.115000.json','["國論盈庭正尚同，唯公英畧與天通。", "一絲不斷千鈞重，九鼎重安萬世功。", "獨見夐超流俗外，先機端在笑談中。", "際高極厚知難報，願輔熙朝到不窮。"]'),
('824fc780-550c-49fc-9797-bb4927ed4293','代上時相生辰  其二','陳棣','宋','宋诗','song-poetry','','[]','中興事業耀無前，明聖相逢運半千。',64,'全唐诗/poet.song.115000.json','["中興事業耀無前，明聖相逢運半千。", "盡納有生歸禮樂，全提鴻化入陶甄。", "八風自轉成天籟，五緯更調祚有年。", "體物形容勞頌筆，浪云無象豈其然。"]'),
('57e9aa31-a617-4ea9-9574-e6e2d68a3dee','代上時相生辰  其三','陳棣','宋','宋诗','song-poetry','','[]','春光先向隴梅歸，正值崧神降嶽時。',64,'全唐诗/poet.song.115000.json','["春光先向隴梅歸，正值崧神降嶽時。", "孕秀直疑天地相，輸忠唯許冕旒知。", "八珍錫燕宮厨送，百兩傳宣使驛馳。", "盛事逖聞千載後，魯公綵服效兒嬉。"]'),
('675ec05e-fd65-450f-8068-ce9808e462e0','代上時相生辰  其四','陳棣','宋','宋诗','song-poetry','','[]','武定文明過十秋，光芒無復見旄頭。',64,'全唐诗/poet.song.115000.json','["武定文明過十秋，光芒無復見旄頭。", "身更萬變心方壯，位極千官寵更優。", "賀厦阻趨丞相閤，分符假守子陵州。", "長生不老何須祝，元是丹臺第一流。"]'),
('2f3be04c-3078-4d22-8b50-eccbf8bc9a51','錢使君知原生辰  其一','陳棣','宋','宋诗','song-poetry','','[]','天眷中興瑞玉麟，果聞崧嶽爲生申。',64,'全唐诗/poet.song.115000.json','["天眷中興瑞玉麟，果聞崧嶽爲生申。", "逢迎聖主千年運，領畧東君五日春。", "濟世豐功銘鼎鼐，傳家清德冠簪紳。", "仙風道骨應難老，曾向瑶宮侍帝宸。"]'),
('c25301b3-1512-42b2-a7a7-bd9ff9275a3d','錢使君知原生辰  其二','陳棣','宋','宋诗','song-poetry','','[]','十載幽居安綠野，一麾出守擁朱轓。',64,'全唐诗/poet.song.115000.json','["十載幽居安綠野，一麾出守擁朱轓。", "華堂不聽紅兒唱，凈几唯聞黄嬭言。", "庭下芝蘭方鼎盛，胸中梨棗已長存。", "梅花欲報和羹信，故遣清香到壽樽。"]'),
('213750ee-5811-442f-acc3-581f62e333c0','上梁尚書生辰  其一','陳棣','宋','宋诗','song-poetry','','[]','破曉霜晴快活天，少微光彩煥臺躔。',64,'全唐诗/poet.song.115000.json','["破曉霜晴快活天，少微光彩煥臺躔。", "來從紫府飛仙窟，生作皇家間世賢。", "勳業定應銘鼎鼐，儀容端合珥貂蟬。", "外家舊事今重覩，又致昇平五百年。"]'),
('dfb7111f-4f0f-423a-9eb9-cad3c5832c5e','上梁尚書生辰  其二','陳棣','宋','宋诗','song-poetry','','[]','一麾卧治鎮江邊，芳草還應夢惠連。',64,'全唐诗/poet.song.115000.json','["一麾卧治鎮江邊，芳草還應夢惠連。", "十載從班聯玉笋，六城課最用蒲鞭。", "依劉曾識尚書履，借寇難私刺史天。", "共徯公歸緣底事，嗷嗷四海望陶甄。"]'),
('6c65f75d-f2c5-4af1-9af3-ffad8b96bc60','上梁尚書生辰  其三','陳棣','宋','宋诗','song-poetry','','[]','上苑春光一夜回，和羹消息報江梅。',64,'全唐诗/poet.song.115000.json','["上苑春光一夜回，和羹消息報江梅。", "促裝舊事追曹相，折桂新榮付老萊。", "千里頌聲形鼓吹，萬家和氣入樽罍。", "明年此日趨黄閣，待看傳宣押賜來。"]'),
('e28bf4a3-1897-43ee-8800-4f9db4c8ea91','陳鎮江生辰  其一','陳棣','宋','宋诗','song-poetry','','[]','協氣盤空兆吉祥，挺生英傑輔明昌。',64,'全唐诗/poet.song.115000.json','["協氣盤空兆吉祥，挺生英傑輔明昌。", "依乘聖際風雲久，遊戲人間日月長。", "落落詞華天黼黻，堂堂儀榘國輝光。", "煙橈破浪來何事，敬爲宗盟一瓣香。"]'),
('a3747cb2-ee5a-419d-92e8-7482056e6e3f','陳鎮江生辰  其二','陳棣','宋','宋诗','song-poetry','','[]','力致功名上要途，忠嘉屢奉玉音俞。',64,'全唐诗/poet.song.115000.json','["力致功名上要途，忠嘉屢奉玉音俞。", "持荷久侍甘泉橐，剖竹仍分刺史符。", "撫字雅聞閒燕寢，經綸先已定規模。", "久虛左轄寧無謂，天子疇庸正用儒。"]'),
('694b1df7-eb10-490e-929e-21282af59daf','陳鎮江生辰  其三','陳棣','宋','宋诗','song-poetry','','["\u957f\u6c5f"]','着物薰然一氣和，溫溫眉宇得春多。',64,'全唐诗/poet.song.115000.json','["着物薰然一氣和，溫溫眉宇得春多。", "腰黄眼赤渾閒事，柳綠花紅奈樂何。", "舊事幾經銅狄話，佳詞慣聽雪兒歌。", "一杯何以爲公壽，願借長江萬里波。"]'),
('9c239cb9-2651-4263-b4bc-efed425dd140','立春日有感','陳棣','宋','宋诗','song-poetry','','[]','剪綵漫添懷抱惡，簪花空映鬢毛秋。',64,'全唐诗/poet.song.115000.json','["剪綵漫添懷抱惡，簪花空映鬢毛秋。", "流年舊事陳芻狗，佳節新春報土牛。", "里社浮沉貧可忍，身名坎壈老宜休。", "天高難問平生意，已矣冥心任去留。"]'),
('560eeeda-b4ee-4b3c-9958-9455521b3fae','王有之見和復用韻二首  其一','陳棣','宋','宋诗','song-poetry','','[]','年來慵墮畏多愁，怕見羣才得意秋。',64,'全唐诗/poet.song.115000.json','["年來慵墮畏多愁，怕見羣才得意秋。", "題柱敢期乘駟馬，隠鄽端欲舍蝸牛。", "既成春服聊歌詠，擬賦閒情且罷休。", "漫道無心關節物，杖藜時爲好山留。"]'),
('4dc13b23-a322-4edd-b023-5d04591ae970','王有之見和復用韻二首  其二','陳棣','宋','宋诗','song-poetry','','[]','小雨冥冥暗市樓，無聊一日似三秋。',64,'全唐诗/poet.song.115000.json','["小雨冥冥暗市樓，無聊一日似三秋。", "窮愁顧我堆千斛，健筆期君回萬牛。", "語怪未應書咄咄，身閒底用賦休休。", "曉來春到西窗外，喚夢一聲黄栗留。"]'),
('aaf6e6e0-2b00-43d7-95aa-1d414bec9efd','高師魯以詩求鶴膝杖且有詩壇尋盟之語戲次其韻  其一','陳棣','宋','宋诗','song-poetry','','[]','莫將好語趁時名，寶唾聯篇得我驚。',64,'全唐诗/poet.song.115000.json','["莫將好語趁時名，寶唾聯篇得我驚。", "酬唱蜂腰徒自苦，棄捐鶴膝太無情。", "故人何止十年別，上座曾同千里行。", "散策尋幽江上路，何時歸踐白鷗盟。"]'),
('b2b9ee12-c34d-4c52-b159-a02dd96fc063','高師魯以詩求鶴膝杖且有詩壇尋盟之語戲次其韻  其二','陳棣','宋','宋诗','song-poetry','','[]','榮枯寵辱盡强名，老去無堪只自驚。',64,'全唐诗/poet.song.115000.json','["榮枯寵辱盡强名，老去無堪只自驚。", "尤物端能亂人意，粗官安得有詩情。", "暫憑竹杖聊相謔，敢對金樽畧放行。", "果向詩壇尋舊約，心如江水不須盟。"]'),
('67351ee6-43a8-4651-b05d-7954a4b5fe09','客舍春晚','陳棣','宋','宋诗','song-poetry','','[]','晼晚春歸婺女城，輕陰淺綠繞長亭。',64,'全唐诗/poet.song.115000.json','["晼晚春歸婺女城，輕陰淺綠繞長亭。", "禽聲勸客年年恨，草色隨人處處青。", "爲米未容陶令去，餔糟敢笑屈原醒。", "詩成錯莫渾無事，滿院楊花晝掩扃。"]'),
('bcf06351-c93a-4eac-91a8-f849c04ba7cb','又次韻馮文度春晚二首  其一','陳棣','宋','宋诗','song-poetry','','[]','花梢踈雨下巫陽，酒面新鵝拂嫩黄。',64,'全唐诗/poet.song.115000.json','["花梢踈雨下巫陽，酒面新鵝拂嫩黄。", "老去光陰春苦短，閒中氣味日偏長。", "方塘水滿丙鱗躍，故壘泥空乙羽忙。", "剩作篇章酬節物，忍令相背去堂堂。"]'),
('093b732a-11b7-4acf-b9c3-ee6b80c79f11','又次韻馮文度春晚二首  其二','陳棣','宋','宋诗','song-poetry','','[]','春到窮簷分外和，典衣日日飲無何。',64,'全唐诗/poet.song.115000.json','["春到窮簷分外和，典衣日日飲無何。", "未陪蠟屐尋幽樂，已覺詩囊得句多。", "頗喜醉鄉無畔岸，從教平地有風波。", "脫巾露頂君休問，倦客塵冠底用峨。"]'),
('a08e4f5c-4e53-4789-911f-966addc38ad0','題義烏縣繡川驛','陳棣','宋','宋诗','song-poetry','','[]','湖漾晴波萬疊秋，山攢遠翠兩眉愁。',64,'全唐诗/poet.song.115000.json','["湖漾晴波萬疊秋，山攢遠翠兩眉愁。", "一川暝色烟欹柳，千里寒光月滿洲。", "直恐斷堤橫北固，定知絕景冠東州。", "塵纓欲濯滄浪水，愧見沙頭雙白鷗。"]'),
('7851b9b6-b2ab-4eb4-bb22-5a851146e84c','再過繡川驛','陳棣','宋','宋诗','song-poetry','','[]','霜林病葉日凋殘，更覺平蕪眼界寬。',64,'全唐诗/poet.song.115000.json','["霜林病葉日凋殘，更覺平蕪眼界寬。", "天外碧雲山共遠，階前明月水爭寒。", "愔愔夜氣侵肌骨，戢戢詩愁入肺肝。", "欲去自憐心未愜，爲君滿意更重看。"]'),
('e7bed47d-d6b3-4cff-9a38-6d0a94dec749','永嘉旅中','陳棣','宋','宋诗','song-poetry','','[]','小雨凄風釀早寒，行厨蕭索酒壺乾。',64,'全唐诗/poet.song.115000.json','["小雨凄風釀早寒，行厨蕭索酒壺乾。", "抄書時自囁嚅語，把菊誰同仔細看。", "收拾夢魂歸枕上，掃除愁思寄毫端。", "家山只在一帆外，望隔烟巒漫倚欄。"]'),
('bc801732-ffe8-431d-8f38-b363dbce8be2','盛暑宿集福院晚風雨大作','陳棣','宋','宋诗','song-poetry','','[]','火雲燒天天爲高，畏日爍地地欲焦。',64,'全唐诗/poet.song.115000.json','["火雲燒天天爲高，畏日爍地地欲焦。", "舴艋浮江線溜澁，招提稅鞅煩襟消。", "風聲聒聒閙山闕，雨脚霏霏轉樹腰。", "猛省奔馳竟何事，此心寧不愧漁樵。"]'),
('db14a7b1-5f83-4d6d-9847-662eb8f3b64d','甲子歲除一夕夢與先子論詩有云未能免俗猶聽讖無計爲生只送窮此吾頃年詩也汝亦得之否某曰已在家集中既覺泣書二章  其一','陳棣','宋','宋诗','song-poetry','','[]','驚風急雪不勝寒，葦索桃符歲事殘。',64,'全唐诗/poet.song.115000.json','["驚風急雪不勝寒，葦索桃符歲事殘。", "里巷杯盤喧半夜，兒童燈火守更闌。", "年催老色歸鬚鬢，詩引窮愁入肺肝。", "無復斑衣頌椒栢，只將淚血灑毫端。"]'),
('27bfcf52-d187-4d47-8377-c8f5301ae64f','甲子歲除一夕夢與先子論詩有云未能免俗猶聽讖無計爲生只送窮此吾頃年詩也汝亦得之否某曰已在家集中既覺泣書二章  其二','陳棣','宋','宋诗','song-poetry','','[]','昔年浩氣許誰攀，詩禮趨庭侍燕閒。',64,'全唐诗/poet.song.115000.json','["昔年浩氣許誰攀，詩禮趨庭侍燕閒。", "但喜新陽更舊律，豈知斑鬢改朱顔。", "時挑短燼傾蕉葉，獨擁寒燼炷博山。", "不見詩翁送窮處，空留膏馥在人間。"]'),
('6c4ffe9e-e86d-4281-947e-112942bdf17f','再次韻  其一','陳棣','宋','宋诗','song-poetry','','[]','畏途憂患飽相諳，火芋何當問懶殘。',64,'全唐诗/poet.song.115000.json','["畏途憂患飽相諳，火芋何當問懶殘。", "每覺愁來詩思苦，更因老去壯心闌。", "年光背我捐鷄肋，世事甜人嗜馬肝。", "撥盡寒爐殘漏永，已知春馭到林端。"]'),
('e0f0b7e2-6a64-47c7-b1de-49092471c761','再次韻  其二','陳棣','宋','宋诗','song-poetry','','[]','擾擾膠膠度歲年，只應今夕暫休閒。',64,'全唐诗/poet.song.115000.json','["擾擾膠膠度歲年，只應今夕暫休閒。", "又聞玉燭更新籥，那得金丹駐舊顔。", "是處碧烟聞爆竹，誰家紅玉擁頹山。", "揮毫不作驚人語，句法由來似夢間。"]'),
('229e8df6-b448-479f-875c-e2b09200fa6c','庚申日戲題','陳棣','宋','宋诗','song-poetry','','[]','多情節物苦撩人，用事葩華巧鬭新。',64,'全唐诗/poet.song.115000.json','["多情節物苦撩人，用事葩華巧鬭新。", "老去唯愁添甲子，年來不獨畏庚申。", "身閒淡淡心機靜，夢好齁齁鼻息勻。", "政使三彭肆簧舌，冰壺貯月本無塵。"]'),
('c4c0ee3e-db80-4e4a-973b-53b4709c6d4d','次韻李元老柬王令周簿喜雨  其一','陳棣','宋','宋诗','song-poetry','','[]','阿香破旱用功深，更遣新凉入素襟。',64,'全唐诗/poet.song.115000.json','["阿香破旱用功深，更遣新凉入素襟。", "曝日已通賢令意，望霓聊慰野人心。", "水添淺瀨征帆穩，雲掩殘陽古樹陰。", "洗眼看君調燮手，一同先已荷商霖。"]'),
('662cbe46-d80d-4184-a326-c4a95296b3a2','次韻李元老柬王令周簿喜雨  其二','陳棣','宋','宋诗','song-poetry','','[]','山色雲容潑墨深，隨車甘澍濕衣襟。',64,'全唐诗/poet.song.115000.json','["山色雲容潑墨深，隨車甘澍濕衣襟。", "神龍應禱方施力，虐魃爲殃漫有心。", "洗出篔簹無滯暑，養成䆉稏有餘陰。", "他年德政君須記，能遣驕陽化作霖。"]'),
('dd06cf40-d872-4b18-b9b6-687d32e4d959','次韻馬仲元推官賀五馬喜雨','陳棣','宋','宋诗','song-poetry','','[]','甘澍隨車未足賢，商霖小試漲晴川。',64,'全唐诗/poet.song.115000.json','["甘澍隨車未足賢，商霖小試漲晴川。", "溶溶舊綠低蟬柳，聒聒新流響露田。", "刈熟腰鐮爭滿載，叩門乞粟不論錢。", "老農豈但歌襦袴，盡道今年勝去年。"]'),
('f000bf06-0791-4cdc-b1a8-6cc2ab4ca2ce','次韻喜雨兼簡彝老','陳棣','宋','宋诗','song-poetry','','[]','此身閲世一浮漚，無地安巢拙勝鳩。',64,'全唐诗/poet.song.115000.json','["此身閲世一浮漚，無地安巢拙勝鳩。", "擊節聞君歌喜雨，裹糧知我迫填溝。", "凉宵自足莊生夢，豐歲仍寬子美憂。", "遥想高人禪寂處，娟娟窗竹不勝幽。"]'),
('b50c275d-3ebe-40c8-bbca-972bcc41077d','次韻喜雨','陳棣','宋','宋诗','song-poetry','','[]','雨氣侵人襟袖凉，詩愁惱起沈東陽。',64,'全唐诗/poet.song.115000.json','["雨氣侵人襟袖凉，詩愁惱起沈東陽。", "詰朝秧馬催田畯，昨夜雷車動阿香。", "鳩婦豈知憂旱去，商羊聊亦爲時忙。", "芙蓉秋水須佳句，妙意宜搜到渺茫。"]'),
('110752b0-9d6d-4d7e-80b2-092ab170f545','次韻陶幾道喜雨','陳棣','宋','宋诗','song-poetry','','[]','環珮來從十二峯，飛廉清道駕豐隆。',64,'全唐诗/poet.song.115000.json','["環珮來從十二峯，飛廉清道駕豐隆。", "已占月魄離星次，欲採民謠詠雨濛。", "健筆輸君三峽峻，新凉許我一樽同。", "豚蹄斗酒無多誚，神報邦人亦已豐。"]'),
('8ff54d31-8a25-4e11-9816-44a5f2cbc1e9','次韻陳季陵主簿秋雨','陳棣','宋','宋诗','song-poetry','','[]','一雨庭蕪便許凉，掃除旱魃化驕陽。',64,'全唐诗/poet.song.115000.json','["一雨庭蕪便許凉，掃除旱魃化驕陽。", "微添遠水羅襟潤，已覺踈苗玉粒香。", "樂歲可期寬吏責，謭才無取爲詩忙。", "蕭蕭枕簟偏宜睡，夢入華胥正渺茫。"]'),
('2eeda6b6-3a01-44d8-9313-a576609fbb44','客舍久雨無酒戲柬沈泰叔','陳棣','宋','宋诗','song-poetry','','[]','秋來濘淖幾曾乾，旅邸盤旋尋丈間。',64,'全唐诗/poet.song.115000.json','["秋來濘淖幾曾乾，旅邸盤旋尋丈間。", "擬仗神功擊陽石，却疑天漏類陰山。", "已甘從事經年別，未放管城終日閒。", "欲課新詩强消遣，客情無頼語還慳。"]'),
('2be09b47-1509-4cde-80d6-a0bc7c5a6812','次韻','陳棣','宋','宋诗','song-poetry','','[]','莫訝經旬笑語乾，誰令插手斗筲間。',64,'全唐诗/poet.song.115000.json','["莫訝經旬笑語乾，誰令插手斗筲間。", "長篇險語懷東野，俗狀塵容愧北山。", "車馬無堪泥淖滑，蛟龍不放水雲閒。", "翻思九夏無涓滴，天意何如向日慳。"]'),
('92de3776-704b-46f1-8ef4-69d0ff68f538','次韻陳季陵覓酒二首  其一','陳棣','宋','宋诗','song-poetry','','[]','西風曾未入梧楸，已有騷人怨凜秋。',64,'全唐诗/poet.song.115000.json','["西風曾未入梧楸，已有騷人怨凜秋。", "草賦未爲傖父語，破愁宜召麴生謀。", "君方負笈金陵去，我欲乘桴滄海浮。", "後夜月明應好在，一樽能爲輟行不。"]'),
('4a8cd4ff-7437-486f-834f-e340104979fa','次韻陳季陵覓酒二首  其二','陳棣','宋','宋诗','song-poetry','','[]','山遠誰憐眉黛愁，水明遥憶眼波秋。',64,'全唐诗/poet.song.115000.json','["山遠誰憐眉黛愁，水明遥憶眼波秋。", "久拋大白猶閒事，却對短檠真拙謀。", "楚佩紉香塵未暗，巫雲賦夢語多浮。", "扊扅政恐閨人怨，曾效當年擁髻不。"]'),
('462ba66c-1783-4e81-9399-05d4c3766b6f','次韻劉伯瑞覓酒','陳棣','宋','宋诗','song-poetry','','[]','貧病相仍坐拙方，敢將斗酒博西凉。',64,'全唐诗/poet.song.115000.json','["貧病相仍坐拙方，敢將斗酒博西凉。", "自憐里巷棲遲久，倍覺樽罍氣味長。", "玉斚交飛君有約，紅裙共醉我何嘗。", "一樽聊慰相如渴，要聽歌聲過女牆。"]'),
('95ec3ed2-555c-4ebb-a48c-5c2b9db9ec93','謝汪汝平送酒','陳棣','宋','宋诗','song-poetry','','[]','塵土侵陵老瓦盆，胸中磊塊與誰論。',64,'全唐诗/poet.song.115000.json','["塵土侵陵老瓦盆，胸中磊塊與誰論。", "閒披黄卷欲欹枕，忽有白衣來扣門。", "和氣醺人紅綠眩，濃香破鼻典刑存。", "倒罍徹底清如水，不比春江带雨渾。"]'),
('02830c50-5d9a-4560-8ed8-4e36a5eee9c5','汝平諸公見和復用韻二首  其一','陳棣','宋','宋诗','song-poetry','','[]','鵝黄快瀉映金盆，白墮湘酃豈並論。',64,'全唐诗/poet.song.115000.json','["鵝黄快瀉映金盆，白墮湘酃豈並論。", "酩酊不妨尋醉侶，鞠躬底事入公門。", "盃觴往往陪嘲謔，筆札時時荷記存。", "指日看君乘障去，好將韜畧靖羌渾。"]'),
('6f46c53f-ee2b-450e-a8bd-6aac48baf4b6','汝平諸公見和復用韻二首  其二','陳棣','宋','宋诗','song-poetry','','[]','新詩敏捷雨翻盆，樽酒何時與細論。',64,'全唐诗/poet.song.115000.json','["新詩敏捷雨翻盆，樽酒何時與細論。", "擬把鉛刀侔巨闕，却慙布鼓過雷門。", "天心月脅形容遍，春蚓秋蛇體勢存。", "但得唱酬爲老伴，此生道眼未容渾。"]'),
('c46a0fd9-aabf-468b-bf0c-26af2ee951ae','再用前韻三首  其一','陳棣','宋','宋诗','song-poetry','','[]','刺頭底事向膠盆，沉湎應從通率論。',64,'全唐诗/poet.song.115000.json','["刺頭底事向膠盆，沉湎應從通率論。", "人世百年都是夢，醉鄉四達總無門。", "顛狂自索形骸外，酣適寧知禮法存。", "日飲亡何真得計，袁絲由此脫全渾。"]'),
('597e243a-ee96-45dd-b4f2-f50e79175269','再用前韻三首  其二','陳棣','宋','宋诗','song-poetry','','[]','墮地何勞顧甑盆，事同電往不堪論。',64,'全唐诗/poet.song.115000.json','["墮地何勞顧甑盆，事同電往不堪論。", "歸休我願白駒谷，登用君宜金馬門。", "氣習肯隨流俗變，笑談如見古人存。", "詞源清徹如甘井，愈汲方知愈不渾。"]'),
('0685b371-f25a-4213-9ec9-e400ed1666fd','再用前韻三首  其三','陳棣','宋','宋诗','song-poetry','','[]','陶冶無心甕與盆，等閒妍窳意難論。',64,'全唐诗/poet.song.115000.json','["陶冶無心甕與盆，等閒妍窳意難論。", "年光未易留駒隙，世事唯堪隠鹿門。", "久客思家華髮滿，小儒憂國赤心存。", "江山還有新亭嘆，痛惜伊川化陸渾。"]'),
('f9bb6b29-20f1-400d-be83-afeda7fcff69','別墅芍藥盛開沈公闢有詩見嘲次韻代柬  其一','陳棣','宋','宋诗','song-poetry','','[]','誰爲東君得意忙，尚留紅藥殿羣芳。',64,'全唐诗/poet.song.115000.json','["誰爲東君得意忙，尚留紅藥殿羣芳。", "臉霞得酒生朝暈，衣翠籠紗弄晚粧。", "賸馥倚風來蝶翅，殘膏和露到蜂房。", "惜花極力搜佳句，瘦損東陽笑沈郎。"]'),
('df33ba17-2c6b-48e3-8221-ffa9bdcac9f6','別墅芍藥盛開沈公闢有詩見嘲次韻代柬  其二','陳棣','宋','宋诗','song-poetry','','[]','翰林憶昔詠孤芳，自合移根向玉堂。',64,'全唐诗/poet.song.115000.json','["翰林憶昔詠孤芳，自合移根向玉堂。", "貴客親陪天女手，侍臣應带御爐香。", "花前未許退之醉，江上空嗟子美狂。", "一夜殷紅飄落盡，不堪寂寞對霞觴。"]'),
('48bd0b8a-6ad3-4ccd-9b6f-d9694ed096c6','次韻艾慎機縣庠蕉花','陳棣','宋','宋诗','song-poetry','','[]','蕉心擢秀占文庭，潤沃偏宜雨露聲。',64,'全唐诗/poet.song.115000.json','["蕉心擢秀占文庭，潤沃偏宜雨露聲。", "已向杏壇新表瑞，莫嫌花譜舊無名。", "决科此日先幽讖，記異他年見史評。", "况有能詩賢令尹，直將美事付羣英。"]'),
('3537a474-eb29-4670-af83-c8604d9965cc','艾以諸公雌黄其詩意殊不平戲用前韻','陳棣','宋','宋诗','song-poetry','','[]','載味君詩字字新，方知後實稱先聲。',64,'全唐诗/poet.song.115000.json','["載味君詩字字新，方知後實稱先聲。", "文章素號五經笥，姓字行添千佛名。", "趙璧有瑕虛指示，隨珠無價妄譏評。", "官閒聊戯管城穎，小草銀鈎亂伯英。"]'),
('9de00351-9808-4f76-9b93-2fa5a05528c9','次韻蘇守金橘','陳棣','宋','宋诗','song-poetry','','[]','孤根移植自秋山，長養潛私刺史天。',64,'全唐诗/poet.song.115000.json','["孤根移植自秋山，長養潛私刺史天。", "青女染成金色淺，馮夷剖出蚌胎圓。", "慙非甘吉曾同傳，恥與楊盧議並肩。", "况有詞章傳樂府，佳名從此入新編。"]'),
('299cf198-6773-4aa1-8b64-bace527fcd35','白菊','陳棣','宋','宋诗','song-poetry','','[]','千芳百卉正凋零，喜見東籬粲玉英。',64,'全唐诗/poet.song.115000.json','["千芳百卉正凋零，喜見東籬粲玉英。", "粉面真能延月姊，檀心端不羨梅兄。", "騷經豈爲黄花作，丹鼎應須素液成。", "勿訝開遲後佳節，白衣猶足向淵明。"]'),
('27ec366e-74ca-4706-b97a-ce0b1b2d54be','次韻梅花四首  其一','陳棣','宋','宋诗','song-poetry','','[]','得得尋梅已覺遲，憑欄空賦惜花詩。',64,'全唐诗/poet.song.115000.json','["得得尋梅已覺遲，憑欄空賦惜花詩。", "流傳遠信人千里，漏洩春工雪一枝。", "照水丰容妃子浴，傍山瘦影伯夷饑。", "最憐清絕牽情處，月落參橫畫角悲。"]'),
('9e2c0e6f-e03c-4fd3-be04-a8210de5523c','次韻梅花四首  其二','陳棣','宋','宋诗','song-poetry','','[]','凍合千林暖未回，一枝先見臘前梅。',64,'全唐诗/poet.song.115000.json','["凍合千林暖未回，一枝先見臘前梅。", "寒溪淡月憑誰賞，冷蘂踈香不自媒。", "頼有此君爲伴侶，畧無凡卉作輿臺。", "欹危百折江頭路，應爲多情得得來。"]'),
('78cf1ded-ca79-40f4-9d97-a9bf7f047213','次韻梅花四首  其三','陳棣','宋','宋诗','song-poetry','','[]','鏤玉凝酥若未勻，南枝髣髴露天真。',64,'全唐诗/poet.song.115000.json','["鏤玉凝酥若未勻，南枝髣髴露天真。", "橫陳月下無雙影，占斷人間第一春。", "屈子浪吟蘭畹佩，韓公羞卜杏花隣。", "廣平見謂心如鐵，翻學高唐草賦人。"]'),
('6f2025d6-51b0-43cc-bd01-25c387133939','次韻梅花四首  其四','陳棣','宋','宋诗','song-poetry','','[]','愛花長苦惱天君，政恐因花賦洛神。',64,'全唐诗/poet.song.115000.json','["愛花長苦惱天君，政恐因花賦洛神。", "江上風霜方破臘，嶺頭氷雪已回春。", "故人遠信來千里，浪蘂凡香隔一塵。", "天與孤高超世俗，肯將賸馥乞蜂臣。"]'),
('d06b75e0-3844-455e-bc80-28339d2f929f','次韻劉敷言新雁','陳棣','宋','宋诗','song-poetry','','[]','倦飛聊復下江湖，此去衡陽萬里餘。',64,'全唐诗/poet.song.115000.json','["倦飛聊復下江湖，此去衡陽萬里餘。", "陣合魚麗司馬法，字排草聖右軍書。", "隨陽度塞身良苦，避繳啣蘆計已踈。", "一抹參差無亂序，似聞衙鼓列羣胥。"]'),
('6eb0a3cc-b0de-43d4-8bb3-8044f44cb33e','觀曹壽卿上舍詩軸題其後  其一','陳棣','宋','宋诗','song-poetry','','[]','君詩字字敵雙南，直把驪珠取次探。',64,'全唐诗/poet.song.115000.json','["君詩字字敵雙南，直把驪珠取次探。", "李杜盟寒誰共主，曹劉機淺不須參。", "囊中句好緣多愛，天外心歸計飽諳。", "讀罷長編知雋永，自然齒頰带餘甘。"]'),
('66422459-ed13-498b-97e6-c267a04815aa','觀曹壽卿上舍詩軸題其後  其二','陳棣','宋','宋诗','song-poetry','','[]','欲觀騷雅繼周南，虎子應須虎穴探。',64,'全唐诗/poet.song.115000.json','["欲觀騷雅繼周南，虎子應須虎穴探。", "策蹇衝寒將類賈，避堂舍蓋願同參。", "書能泣鬼世誰信，詩解窮人我自諳。", "但得低頭拜東野，此心依約已先甘。"]'),
('46204dfe-c978-4f2e-a880-2082462ad0e7','旅中有感復用前韻','陳棣','宋','宋诗','song-poetry','','[]','擿埴憑誰爲指南，囊空羞澁不容探。',64,'全唐诗/poet.song.115000.json','["擿埴憑誰爲指南，囊空羞澁不容探。", "年光有限堂堂去，世事無心細細參。", "故舊白頭驚未識，比隣青眼喜相諳。", "此生自斷何須問，荼苦從今等薺甘。"]'),
('c7e077ea-95be-48c0-bec1-4bfc500f57af','戲德秀幾道','陳棣','宋','宋诗','song-poetry','','[]','小檻新篁脫籜初，依然數軸壁間書。',64,'全唐诗/poet.song.115000.json','["小檻新篁脫籜初，依然數軸壁間書。", "已無塵落清聲外，空有香分素手餘。", "古獄寃銷神劍去，高堂夢破曉雲踈。", "圜扉只掩青青草，門外應無長者車。"]'),
('b19e1f6c-c6e1-4196-a856-e3f45f7e9170','使君饋食戲少蒙教授','陳棣','宋','宋诗','song-poetry','','[]','朝來食指非常動，果報兵厨已割烹。',64,'全唐诗/poet.song.115000.json','["朝來食指非常動，果報兵厨已割烹。", "醇德且多從事酒，珍庖特異小人羹。", "虎頭食肉方灰念，羊脚蹴蔬應震驚。", "歸遺細君真得計，隨緣燈火任卿卿。"]'),
('b44c50a2-0921-4aad-89db-989d6d89427b','還余朝綱雜編','陳棣','宋','宋诗','song-poetry','','[]','胸中渾渾乏新奇，虛辱熊羆百萬師。',64,'全唐诗/poet.song.115000.json','["胸中渾渾乏新奇，虛辱熊羆百萬師。", "較藝昔嘗窮五技，還書今復墮三癡。", "退飛頗愧一爲甚，盡銳那知再愈衰。", "自計拋書無復用，緘題重寄仲舒幃。"]'),
('f91ac81c-e116-43d5-a05e-434d00dd98d3','偶書','陳棣','宋','宋诗','song-poetry','','[]','詩魔大抵解窮人，到得人窮句益新。',64,'全唐诗/poet.song.115000.json','["詩魔大抵解窮人，到得人窮句益新。", "筆下自慚無好語，眼前底事最清貧。", "草玄天祿書窗冷，滌器臨邛酒市春。", "自古才高多命薄，區區何必論錢神。"]'),
('7323b2e4-fbce-4ded-8c00-a240613566ff','戲效連珠疊韻體','陳棣','宋','宋诗','song-poetry','','[]','泝流遲澁須流輕，石岸崎嶇沙岸平。',64,'全唐诗/poet.song.115000.json','["泝流遲澁須流輕，石岸崎嶇沙岸平。", "高樹影藏低樹影，前灘聲掩後灘聲。", "飛禽飛去語禽語，歸客歸休行客行。", "望斷誰憐魂欲斷，詩成轉覺夢難成。"]'),
('63597317-a283-4681-b697-ab35b588111c','戲題酒肆','陳棣','宋','宋诗','song-poetry','','[]','一氣無私萬物春，小兒造化果能神。',64,'全唐诗/poet.song.115000.json','["一氣無私萬物春，小兒造化果能神。", "鳥啼花發遽如許，酒病詩狂那厭頻。", "倒著敢期山簡醉，典衣誰計少陵貧。", "上林五祚他年賦，姑作臨邛滌器人。"]'),
('35cd74cd-f758-4f47-bdcf-4966770f589c','夜雪','陳棣','宋','宋诗','song-poetry','','[]','書帷夜雪耿無眠，晨起猶禁曉日寒。',64,'全唐诗/poet.song.115000.json','["書帷夜雪耿無眠，晨起猶禁曉日寒。", "旋見軟紅生野水，似看寸碧出遥山。", "詩成已覺風生座，飲散俄驚月滿鞍。", "夢破小窗依約態，渾疑暮雨楚臺還。"]'),
('26ff9d68-ab35-4e0b-b260-b4cd349f4922','挽處士喬公','陳棣','宋','宋诗','song-poetry','','[]','姓氏詳聞月旦推，典刑尚可一斑窺。',64,'全唐诗/poet.song.115000.json','["姓氏詳聞月旦推，典刑尚可一斑窺。", "義高諾重人皆仰，券失金存自不欺。", "富貴浮雲曾唾去，死生幻泡獨先知。", "一經教子陰功遠，印綬纍纍看異時。"]'),
('53993b96-78f7-400f-8df8-43b204bd785c','挽提幹趙君','陳棣','宋','宋诗','song-poetry','','[]','識君童稚過成人，旋見從師學日新。',64,'全唐诗/poet.song.115000.json','["識君童稚過成人，旋見從師學日新。", "一舉文場收雋譽，十年仕路固清貧。", "豪添徐邈中賢興，瘦減相如病渴身。", "好善如顔還短折，傷哉命也重悲辛。"]'),
('44164d14-7181-472c-a22d-a847289b4b48','挽張世英母夫人','陳棣','宋','宋诗','song-poetry','','[]','異鄉萍梗寄生涯，朝露俄驚嘆落花。',64,'全唐诗/poet.song.115000.json','["異鄉萍梗寄生涯，朝露俄驚嘆落花。", "蒿里歌傳風正慘，萱堂香冷月空斜。", "魂歸故國三千里，地卜高原一萬家。", "明日送車應擊轂，不堪閣泪聽邊笳。"]'),
('b91c00de-0dc3-4803-8633-95cf85aeb54b','巖桂餉鄭舜舉戲筆代柬  其一','陳棣','宋','宋诗','song-poetry','','[]','天香薰透辟寒金，拂拂鵝黄漢額深。',32,'全唐诗/poet.song.115000.json','["天香薰透辟寒金，拂拂鵝黄漢額深。", "多謝西風喚幽夢，徑隨秋蝶到踈林。"]'),
('995d9829-0b38-4a2e-899c-a4a652ddfff0','巖桂餉鄭舜舉戲筆代柬  其二','陳棣','宋','宋诗','song-poetry','','[]','折得天葩滿袖香，小窗寂寂伴凄凉。',32,'全唐诗/poet.song.115000.json','["折得天葩滿袖香，小窗寂寂伴凄凉。", "何如乞與文園客，瑶髻斜簪試晚粧。"]'),
('719163ae-32e4-4dbf-8e6b-6b63440a2465','再次韻  其一','陳棣','宋','宋诗','song-poetry','','[]','翠葆低籠衣縷金，惱人風味在秋深。',32,'全唐诗/poet.song.115000.json','["翠葆低籠衣縷金，惱人風味在秋深。", "不緣月窟移仙種，安得塵寰有桂林。"]'),
('e03755ac-8427-4395-a26b-910aa766ec57','再次韻  其二','陳棣','宋','宋诗','song-poetry','','[]','天恐花神漏洩香，故教醖釀待新凉。',32,'全唐诗/poet.song.115000.json','["天恐花神漏洩香，故教醖釀待新凉。", "丹鉛不御丰容淺，一洗塵凡時世粧。"]'),
('43ed744c-fdec-479b-b893-53ac1439faf4','次韻徐庭珍春日雜言十首  其一','陳棣','宋','宋诗','song-poetry','','[]','溪風嫋嫋素濤翻，兀坐書帷怯悄寒。',32,'全唐诗/poet.song.115000.json','["溪風嫋嫋素濤翻，兀坐書帷怯悄寒。", "老去見春如夢寐，此心底用倩人安。"]'),
('ae9ae576-2003-4e1f-afd5-a0bb8f3e7fd3','次韻徐庭珍春日雜言十首  其二','陳棣','宋','宋诗','song-poetry','','[]','身如不繫一虛舟，入眼江山總舊遊。',32,'全唐诗/poet.song.115000.json','["身如不繫一虛舟，入眼江山總舊遊。", "視昔視今俱勿論，且憑從事到青州。"]'),
('f8e8c66a-bd2d-424b-b46f-77829813ea81','次韻徐庭珍春日雜言十首  其三','陳棣','宋','宋诗','song-poetry','','[]','燕雀經營競短簷，未容蝶夢到花前。',32,'全唐诗/poet.song.115000.json','["燕雀經營競短簷，未容蝶夢到花前。", "吾生幾閲春榮謝，自嘆如蠶已再眠。"]'),
('a8dd46fb-4beb-4170-a37c-9283cb43a23b','次韻徐庭珍春日雜言十首  其四','陳棣','宋','宋诗','song-poetry','','[]','擾擾膠膠且罷休，會栽奴橘滿汀洲。',32,'全唐诗/poet.song.115000.json','["擾擾膠膠且罷休，會栽奴橘滿汀洲。", "但教方寸無餘事，不必林泉學枕流。"]'),
('dae3ad80-2167-452b-b883-efcc9bfc7cdc','次韻徐庭珍春日雜言十首  其五','陳棣','宋','宋诗','song-poetry','','[]','輕陰醖釀勒花天，節物撩人接禁烟。',32,'全唐诗/poet.song.115000.json','["輕陰醖釀勒花天，節物撩人接禁烟。", "沂上未成曾點服，杖頭聊掛阮生錢。"]'),
('d76cad6d-eca0-4565-b4cf-520288cc2785','次韻徐庭珍春日雜言十首  其六','陳棣','宋','宋诗','song-poetry','','[]','沉酣蠹簡不知春，庭設雀羅誰扣門。',32,'全唐诗/poet.song.115000.json','["沉酣蠹簡不知春，庭設雀羅誰扣門。", "拄頰看山無限意，陰晴變態異朝昏。"]'),
('694c91ea-7e51-4042-9767-cd0ff34fb2c2','次韻徐庭珍春日雜言十首  其七','陳棣','宋','宋诗','song-poetry','','[]','卉木爭供衆妙薰，春工試手爲裁成。',32,'全唐诗/poet.song.115000.json','["卉木爭供衆妙薰，春工試手爲裁成。", "紛紛落蘂鶑邊雨，寂寂遊絲燕外晴。"]'),
('96f4a4cc-43b1-4e32-8362-f5b1b65bc8b7','次韻徐庭珍春日雜言十首  其八','陳棣','宋','宋诗','song-poetry','','[]','幽花野蔓竟誰栽，傍水盈盈一笑開。',32,'全唐诗/poet.song.115000.json','["幽花野蔓竟誰栽，傍水盈盈一笑開。", "幾許遠携吟筆去，未應空掉酒船回。"]'),
('6c39047c-3adb-4b37-b85d-018cb4f63b83','次韻徐庭珍春日雜言十首  其九','陳棣','宋','宋诗','song-poetry','','[]','冶葉倡條過女牆，依然還作故園香。',32,'全唐诗/poet.song.115000.json','["冶葉倡條過女牆，依然還作故園香。", "雄蜂雌蝶無聊頼，盡日顛狂有底忙。"]'),
('f5696919-e372-48fb-825d-463cd4820577','次韻徐庭珍春日雜言十首  其一○','陳棣','宋','宋诗','song-poetry','','[]','小兒造化本無心，孰爲芳時作主人。',32,'全唐诗/poet.song.115000.json','["小兒造化本無心，孰爲芳時作主人。", "唯有丹青留得住，好令昌輩寫花真。"]'),
('a19af652-fb8b-46e9-8b6d-bd144fe58201','次韻陳季陵元夕  其一','陳棣','宋','宋诗','song-poetry','','[]','山城燈火欲黄昏，濕雨踈梅暗小園。',32,'全唐诗/poet.song.115000.json','["山城燈火欲黄昏，濕雨踈梅暗小園。", "回首武林行樂地，太平風物似開元。"]'),
('215a755a-486e-427b-8eb3-6855228a1f33','次韻陳季陵元夕  其二','陳棣','宋','宋诗','song-poetry','','[]','歸休無頼曲眠肱，掃盡繁華只一燈。',32,'全唐诗/poet.song.115000.json','["歸休無頼曲眠肱，掃盡繁華只一燈。", "冷淡生涯吾舊物，前身疑是小乘僧。"]'),
('4ece2842-5c51-496d-8868-98a095b79224','次韻陳季陵元夕  其三','陳棣','宋','宋诗','song-poetry','','[]','顧我每爲驚座客，如君真是謫仙人。',32,'全唐诗/poet.song.115000.json','["顧我每爲驚座客，如君真是謫仙人。", "相逢不作尋常語，一笑同酬慘澹春。"]'),
('c6688451-2ff5-4d6c-91f5-d62830efe380','李倅生辰三首  其一','陳棣','宋','宋诗','song-poetry','','[]','伯陽飛御上層天，繼世雲礽盡謫仙。',32,'全唐诗/poet.song.115000.json','["伯陽飛御上層天，繼世雲礽盡謫仙。", "炯炯方瞳真壽相，不勞頌祝自長年。"]'),
('61379c4b-0aa6-43fa-a42e-2fb1b5325683','李倅生辰三首  其二','陳棣','宋','宋诗','song-poetry','','[]','心覽沖虛厭物波，樽前肯聽雪兒歌。',32,'全唐诗/poet.song.115000.json','["心覽沖虛厭物波，樽前肯聽雪兒歌。", "能捐伐性嬋娟斧，不必樛枝號養和。"]'),
('6c4f68ff-465b-46e5-bdc1-f6abc65ed964','李倅生辰三首  其三','陳棣','宋','宋诗','song-poetry','','[]','文章浩浩若江河，錦橐嘲吟得句多。',32,'全唐诗/poet.song.115000.json','["文章浩浩若江河，錦橐嘲吟得句多。", "政恐絲綸須大手，竚看三俊在鑾坡。"]'),
('cb28c8a4-b306-461e-85e2-64f6ccb6f9f2','挽奉議劉公度四首  其一','陳棣','宋','宋诗','song-poetry','','[]','英譽當年藹上庠，談經肯羨解頤匡。',32,'全唐诗/poet.song.115000.json','["英譽當年藹上庠，談經肯羨解頤匡。", "才高不第空嗟惜，一命聊爲末路光。"]'),
('2c2ba72f-8d83-4cac-847b-7ac92e01a99c','挽奉議劉公度四首  其二','陳棣','宋','宋诗','song-poetry','','[]','平生學術在斯民，藴積淵源百未伸。',32,'全唐诗/poet.song.115000.json','["平生學術在斯民，藴積淵源百未伸。", "邊障掾曹聊小試，一城惠愛已如春。"]'),
('4d152d4e-4b4a-46b6-a9c9-f8d41e4fb194','挽奉議劉公度四首  其三','陳棣','宋','宋诗','song-poetry','','[]','風鑒高明世少雙，衮榮撻辱擅雌黄。',32,'全唐诗/poet.song.115000.json','["風鑒高明世少雙，衮榮撻辱擅雌黄。", "須知柱下書言手，元是東床坦腹郎。"]'),
('22730134-d03c-406f-a951-abf0e9438c75','挽奉議劉公度四首  其四','陳棣','宋','宋诗','song-poetry','','[]','掛冠神武賦歸歟，旋捧恩綸賜佩魚。',32,'全唐诗/poet.song.115000.json','["掛冠神武賦歸歟，旋捧恩綸賜佩魚。", "誰謂桑榆將暮景，駢來慶事萃門閭。"]'),
('eea2fe9e-06a7-4657-b1ba-4da2ed826001','過馮公嶺','陳棣','宋','宋诗','song-poetry','','[]','整促籃輿破曉晴，嵐光滴翠夾衣輕。',32,'全唐诗/poet.song.115000.json','["整促籃輿破曉晴，嵐光滴翠夾衣輕。", "日窺青嶂坳中出，身在白雲深處行。"]'),
('151e1fb1-f283-48b1-9e6e-b83e91a89d66','陳公藻覓筍仍許作包子','陳棣','宋','宋诗','song-poetry','','[]','玉版禪師來應供，錦綳稚子敢分珍。',32,'全唐诗/poet.song.115000.json','["玉版禪師來應供，錦綳稚子敢分珍。", "并包更藉桄榔屑，風味懸知定可人。"]'),
('6e096297-7499-4f79-9e89-39fd5935c864','晚春道中四首  其一','陳棣','宋','宋诗','song-poetry','','[]','簿書叢裏掣歸身，萬樹毶毶淺綠勻。',32,'全唐诗/poet.song.115000.json','["簿書叢裏掣歸身，萬樹毶毶淺綠勻。", "試向小園尋落蘂，慇懃拂拭覓餘春。"]'),
('670c2374-a9da-4939-a3da-fbd7f9c832a5','晚春道中四首  其二','陳棣','宋','宋诗','song-poetry','','[]','歸塗檢點物華非，黛色隨風上柳枝。',32,'全唐诗/poet.song.115000.json','["歸塗檢點物華非，黛色隨風上柳枝。", "撲撲晴香戀芳草，却疑春去未多時。"]'),
('a0d2412c-4a65-4cb7-b218-cf05dafdf636','晚春道中四首  其三','陳棣','宋','宋诗','song-poetry','','[]','纖穠掃盡換清陰，便有南風欲薦琴。',32,'全唐诗/poet.song.115000.json','["纖穠掃盡換清陰，便有南風欲薦琴。", "漫道仙葩歸閬苑，小兒造化本無心。"]'),
('e3b5ecb9-e5a9-4f82-b8f4-67100b51dfb9','晚春道中四首  其四','陳棣','宋','宋诗','song-poetry','','[]','芍藥無香燕有雛，綿蠻猶苦勸提壺。',32,'全唐诗/poet.song.115000.json','["芍藥無香燕有雛，綿蠻猶苦勸提壺。", "直須强作留春計，爛醉黄公舊酒罏。"]'),
('70f07e68-0379-4e88-9394-4049f93b4b24','回文二絕  其一','陳棣','宋','宋诗','song-poetry','','[]','春晚落花飛藉草，月明驚鵲墮棲枝。',32,'全唐诗/poet.song.115000.json','["春晚落花飛藉草，月明驚鵲墮棲枝。", "人歸望濶江天暮，夢斷愁深夜漏遲。"]'),
('9e6dd7f4-5ae4-440a-9be7-9ebe31c07b65','回文二絕  其二','陳棣','宋','宋诗','song-poetry','','[]','衣沾暗淚香凝怨，錦織新詩遠寄愁。',32,'全唐诗/poet.song.115000.json','["衣沾暗淚香凝怨，錦織新詩遠寄愁。", "圍減带銷紅玉瘦，粉慵粧淺翠蛾羞。"]'),
('a5583ab7-6621-48f5-9c0e-1644d6d52821','讀少陵詩','陳棣','宋','宋诗','song-poetry','','[]','建安七子文，騷雅生贅疣。',144,'全唐诗/poet.song.115000.json','["建安七子文，騷雅生贅疣。", "除苛起膏肓，公爲第一流。", "滿朝競飛翔，惟公獨淹留。", "平生一嚴武，幾成鞭虎頭。", "定知詩窮人，到骨未肯休。", "執友自青雲，蹭跳老滄洲。", "破除世萬事，麯生聊可謀。", "危言竟何補，軟語祇自羞。", "成此一段奇，政坐多牢愁。", "收拾萬丈光，千古射斗牛。", "開卷想清標，凜如對霜秋。", "閉戶味膏馥，妄言希驊騮。"]'),
('61f92f27-634a-434a-9096-02463fbab25c','偶成','陳棣','宋','宋诗','song-poetry','','[]','直面溪山照眼明，息肩簿領暫身輕。',64,'全唐诗/poet.song.115000.json','["直面溪山照眼明，息肩簿領暫身輕。", "蝸巢得失真餘事，燕羽差池已半生。", "老境到門顔有甲，愁城堅壁酒無兵。", "何時蛻迹囂塵外，莫問人間無用名。"]'),
('59050cd9-f42e-45c7-a748-047480933650','無題','陳棣','宋','宋诗','song-poetry','','[]','斥鷃蒿蓬足，鯤鵬謾北溟。',48,'全唐诗/poet.song.115000.json','["斥鷃蒿蓬足，鯤鵬謾北溟。", "餘生薰白業，內景練黄庭。", "大白蟻浮綠，短檠燈閃青。", "欲知陶令趣，應向醉中醒。"]'),
('1f3f6e84-5f7f-467d-88a8-b29fde4218c2','上湖','陳棣','宋','宋诗','song-poetry','','[]','舟車出闤闠，蹔覺脫樊籠。',48,'全唐诗/poet.song.115000.json','["舟車出闤闠，蹔覺脫樊籠。", "松蔭凄迷日，荷香澹沱風。", "凌晨爭迅急，向晚却和融。", "貌取君詩句，方知物象同。"]'),
('c4a5c10d-6d94-457b-80b0-8b70b7fc0c2b','蠟梅三絕  其一','陳棣','宋','宋诗','song-poetry','','[]','蜂採羣芳釀蜜房，釀成猶作百花香。',32,'全唐诗/poet.song.115000.json','["蜂採羣芳釀蜜房，釀成猶作百花香。", "化工却取蜂房蠟，剪出寒梢色正黄。"]'),
('e3997a1b-d6b1-4bb3-b588-54b46d3e7a57','蠟梅三絕  其二','陳棣','宋','宋诗','song-poetry','','[]','林下雖無傾國艷，枝頭疑有返魂香。',32,'全唐诗/poet.song.115000.json','["林下雖無傾國艷，枝頭疑有返魂香。", "新粧未肯隨時改，猶是當年漢額黄。"]'),
('fe5fbf23-b3da-4e40-a55d-e7b4675cfa78','蠟梅三絕  其三','陳棣','宋','宋诗','song-poetry','','[]','寒菊已枯分正色，春蘭未秀借幽香。',32,'全唐诗/poet.song.115000.json','["寒菊已枯分正色，春蘭未秀借幽香。", "憑君折取簪霜鬢，解與眉間一樣黄。"]'),
('3a890c58-219a-4ee9-96a2-c2e91871ba87','廛隠堂爲楊元會賦','陳棣','宋','宋诗','song-poetry','','[]','大隠何曾去市廛，人間真有遁神仙。',64,'全唐诗/poet.song.115000.json','["大隠何曾去市廛，人間真有遁神仙。", "身閒已覺塵難染，心遠由來地自偏。", "何事遊方期汗漫，不妨酌月問嬋娟。", "胸中丘壑可窺處，墨戲縱橫出渭川。"]'),
('f7555f62-3aa8-4901-a741-75b65510c220','新沐有感','陳棣','宋','宋诗','song-poetry','','[]','我髮日已疏，尚喜鬢未斑。',144,'全唐诗/poet.song.115000.json','["我髮日已疏，尚喜鬢未斑。", "晴朝試一沐，但覺盤水寬。", "千梳發清快，凜凜肌骨寒。", "脫落等秋籜，光潤如春巒。", "譬彼雨露滋，下澤枯蓬根。", "烏雲猶半濕，霜葉不加繁。", "我生嗜疏懶，肯事形骸間。", "一月半不理，垢膩何由刪。", "今辰新沐罷，快若沃狂瀾。", "呼兒奉禨飲，爲作椎結團。", "歲月寖相逼，歡娛心已闌。", "看鏡想勳業，森然欲衝冠。"]'),
('b7ff2310-04cf-4424-9f41-526062baa3dd','縱目','陳棣','宋','宋诗','song-poetry','','[]','思窮煙浪闊，目斷暮雲層。',48,'全唐诗/poet.song.115000.json','["思窮煙浪闊，目斷暮雲層。", "舊賞去何有，新詩得未曾。", "披章如對景，搜句懶挑燈。", "酬唱慚非敵，君千我百能。"]'),
('dc0ca616-5e8a-4f06-9cb0-7cc2919cc501','讀豫章集成柏梁體','陳棣','宋','宋诗','song-poetry','','[]','元祐昇平超治古，誕布人文化寰宇。',320,'全唐诗/poet.song.115000.json','["元祐昇平超治古，誕布人文化寰宇。", "道山翰苑郡仙處，一代文章繼周魯。", "斯道盟寒誰是主，眉山二老文章虎。", "眉山鑒裁高難與，網羅九萬摶風羽。", "晁張超然鴻鵠舉，秦郎繼作翹翹楚。", "餘子紛紛謾旁午，韓門籍湜何須數。", "豫章詩律加嚴苦，洗空萬古塵凡語。", "後來鮮儷前無伍，真是江西第一祖。", "錦繡陸離纏肺腑，寶唾珠璣終日吐。", "兔穎煙煤驟如雨，混然天成絕斤斧。", "騷經抑怨知何補，白雪陽春空媚嫵。", "囊括鮑謝包徐庾，下視謫仙平揖甫。", "近時作者宗燕許，入社投名仰成矩。", "殘膏賸馥爭探取，派別枝分已難禦。", "專黨同門伐異戶，陳言糟粕棄如土。", "宗門不絕僅如縷，究竟疇能踵前武。", "遺編璀璨瓊瑶譜，八珍間列羅樽俎。", "誦之琅琅中宮呂，心清何止頭風愈。", "古人純全嗟莫覩，徒味篇章想簪組。", "鋪張盛美誇才諝，自笑雷門持布鼓。"]'),
('2156c6ac-03f1-404f-900e-ed53b3961033','定光南安巗  其一','鄭弼','宋','宋诗','song-poetry','','[]','石聳靈巖接太虛，百千年稱定光居。',32,'全唐诗/poet.song.115000.json','["石聳靈巖接太虛，百千年稱定光居。", "未知天上何方有，應是人間別地無。"]'),
('2254d996-46a8-4073-9e79-cbd002b0f14b','定光南安巗  其二','鄭弼','宋','宋诗','song-poetry','','[]','香風影裏迎新魄，梵唄聲中見落暉。',32,'全唐诗/poet.song.115000.json','["香風影裏迎新魄，梵唄聲中見落暉。", "自恨勞生名利役，不能來此共忘機。"]'),
('f2104216-411c-44e6-94bc-939eb4aba86e','定光南安巗  其三','鄭弼','宋','宋诗','song-poetry','','[]','路入雲山幾萬層，豁然巖宇勢崢嶸。',32,'全唐诗/poet.song.115000.json','["路入雲山幾萬層，豁然巖宇勢崢嶸。", "地從物外囂塵斷，天到壺中日月明。"]'),
('4cb916f1-2b60-427e-a242-0b62fe7812e3','登江樓','李宏','宋','宋诗','song-poetry','','[]','三江會合水交流，擁抱嵐光送客舟。',32,'全唐诗/poet.song.115000.json','["三江會合水交流，擁抱嵐光送客舟。", "只與寄詩身不到，老人可是負江樓。"]'),
('8b067013-e3ef-4535-94bb-f20c5c83b079','大滌洞天留題','鄭名卿','宋','宋诗','song-poetry','','[]','問路先從通濟橋，沿溪長岸去迢迢。',64,'全唐诗/poet.song.115000.json','["問路先從通濟橋，沿溪長岸去迢迢。", "人間別有神仙境，雲裏深藏古洞霄。", "石穴幽陰然火照，琳宮清曠隔塵囂。", "山蟠九鎖人希到，得侶同遊俗慮消。"]'),
('c6f930e5-203a-49aa-b41e-28290fe83cb2','游虎邱','王述','宋','宋诗','song-poetry','','[]','尋勝招提去，追隨李郭舟。',48,'全唐诗/poet.song.115000.json','["尋勝招提去，追隨李郭舟。", "水雲迷遠日，烟景變新秋。", "大愜幽人賞，應忘倦客愁。", "歸來須及晚，初月在山頭。"]'),
('1986de4f-9d92-4b13-b624-120704d21082','題黄陵二妃祠','王遵','宋','宋诗','song-poetry','','[]','帝子當年恨幾多，楚山千疊鬰嵯峨。',64,'全唐诗/poet.song.115000.json','["帝子當年恨幾多，楚山千疊鬰嵯峨。", "淚痕點滴留斑竹，寶瑟悲凉隔素波。", "媯汭舊存虞史載，蒼梧誰證汲書訛。", "凄凉弔古堪傷處，那更瀟湘接汨羅。"]'),
('3e54a405-f1b0-44bc-bd68-8314bca8effb','井蓮坊','戴顗','宋','宋诗','song-poetry','','[]','畫梲文垂藻，蠲災意已傳。',24,'全唐诗/poet.song.115000.json','["畫梲文垂藻，蠲災意已傳。", "哲人思厭勝，東井刻荷蓮。"]'),
('f6e075d5-7ca7-48ad-ac04-7abd2a98e80a','偈頌二十九首  其一','釋雲','宋','宋诗','song-poetry','','[]','丹霞燒木佛，院主眉鬚落。',48,'全唐诗/poet.song.115000.json','["丹霞燒木佛，院主眉鬚落。", "官裏有明條，許人私結約。", "傝䢆杜禪和，識情爭卜度。", "休卜度，萬里遼天飛一鶚。"]'),
('45500efc-44ad-4b74-93b0-847ae8c35231','偈頌二十九首  其二','釋雲','宋','宋诗','song-poetry','','[]','教你不肯你，爲君通一線。',24,'全唐诗/poet.song.115000.json','["教你不肯你，爲君通一線。", "若是明眼人，覓甚臘月扇。"]'),
('f30b5078-1b04-46f5-9850-0f0b241e0a53','偈頌二十九首  其三','釋雲','宋','宋诗','song-poetry','','[]','支提山裏作上元，若校諸方真箇異。',48,'全唐诗/poet.song.115000.json','["支提山裏作上元，若校諸方真箇異。", "大蟲舌上打鞦韆，蟭螟眼裏放夜市。", "燈籠倒退舞三臺，露柱趨前弄鱉鼻。"]'),
('c220b208-219d-47ca-90c0-80bda776dc1c','偈頌二十九首  其四','釋雲','宋','宋诗','song-poetry','','[]','崑崙奴，著鐵袴。',72,'全唐诗/poet.song.115000.json','["崑崙奴，著鐵袴。", "打一棒，行一步。", "遱邏真箇遱邏，峭措非常峭措。", "不惟佛法會盡，且是文章滿肚。", "見渠嘗試篇詩，便有驚人底句。", "如今對大衆前，不免一時剖露。"]'),
('567add2b-86c4-45de-8d72-a26970651694','偈頌二十九首  其五','釋雲','宋','宋诗','song-poetry','','[]','佛說一乘法，無二亦無三。',41,'全唐诗/poet.song.115000.json','["佛說一乘法，無二亦無三。", "山花開似錦，澗水湛如藍。", "支提遮裏，無法可說，贏得口似匾擔。"]'),
('8d7fe898-e695-49f8-928d-bae2e92ed935','偈頌二十九首  其六','釋雲','宋','宋诗','song-poetry','','[]','春無三日晴，夏無十日雨。',24,'全唐诗/poet.song.115000.json','["春無三日晴，夏無十日雨。", "蛇咬蝦蟆聲，更有衆生苦。"]'),
('7add26c7-e06f-4c62-887e-abf2538b924f','偈頌二十九首  其七','釋雲','宋','宋诗','song-poetry','','[]','支提不敢向人說，達磨西來有妙訣。',32,'全唐诗/poet.song.115000.json','["支提不敢向人說，達磨西來有妙訣。", "若將妄語誑衆生，自招拔舌塵沙劫。"]'),
('6624c74c-78c5-4d8e-8d67-4b6403225289','偈頌二十九首  其八','釋雲','宋','宋诗','song-poetry','','[]','支提元不會禪，只是依時及節。',56,'全唐诗/poet.song.115000.json','["支提元不會禪，只是依時及節。", "孟春即曰猶寒，孟夏即曰漸熱。", "雖無格外高談，不向眼中添屑。", "汝等莫錯商量，打你頭破額裂。"]'),
('b6a6d02e-0377-42f3-80b5-d3cc27ccc9c8','偈頌二十九首  其九','釋雲','宋','宋诗','song-poetry','','[]','今朝五月五，擊動禾山鼓。',24,'全唐诗/poet.song.115000.json','["今朝五月五，擊動禾山鼓。", "鬰壘與神荼，歡呼齊起舞。"]'),
('34ebe391-9a21-4770-a484-3b1948aab150','偈頌二十九首  其一○','釋雲','宋','宋诗','song-poetry','','[]','蝦蟆翻出闊，曲鱔草之長。',24,'全唐诗/poet.song.115000.json','["蝦蟆翻出闊，曲鱔草之長。", "門前飛八百，屋後走千張。"]'),
('629b9a81-f1e8-4cb9-8202-7dd709e58569','偈頌二十九首  其一一','釋雲','宋','宋诗','song-poetry','','[]','參禪人，多逐妄，不用起模仍畫樣。',32,'全唐诗/poet.song.115000.json','["參禪人，多逐妄，不用起模仍畫樣。", "春風吹綻桃李花，淡煙疎雨籠青嶂。"]'),
('c9c73a4b-d3c6-46d2-b259-bd0c1647d988','偈頌二十九首  其一二','釋雲','宋','宋诗','song-poetry','','[]','叮嚀損君德，無言真有功。',24,'全唐诗/poet.song.115000.json','["叮嚀損君德，無言真有功。", "任從滄海變，終不爲君通。"]'),
('638aa0d7-9bf0-435f-b83e-92b726ac4d43','偈頌二十九首  其一三','釋雲','宋','宋诗','song-poetry','','[]','支提佛法無多子，何必胡僧勸舉揚。',32,'全唐诗/poet.song.115000.json','["支提佛法無多子，何必胡僧勸舉揚。", "好對春風二三月，鷓鴣啼處百花香。"]'),
('1f03858a-c28d-42cd-9d33-44504165c888','偈頌二十九首  其一四','釋雲','宋','宋诗','song-poetry','','[]','五月方改旦，今朝又初十。',60,'全唐诗/poet.song.115000.json','["五月方改旦，今朝又初十。", "日月去如飛，快鷂趁不及。", "禪須放下參，但莫固拘執。", "是處解脫門，汝自不肯入。", "何必問支提，丁字著脚立。"]'),
('379aef15-ce41-48fd-8bdc-49e8d22a221e','偈頌二十九首  其一五','釋雲','宋','宋诗','song-poetry','','[]','如來禪，祖師意。',64,'全唐诗/poet.song.115000.json','["如來禪，祖師意。", "絕承當，只這是。", "破草鞋，汗臭氣。", "熱碗鳴，馿豚沸。", "也大奇，不思議。", "分明在目前，今古應無墜。", "佛滅二千年，比丘少慚愧。"]'),
('d2f4aa11-e3f7-4574-9b1c-66e26035b296','偈頌二十九首  其一六','釋雲','宋','宋诗','song-poetry','','[]','嗟見世間人，永劫墮迷津。',24,'全唐诗/poet.song.115000.json','["嗟見世間人，永劫墮迷津。", "不省這箇意，修行徒苦辛。"]'),
('b0f88079-c64d-4cc6-b280-a8e470b3247f','偈頌二十九首  其一七','釋雲','宋','宋诗','song-poetry','','[]','雲門普，風穴瞎。',20,'全唐诗/poet.song.115000.json','["雲門普，風穴瞎。", "三門外金剛，冷地裏笑殺。"]'),
('788f0b59-88bd-4a63-8ec5-cac741a23829','偈頌二十九首  其一八','釋雲','宋','宋诗','song-poetry','','[]','參禪人，莫造作。',62,'全唐诗/poet.song.115000.json','["參禪人，莫造作。", "擬心即差，動念即錯。", "大乘小乘，錢貫井索。", "前三後三，佛手馿脚。", "開眼也著，合眼也著。", "擬向這裏承當，鼻孔依前失却。"]'),
('75580dc7-8a9d-4eb4-8021-fa71d45710b5','偈頌二十九首  其一九','釋雲','宋','宋诗','song-poetry','','[]','支提門下，五日一參。',30,'全唐诗/poet.song.115000.json','["支提門下，五日一參。", "我纔合掌，汝便和南。", "龍象蹴蹋，非馿所堪。"]'),
('8eeacab7-616a-414b-9409-629d08e3a50a','偈頌二十九首  其二○','釋雲','宋','宋诗','song-poetry','','[]','乍離千聖林間寺，來汲城頭石罅泉。',32,'全唐诗/poet.song.115000.json','["乍離千聖林間寺，來汲城頭石罅泉。", "相見杯茶雖淡薄，往來無惜爲君煎。"]'),
('0db078b6-aa1b-4219-adae-c5fe64a77b34','偈頌二十九首  其二一','釋雲','宋','宋诗','song-poetry','','[]','佛是塵，法是塵，區區馳覓謾勞神。',32,'全唐诗/poet.song.115000.json','["佛是塵，法是塵，區區馳覓謾勞神。", "向道莫行山下路，果然猿叫斷腸聲。"]'),
('df75e40e-cb0f-463a-8ed6-a8f3c2c3595d','偈頌二十九首  其二二','釋雲','宋','宋诗','song-poetry','','[]','風高八九月，自合知時節。',72,'全唐诗/poet.song.115000.json','["風高八九月，自合知時節。", "何必待山僧，陞堂特地說。", "天際鴈南飛，接翅作行列。", "悉念佛法僧，軋軋聲不絕。", "影落寒山水，已是重漏泄。", "普請好生觀，西來無妙訣。"]'),
('11b9c7f8-61ce-4a4e-b155-e037b5fe778c','偈頌二十九首  其二三','釋雲','宋','宋诗','song-poetry','','[]','前三後三，日面月面。',46,'全唐诗/poet.song.115000.json','["前三後三，日面月面。", "七凸八凹，千化萬變。", "捏聚放開，胡來漢現。", "不離當處常湛然，覓即如君不可見。"]'),
('4ea17cab-eb9b-427c-ac1f-7b6cac01ddfd','偈頌二十九首  其二四','釋雲','宋','宋诗','song-poetry','','[]','了了了時無可了，玄玄玄處亦須呵。',32,'全唐诗/poet.song.115000.json','["了了了時無可了，玄玄玄處亦須呵。", "貪生逐日區區去，喚不回頭爭奈何。"]'),
('b0443f7a-0f99-414d-abb5-d50020e732b2','偈頌二十九首  其二五','釋雲','宋','宋诗','song-poetry','','[]','大盡三十日，小盡二十九。',64,'全唐诗/poet.song.115000.json','["大盡三十日，小盡二十九。", "昨夜送窮年，今朝賀歲首。", "時節有變更，佛法無新舊。", "既是箇中人，不惜娘生口。", "坐對春風唱鷓鴣，嘉聲不落威音後。"]'),
('71925985-9cf0-4929-aca5-1be249135d45','偈頌二十九首  其二六','釋雲','宋','宋诗','song-poetry','','[]','春色融和，羣芳競拆。',63,'全唐诗/poet.song.115000.json','["春色融和，羣芳競拆。", "水綠山青，桃紅李白。", "不是時節因緣，亦非向上奇特。", "恁麽也不得，不恁麽也不得。", "此時若不究根源，直待當來問彌勒。"]'),
('fb9c529f-46a6-426a-a26d-603d95892c57','偈頌二十九首  其二七','釋雲','宋','宋诗','song-poetry','','[]','是非只爲多開口，煩惱皆因强出頭。',32,'全唐诗/poet.song.115000.json','["是非只爲多開口，煩惱皆因强出頭。", "致使韶陽要打殺，思量著甚底來由。"]'),
('a174898b-6e61-4ce1-9e5e-3397497ab89f','偈頌二十九首  其二八','釋雲','宋','宋诗','song-poetry','','[]','今朝五月十有五，十日作了八日雨。',32,'全唐诗/poet.song.115000.json','["今朝五月十有五，十日作了八日雨。", "不薦簷頭滴滴聲，說妙談玄何足數。"]'),
('e20d76d9-d16c-4f9d-a7f2-731d68c7ba17','偈頌二十九首  其二九','釋雲','宋','宋诗','song-poetry','','[]','秋江清淺時，白鷺和煙島。',24,'全唐诗/poet.song.115000.json','["秋江清淺時，白鷺和煙島。", "良哉觀世音，全身入荒草。"]'),
('f8aea127-b4d9-4b4e-9bbf-6ac0c25a7dab','偈頌二十九首  其三○','釋雲','宋','宋诗','song-poetry','','[]','人從陳州來，不得許州信。',37,'全唐诗/poet.song.115000.json','["人從陳州來，不得許州信。", "鐘樓上念讚，牀脚下種菜。", "盞子撲落地，楪子成七八片。"]'),
('d4ad2e1c-003d-45b7-a3a0-f84f2cae79ff','頌古','釋雲','宋','宋诗','song-poetry','','[]','大隠居鄽，小隠居山。',36,'全唐诗/poet.song.115000.json','["大隠居鄽，小隠居山。", "各得其所，隨分安閒。", "何必更來論出入，人生在處有餘歡。"]'),
('abeef4d1-f354-4255-9289-a805a1b884fa','頌古八首  其一','釋雲','宋','宋诗','song-poetry','','[]','一片銀蟾掛碧天，清光冷照鳳樓前。',32,'全唐诗/poet.song.115000.json','["一片銀蟾掛碧天，清光冷照鳳樓前。", "九重玉戶深深閉，爭見扶疎桂影圓。"]'),
('6c72b331-5083-43a3-b7ec-7f6ab340c5e5','頌古八首  其二','釋雲','宋','宋诗','song-poetry','','[]','春風有時惡，春風有時好。',24,'全唐诗/poet.song.115000.json','["春風有時惡，春風有時好。", "人競逐春風，却被春風惱。"]'),
('2f7ce680-43a4-4482-b9bb-bf658359fc86','頌古八首  其三','釋雲','宋','宋诗','song-poetry','','[]','一葉扁舟信晚風，雨昏渾不辨西東。',32,'全唐诗/poet.song.115000.json','["一葉扁舟信晚風，雨昏渾不辨西東。", "不因再到秋江上，爭見蘆花對蓼紅。"]'),
('6997d90b-d4c1-4292-a65e-c30339d799be','頌古八首  其四','釋雲','宋','宋诗','song-poetry','','[]','白雲綻處見明月，黄葉落時聞擣衣。',32,'全唐诗/poet.song.115000.json','["白雲綻處見明月，黄葉落時聞擣衣。", "勸君休去便休去，欲覓了時無了時。"]'),
('69500938-195a-46f4-b811-ef84b57274b5','頌古八首  其五','釋雲','宋','宋诗','song-poetry','','[]','獨唱清新拍不同，寥寥千古意無窮。',32,'全唐诗/poet.song.115000.json','["獨唱清新拍不同，寥寥千古意無窮。", "擬開眼向聲前聽，早被風吹別調中。"]'),
('3a695be8-3f31-4d80-9f5b-b6878ad711f2','頌古八首  其六','釋雲','宋','宋诗','song-poetry','','[]','家人卦變作明夷，爻象分明不待推。',32,'全唐诗/poet.song.115000.json','["家人卦變作明夷，爻象分明不待推。", "無動無謀終吉慶，有求有用即迍危。"]'),
('fecda05a-d7d8-40fa-91ce-10dc77fa5e85','頌古八首  其七','釋雲','宋','宋诗','song-poetry','','[]','縮頭只可藏山谷，出得山來却不堪。',32,'全唐诗/poet.song.115000.json','["縮頭只可藏山谷，出得山來却不堪。", "若謂利生開佛見，這般惡口不如緘。"]'),
('97c9536e-367a-484d-9d3e-da9860d22b95','頌古八首  其八','釋雲','宋','宋诗','song-poetry','','[]','終朝皮{彭/厂毛}街頭走，有口何曾誦法華。',37,'全唐诗/poet.song.115000.json','["終朝皮{彭/厂毛}街頭走，有口何曾誦法華。", "末後脫空尤叵耐，逝多容你更交加。"]'),
('924af33a-c98b-4788-9263-a07eae657e50','給孤長者','釋雲','宋','宋诗','song-poetry','','[]','遠迓瞿曇至給孤，竚聆有法爲開敷。',32,'全唐诗/poet.song.115000.json','["遠迓瞿曇至給孤，竚聆有法爲開敷。", "早知是法應須捨，好請乘時出帝都。"]'),
('0ba3e0fa-3ff9-4a8b-abde-34a498e8e63f','雲門大師','釋雲','宋','宋诗','song-poetry','','[]','中毒睦州，伸寃雪嶠。',40,'全唐诗/poet.song.115000.json','["中毒睦州，伸寃雪嶠。", "拔本無門，剜空作竅。", "有折脚殃，乃破家兆。", "萬福曾郎，容此不肖。"]'),
('71776d27-7e65-4716-b8c6-6a53094ea336','送幽巗滋上人出嶺','釋雲','宋','宋诗','song-poetry','','[]','諸方無說汝無聞，聞說俱無莫倒跟。',32,'全唐诗/poet.song.115000.json','["諸方無說汝無聞，聞說俱無莫倒跟。", "纔起絲毫奇特想，依前似不出雷門。"]'),
('602388a2-b0f0-4a05-85fa-1531ed73e10c','頌古','釋雲','宋','宋诗','song-poetry','','[]','狗子無佛性，泥捏活大聖。',24,'全唐诗/poet.song.115000.json','["狗子無佛性，泥捏活大聖。", "不是泗州人，說著也不信。"]'),
('2d6a6072-570c-4729-a74f-3d6774a99b55','鳳凰巗','張建','宋','宋诗','song-poetry','','[]','盡□□□□□兵，岐山無復鳳凰鳴。',32,'全唐诗/poet.song.115000.json','["盡□□□□□兵，岐山無復鳳凰鳴。", "何人更解驅頑石，飛向中原頌太平。"]'),
('5b28c776-f42b-474e-83cc-5b28ff5648df','句','鄒宗謨','宋','宋诗','song-poetry','','[]','遠繼杜參謀，近追蘇玉局。',12,'全唐诗/poet.song.115000.json','["遠繼杜參謀，近追蘇玉局。"]'),
('29f22bc0-77a1-4fc5-b2e4-49e4342d65a8','病鶴','何若','宋','宋诗','song-poetry','','[]','仙骨珊珊瘦怯風，褵褷晴曬石橋東。',64,'全唐诗/poet.song.115000.json','["仙骨珊珊瘦怯風，褵褷晴曬石橋東。", "丹砂靈圃何緣覓，華表荒城半已空。", "羽化定教隨子晉，舞衣久不悅羊公。", "聽他盍旦鳴相樂，自此朝陽鳳在桐。"]'),
('3ae43bf6-d968-4fa2-aafe-43396759583d','捉搦歌','姚寬','宋','宋诗','song-poetry','','[]','雙蝶護花飛，老女怨春暮。',60,'全唐诗/poet.song.115000.json','["雙蝶護花飛，老女怨春暮。", "撲蝶金粉銷，折花顔色故。", "窗中聲唧唧，雨泣至天曙。", "問婆許嫁女，莫要擇門戶。", "願得不單棲，任他流浪去。"]'),
('c89617ae-afc8-49d0-9bae-9f06bbafaa44','少年行','姚寬','宋','宋诗','song-poetry','','[]','少年白鼻騧，玉勒錦連韉。',36,'全唐诗/poet.song.115000.json','["少年白鼻騧，玉勒錦連韉。", "徑就胡姬飲，熟醉當壚眠。", "剝絲入蠶繭，郎意在纏綿。"]'),
('f206f8e4-5e61-468f-9505-448833186a36','江南新體  其一','姚寬','宋','宋诗','song-poetry','','[]','悠悠復悠悠，日夜瀟湘流。',36,'全唐诗/poet.song.115000.json','["悠悠復悠悠，日夜瀟湘流。", "瀟湘春草生，行人向南愁。", "緩歌竹枝娘，窈窕蘋花洲。"]'),
('d7883966-aa41-4dc6-9afd-baa8ec7f7e5a','江南新體  其二','姚寬','宋','宋诗','song-poetry','','[]','江南無春秋，花草紅復綠。',36,'全唐诗/poet.song.115000.json','["江南無春秋，花草紅復綠。", "燕燕撇波飛，雁雁依雲宿。", "遊子去不歸，凄凉採菱曲。"]'),
('bb99eb3e-f207-455b-b3c6-a502ed33c908','劉生','姚寬','宋','宋诗','song-poetry','','[]','劉生古豪俠，意氣無與俱。',48,'全唐诗/poet.song.115000.json','["劉生古豪俠，意氣無與俱。", "隠若一敵國，不顧千金軀。", "擊劍探赤丸，投瓊叱梟盧。", "醉使新豐酒，笑擁西京姝。"]'),
('10b97d8d-2ab5-46d0-bc22-b66f7dbb0a60','宿諸暨大雄寺','姚寬','宋','宋诗','song-poetry','','[]','解榻無凝塵，雲房愜幽素。',48,'全唐诗/poet.song.115000.json','["解榻無凝塵，雲房愜幽素。", "清寒薄衾枕，微凉散庭戶。", "夢破流水聲，鉤簾捲山霧。", "時與靜者俱，爲擬湯休句。"]'),
('e293f7e5-04c8-4b11-a8a2-b2323079e013','望行人','姚寬','宋','宋诗','song-poetry','','[]','戍客久不歸，生死關山道。',48,'全唐诗/poet.song.115000.json','["戍客久不歸，生死關山道。", "出塞入塞雲，長亭短亭草。", "夢斷玉階人，愁深花欲老。", "庭樹起秋風，寄衣當及早。"]'),
('fd47a0b9-d47d-4024-8582-36d04d91f713','昭君曲','姚寬','宋','宋诗','song-poetry','','[]','漢宮深鎖千蛾眉，妬寵爭妍君不知。',192,'全唐诗/poet.song.115000.json','["漢宮深鎖千蛾眉，妬寵爭妍君不知。", "昭君自恃色殊衆，畫師忍爲黄金欺。", "當時望幸君不顧，淚濕花枝怨無主。", "一朝按圖聘絕域，慷慨尊前爲君去。", "蕭蕭車騎如流水，慘澹風沙千萬里。", "昔年公主嫁烏孫，妾身况是良家子。", "自嗟薄命無歸路，弱質安能事强主。", "可憐宮錦換氊裘，忍變故音作新語。", "馬上琵琶送將遠，行路聞之亦凄斷。", "寄書空憶鴈南飛，只有怨歌傳入漢。", "漢家失計何所獲，羽林射士空頭白。", "白璧駿馬無時無，傾國傾城難再得。"]'),
('c8b11eea-092b-4348-a6bf-e8a8143e75c8','西湖醉歸作','姚寬','宋','宋诗','song-poetry','','["\u897f\u6e56"]','湧金門外看春色，水流不盡花枝碧。',128,'全唐诗/poet.song.115000.json','["湧金門外看春色，水流不盡花枝碧。", "一番洗雨一番風，墮蘂零紅收不得。", "蜜房羽客尋芳歇，蝶翅粉盡金翠滅。", "雲昏草暖天亦迷，日暮楊花散成雪。", "傾城一醉爭狂蕩，踏歌相携大堤上。", "湘妃有意解明璫，桃葉竟誰迎兩槳。", "東君無情背人去，脈脈那由話衷素。", "歸來簾幕護殘燈，一夢閑階月如霧。"]'),
('b2440e39-10a1-4897-befa-edefba459055','搏雞行','姚寬','宋','宋诗','song-poetry','','[]','大雞角角號秋田，小雞啾啾隨後先。',80,'全唐诗/poet.song.115000.json','["大雞角角號秋田，小雞啾啾隨後先。", "喧鳴得意啄遺黍，四顧無人驚復聚。", "青天閃倏片影落，饑鳶搏取填空嗉。", "紛紛散亂入荆棘，老父應門叫無力。", "鳶飛突去何遒疾，大雞還呼小雞出。"]'),
('44885db8-28a3-40b5-8176-12ea70a32143','西溪早行','姚寬','宋','宋诗','song-poetry','','[]','清晨出故溪，鄰曲未聞雞。',48,'全唐诗/poet.song.115000.json','["清晨出故溪，鄰曲未聞雞。", "草露平平濕，溪雲漠漠低。", "轉山人忽見，分路馬多迷。", "作客風埃裏，難堪聽鼓鼙。"]'),
('51fa53fa-d6cd-45e5-a029-9ae07c9a993b','天台夜雨','姚寬','宋','宋诗','song-poetry','','[]','瘴海遠黏天，山城入暝煙。',48,'全唐诗/poet.song.115000.json','["瘴海遠黏天，山城入暝煙。", "春潮生蛤暈，夜雨長蝸涎。", "燈几花時落，風簾客未眠。", "平生懷此地，今夕意茫然。"]'),
('a86f01a0-1399-4edc-908c-71b3dbfc89fd','夜坐懷歸簡報恩振老','姚寬','宋','宋诗','song-poetry','','[]','冷燭翠光殘，踈梅雪影寒。',48,'全唐诗/poet.song.115000.json','["冷燭翠光殘，踈梅雪影寒。", "客心春鴈急，詩思暮江寬。", "髣髴連環夢，凄凉錦瑟彈。", "明朝山下寺，窗竹問平安。"]'),
('49cb4570-9119-4731-860d-d5c99cb0a753','春暮送碧雲闍棃歸靈巗','姚寬','宋','宋诗','song-poetry','','[]','歸意太匆匆，逢春去住中。',48,'全唐诗/poet.song.115000.json','["歸意太匆匆，逢春去住中。", "澹香花濕雨，薄影絮行風。", "覓句愁何許，談玄興未窮。", "應緣知有處，祇莫恨飄蓬。"]'),
('06f70f98-d5b6-46f8-9f83-33282b728407','宿多福寺','姚寬','宋','宋诗','song-poetry','','[]','蕭寺虛庭夜氣嘉，微風入樹碧交加。',64,'全唐诗/poet.song.115000.json','["蕭寺虛庭夜氣嘉，微風入樹碧交加。", "露荷滴瀝珠無翳，月桂扶踈璧有瑕。", "欲採蘋花歸已晚，擬尋竹葉夢還賒。", "愁來剩有凄凉意，織女銀河又復斜。"]'),
('28da542a-e242-44f7-a180-5c3491237026','釣魚','姚寬','宋','宋诗','song-poetry','','[]','自小弄絲來，驚多去復回。',24,'全唐诗/poet.song.115000.json','["自小弄絲來，驚多去復回。", "沙頭晚風起，波上夕陽開。"]'),
('0d8dc75f-babc-427b-9cc9-b0fcbf7e95d1','春晴','姚寬','宋','宋诗','song-poetry','','[]','風雨惜春殘，新晴爲啟關。',24,'全唐诗/poet.song.115000.json','["風雨惜春殘，新晴爲啟關。", "白雲歸去盡，還我舊青山。"]'),
('d43b851e-00ae-4ae4-9e33-a14341d4ee73','真戒僧首房晝寢','姚寬','宋','宋诗','song-poetry','','[]','薄薄簾櫳日，陰陰殿閣風。',24,'全唐诗/poet.song.115000.json','["薄薄簾櫳日，陰陰殿閣風。", "無人驚午夢，雙蝶下花叢。"]'),
('2558e740-747b-46f9-a702-023b368a1dfe','蓮盤莊納凉','姚寬','宋','宋诗','song-poetry','','[]','密竹蔭回塘，陰陰小院凉。',48,'全唐诗/poet.song.115000.json','["密竹蔭回塘，陰陰小院凉。", "低徊忘扇拂，獨自懶衣裳。", "弱蔓扶新綠，紅蕖並晚香。", "華胥愁不到，只在水雲鄉。"]'),
('22d47286-5960-488e-a4ce-aa6e81fc9427','下章安杜瀆七首  其一','姚寬','宋','宋诗','song-poetry','','[]','京洛風塵久不開，晚尋雲水到天台。',32,'全唐诗/poet.song.115000.json','["京洛風塵久不開，晚尋雲水到天台。", "如何更下章安浦，縹緲山城首重回。"]'),
('19648045-c6ba-4b13-9378-325af9806f74','下章安杜瀆七首  其二','姚寬','宋','宋诗','song-poetry','','[]','帆落秋風泊暮灘，月生潮上客心閒。',32,'全唐诗/poet.song.115000.json','["帆落秋風泊暮灘，月生潮上客心閒。", "海門南望天侵水，左直金鼇駐蹕山。"]'),
('156a69a5-2e48-4a09-a0ee-a5ac99f9601a','下章安杜瀆七首  其三','姚寬','宋','宋诗','song-poetry','','[]','石柱山前煙在川，金鵝浦口浪黏天。',32,'全唐诗/poet.song.115000.json','["石柱山前煙在川，金鵝浦口浪黏天。", "北人凄斷南人笑，愁水愁風最可憐。"]'),
('48c7578f-dfb9-4d65-8cc8-d13abf47da74','下章安杜瀆七首  其四','姚寬','宋','宋诗','song-poetry','','[]','平生顧挹山陰道，種竹栽花越水東。',32,'全唐诗/poet.song.115000.json','["平生顧挹山陰道，種竹栽花越水東。", "海角天涯心未穩，吳頭楚尾信難通。"]');
